export const category = "devops";
export const questions = [{"category":"devops","difficulty":"easy","type":"short_answer","title":"Dockerfile 最佳实践","content":"编写 Dockerfile 时有哪些最佳实践可以减小镜像体积和提升构建速度？","answer":"答案：多阶段构建 + 合理利用缓存 + 精简基础镜像\n\n解析：1）多阶段构建：构建阶段用完整 SDK 镜像，运行阶段用 slim/JRE 镜像拷贝产物。2）利用构建缓存：先 COPY package.json 安装依赖（依赖变更频率低），再 COPY 源码（变更频繁），这样不改依赖时缓存生效。3）基础镜像选择：alpine（5MB）或 slim（常 100MB），避免用 full 镜像。4）合并 RUN 命令减少层数，清理 apt/apk 缓存。\n\n扩展延伸：优化效果示例：多阶段构建前 1.2GB → 构建后 120MB。推荐工具：Dive（分析镜像每层空间占用）、docker-slim（自动收缩镜像）。安全建议：不以 root 用户运行（RUN adduser -D app && USER app）、使用可信基础镜像、定期扫描漏洞（Trivy/Snyk）。","hints":["Docker 镜像的层（Layer）是怎么产生的","为什么 alpine 镜像更小但可能有兼容问题"],"tags":["Docker","容器"],"id":1736},{"category":"devops","difficulty":"easy","type":"short_answer","title":"Docker Compose vs Kubernetes","content":"对比 Docker Compose 和 Kubernetes 的使用场景和核心差异。","answer":"答案：Compose 适合单机多容器编排，K8s 适合集群级容器编排\n\n解析：Docker Compose 通过 YAML 定义多服务（前端/后端/数据库），docker compose up 一键启动，适合本地开发和小项目。Kubernetes 管理集群（多节点），自动调度、服务发现、自动扩缩容、滚动更新、自愈。学习曲线陡，运维成本高。\n\n扩展延伸：什么样的规模需要 K8s？建议标准：超过 5 个微服务、需要自动扩缩容、需要灰度发布/蓝绿部署、跨多台机器。K8s 核心概念：Pod（最小调度单位）、Deployment（声明式更新）、Service（服务发现和负载均衡）、ConfigMap/Secret（配置管理）、Ingress（外部访问入口）。","hints":["Pod 和 Deployment 的关系","Service 的 ClusterIP/NodePort/LoadBalancer 三种类型"],"tags":["Docker","K8s","容器"],"id":1737},{"category":"devops","difficulty":"medium","type":"short_answer","title":"CI/CD 流水线设计","content":"请设计一个 Java 项目的 CI/CD 流水线，包含代码提交到生产部署的完整流程。","answer":"答案：代码提交 → 自动构建 → 自动测试 → 构建镜像 → 部署到测试环境 → 验收 → 灰度发布 → 生产\n\n解析：完整流水线 1）代码提交触发 CI（push/PR）2）代码检查：Lint + 单元测试 + 集成测试 3）构建和打包：Maven/Gradle 编译、Docker 构建镜像 4）推送到镜像仓库（Docker Hub/Harbor）5）部署到测试/预发环境 6）自动化测试（接口/UI）7）人工验收（可选）8）灰度发布（金丝雀部署，先 1% 流量）9）全量上线。\n\n扩展延伸：质量门禁：测试覆盖率低于 80% 阻断、SonarQube 代码质量检测阻断、安全扫描（SAST/DAST）。回滚策略：K8s 天然支持滚动回滚（kubectl rollout undo）。版本管理：GitFlow 或 Trunk-Based，镜像 tag 使用 git commit SHA（可追溯）。","hints":["蓝绿部署和金丝雀部署的区别","CI 和 CD 的分界点在哪里"],"tags":["CI/CD","DevOps"],"id":1738},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Docker 网络模式","content":"请说明 Docker 的几种网络模式及各自适用场景。","answer":"答案：bridge/host/none/overlay 四种主要模式\n\n解析：bridge（默认）：Docker 网桥（docker0），容器分配独立 IP 通过 NAT 对外通信，容器间可通过 IP 或 --link 通信，适合单机多容器。host：容器直接使用宿主机网络栈，无独立 IP，性能好但端口隔离差，适合网络性能敏感场景。none：容器无网络能力，用于安全隔离或自定义网络。overlay：跨宿主机容器通信（Swarm/K8s 使用），通过 VXLAN 隧道实现。\n\n扩展延伸：Docker Compose 默认创建自定义 bridge 网络，支持 DNS 解析（服务名直接访问），比默认 bridge 多自动服务发现功能。常用：docker network create -d overlay mynet 创建 overlay 网络。端口映射 docker run -p 8080:80，底层是 iptables DNAT 规则。","hints":["docker run -p 8080:80 底层做了什么","host 模式为什么性能更好"],"tags":["Docker","网络"],"id":1739},{"category":"devops","difficulty":"hard","type":"short_answer","title":"K8s Pod 的生命周期","content":"请描述 Kubernetes Pod 的状态流转和探针（Probe）机制。","answer":"答案：Pod 状态：Pending → Running → Succeeded/Failed，探针决定 Pod 是否健康\n\n解析：Pod 生命周期：Pending（调度中/拉取镜像）→ Running（至少一个容器运行）→ Succeeded（任务完成）→ Failed（出错退出）。未知状态（Unknown）意味着与节点通信失败。三种探针：livenessProbe（存活—检测容器是否运行，失败则重启）、readinessProbe（就绪—检测是否能接受流量，失败则从 Service 摘除）、startupProbe（启动—给慢启动应用缓冲时间）。\n\n扩展延伸：探针配置：initialDelaySeconds（启动后等多久开始检测）、periodSeconds（检测间隔）、timeoutSeconds（超时）。常用检测方式 HTTP GET、TCP Socket、Exec 命令。典型问题：初次启动慢的 Java 应用需 startupProbe 避免被误杀；livenessProbe 不应依赖外部服务（否则外部故障导致容器连环重启）。","hints":["restartPolicy 的三个值和各自作用","liveness 和 readiness 探针都失败时行为有什么不同"],"tags":["K8s","容器"],"id":1740},{"category":"devops","difficulty":"medium","type":"short_answer","title":"监控告警体系设计","content":"如何为一个线上服务设计监控告警体系？常用的指标和工具有哪些？","answer":"答案：四类黄金指标 + Prometheus + Grafana + 告警通道\n\n解析：Google SRE 四类黄金信号：1）延迟（Latency）— 接口 P99/P95/P50 响应时间 2）流量（Traffic）— QPS/TPS 3）错误（Errors）— HTTP 5xx、业务错误码 4）饱和度（Saturation）— CPU/内存/磁盘/连接池使用率。工具链：Prometheus（指标采集 + 存储）→ Grafana（可视化）→ AlertManager（告警管理）→ 飞书/钉钉/邮件（通知）。\n\n扩展延伸：告警策略核心原则 1）不要告警」机器 CPU 高了」，要告警」业务受损了」（如 P99 延迟 > 5s）2）没有对应的处理动作就不要告警 3）设置告警静默期避免告警风暴 4）用」多窗口」检测（连续 N 次超过阈值才告警，避免抖动）。SLA/SLO 的制定：以用户感知为准，而非基础设施指标。","hints":["P99 延迟和平均延迟的差异","什么是指标（Metrics）、日志（Logs）、链路（Traces）三支柱"],"tags":["监控","可观测性"],"id":1741},{"category":"devops","difficulty":"hard","type":"short_answer","title":"K8s 排障实战","content":"K8s 中 Pod 一直处于 Pending/CrashLoopBackOff/ImagePullBackOff 状态，分别是什么原因？怎么排查？","answer":"答案：Pending→资源不足或调度失败，CrashLoop→容器启动后立即崩溃，ImagePull→镜像拉取失败\n\n解析：Pending：kubectl describe pod 查看 Events。常见原因：节点 CPU/内存不足、PVC 不可用、NodeSelector/Affinity 不匹配、节点有 taints（污点）。CrashLoopBackOff：kubectl logs pod 查看容器日志，kubectl logs --previous pod 查看前一次崩溃日志。常见原因：应用启动即抛异常、配置错误、健康检查探针配置不合理。ImagePullBackOff：检查镜像名和 tag、镜像仓库认证（imagePullSecrets）、仓库地址是否可达。\n\n扩展延伸：实用调试命令：kubectl exec -it pod -- sh（进入容器排查）、kubectl port-forward pod 8080:8080（端口转发本地调试）、kubectl get events --sort-by='.lastTimestamp'（按时间排序事件）。高级：临时 Pod 调试 kubectl debug node/node-name（K8s 1.20+）。","hints":["kubectl describe pod 和 kubectl logs 分别看什么","CrashLoopBackOff 的重启间隔策略"],"tags":["K8s","排查"],"id":1742},{"category":"devops","difficulty":"easy","type":"short_answer","title":"Git 工作流对比","content":"请对比 GitFlow、GitHub Flow、Trunk-Based Development 三种 Git 工作流。","answer":"答案：GitFlow 适合有版本发布节奏的项目，GitHub Flow 适合持续部署，Trunk-Based 适合 CI/CD 成熟度高的团队\n\n解析：GitFlow：main + develop + feature/hotfix/release 分支，每个 release 从 develop 切出，合入 main 和 develop。结构严谨但分支复杂，不适合每天多次部署。GitHub Flow：只有一个 main 分支，功能分支短命，提交 PR → review → merge → 立即部署。简单但要求 CI 完善和快速发布。Trunk-Based：所有人直接向主干提交（短特性分支 < 1 天），通过 Feature Flag 控制未完成功能上线。最大程度减少 merge 冲突和最简 CI/CD 路径。\n\n扩展延伸：选择建议：有固定版本号、需要维护多个版本（如移动端）→ GitFlow；SaaS 产品每天多次部署 → GitHub Flow 或 Trunk-Based。Feature Flag 工具（LaunchDarkly/Unleash）是 Trunk-Based 的核心前提。关键原则：工作流只是手段，目标是减少合并冲突和加快交付速度，不是流程越复杂越「规范」。","hints":["GitFlow 的 release 分支和 hotfix 分支分别用于什么","Feature Flag 如何帮助团队不用功能分支也能控制上线"],"tags":["Git","工作流"],"id":1743},{"category":"devops","difficulty":"medium","type":"short_answer","title":"配置管理工具对比","content":"对比 Ansible、Terraform、Chef/Puppet 的异同和适用场景。","answer":"答案：Ansible（无 Agent 配置管理）、Terraform（基础设施即代码）、Chef/Puppet（有 Agent 配置管理）\n\n解析：Ansible：基于 SSH（无 Agent），Push 模式，YAML Playbook，适合临时任务和配置管理。学习曲线低，但大规模下速度慢。Terraform：声明式 IaC，管理云资源（AWS/Azure/GCP），HCL 语言，有状态文件（tfstate）。核心是资源编排而非配置管理。Chef/Puppet：基于 Agent，Pull 模式（Agent 从 Server 拉取配置），适合大规模服务器配置管理。Chef 用 Ruby DSL，Puppet 用声明式 DSL，两者都有 Master 架构。\n\n扩展延伸：现代 DevOps 常见组合：Terraform（管基础设施创建）+ Ansible（管服务器初始化配置）+ Packer（构建镜像）+ Helm（管 K8s 应用部署）。Pulumi：新一代 IaC 工具，用通用编程语言（TypeScript/Python/Go）替代 DSL，比 Terraform 更灵活但生态不如成熟。不可变基础设施趋势：不修改运行中的服务器，而是构建新镜像替换——这从根本上改变了配置管理工具的角色。","hints":["Terraform 的 desired state 和 current state 如何同步","Push 模式和 Pull 模式各自优缺点"],"tags":["IaC","DevOps","自动化"],"id":1744},{"category":"devops","difficulty":"easy","type":"short_answer","title":"Docker 数据卷和数据挂载","content":"请说明 Docker 中 Volume 和 Bind Mount 的区别及各自适用场景。","answer":"答案：Volume 由 Docker 管理（推荐），Bind Mount 映射宿主机任意路径\n\n解析：Volume：docker volume create 创建，存储在 /var/lib/docker/volumes/，完全由 Docker 管理。适合持久化数据库数据、在容器间共享数据、备份恢复。Bind Mount：docker run -v /host/path:/container/path 直接映射宿主机路径。权限与宿主机一致，性能略好。适合开发时热重载代码（源码目录挂载进去）、读取宿主机配置文件。\n\n扩展延伸：tmpfs mount：内存中的临时存储（- —tmpfs），不持久化，适合敏感数据（密码/密钥）。数据卷容器：在早期（Compose 普及前）用于在容器间共享数据，目前已少用。docker compose 中 volumes 定义的 named volume 底层就是 Volume。生产建议：数据库等有状态服务用 Volume + 定期备份，开发场景用 Bind Mount。","hints":["docker run -v 和 docker compose volumes 的关系","数据库容器为什么推荐 Volume 而非 Bind Mount"],"tags":["Docker","存储"],"id":1745},{"category":"devops","difficulty":"medium","type":"short_answer","title":"日志收集方案","content":"设计一套分布式系统的日志收集方案，对比 ELK 和 Loki 的优劣。","answer":"答案：Filebeat/Fluentd → 集中存储 → 搜索和可视化\n\n解析：ELK（Elasticsearch + Logstash + Kibana）：Logstash 聚合日志写入 ES，Kibana 查询分析。功能强大（全文搜索 + 聚合分析 + 仪表盘），但资源消耗大（ES 吃内存），运维复杂。Loki + Promtail + Grafana：Loki 借鉴 Prometheus 理念，只索引元数据（标签），日志内容不索引。资源消耗小，与 Prometheus 和 Grafana 无缝集成，但查询能力弱于 ES。\n\n扩展延伸：采集方案对比：Filebeat（轻量，Go 实现，ELK 生态）/ Fluentd（Ruby，插件丰富）/ Promtail（Loki 专属）/ Vector（Rust，新一代高性能，支持多输出）。日志治理：设置保存周期（热节点 7 天、冷节点 30 天）、日志级别采样（DEBUG 级别按 1:100 采样）、敏感信息脱敏（密码/身份证正则替换）。注意：日志不是越多越好，T 级日志如果没有索引和治理等于垃圾。","hints":["Loki 为什么不索引日志内容","全量索引（ES）vs 索引元数据（Loki）的各自适用场景"],"tags":["日志","可观测性"],"id":1746},{"category":"devops","difficulty":"hard","type":"short_answer","title":"蓝绿部署与滚动更新","content":"请解释蓝绿部署、滚动更新、金丝雀发布三种发布策略的区别。","answer":"答案：蓝绿部署是两套环境切换，滚动更新是逐步替换，金丝雀是小比例灰度验证\n\n解析：蓝绿部署：维护两套完全相同的环境（蓝=当前在线，绿=新版本）。切换时调整负载均衡流量从蓝切到绿。问题：需要双倍资源、切换瞬间可能有短暂不一致。滚动更新：逐个或逐批替换 Pod（K8s deployment strategy: RollingUpdate）。设置 maxSurge（最多超出多少个新 Pod）和 maxUnavailable（最多允许多少个不可用）。部署过程不中断服务，但回滚慢。金丝雀发布：先让 1%-5% 的流量走新版本，监控指标正常后逐步增加到 100%。与 A/B 测试的区别：金丝雀是验证稳定性，A/B 测试是验证业务效果（转化率等）。\n\n扩展延伸：K8s 中的实现：Deployment 的 rollingUpdate 参数控制滚动更新行为。金丝雀需用 Service Mesh（Istio/Linkerd）或 Ingress Controller（NGINX Ingress 的 canary annotation）实现精细流量控制。自动化的发布决策：金丝雀阶段自动回滚（检测到错误率上升 → 自动切回旧版本）是 SRE 实践中重要的发布安全保障。","hints":["Deployment 的 maxSurge 和 maxUnavailable 参数怎么配","为什么金丝雀发布需要 Service Mesh 或高级 Ingress"],"tags":["发布","K8s","SRE"],"id":1747},{"category":"devops","difficulty":"hard","type":"short_answer","title":"SRE 核心实践","content":"请解释 SRE（Site Reliability Engineering）的核心概念：SLO、SLI、Error Budget。","answer":"答案：SLI 是实际指标，SLO 是目标阈值，Error Budget = 1 - SLO，代表可容忍的不可靠时间\n\n解析：SLI（Service Level Indicator）——我们怎么衡量可靠性？如请求延迟 P99 < 200ms、可用率 > 99.9%。SLO（Service Level Objective）——目标值，如」季度内 P99 延迟 < 200ms 的时间占比 > 99.9%」。Error Budget（错误预算）——如果 SLO 是 99.9%，季度错误预算 = 0.1% × 3 个月 ≈ 2.6 小时不可用。预算用完前可以发布新功能，用完后必须冻结发布专注于稳定性——这是 SRE 平衡」可靠性和创新速度」的核心机制。\n\n扩展延伸：SRE 与传统运维的区别：SRE 是软件工程师做运维，用工程手段解决运维问题（自动化而非手动）。SRE 践行」运维是软件工程」理念，限制运维工作 < 50% 时间，剩余时间做开发减少运维负担。谷歌 SRE 书的经典原则：1）减少琐事（Toil）——手动、重复、可自动化的操作 2）可靠性的边际递减——99.99% 比 99.9% 只多 9 分钟/月但成本翻数倍 3）监控应简单——4 个黄金信号比 100 个指标更有效。","hints":["99.9% 和 99.99% 的可用性差异有多大","Error Budget 用完后的发布冻结如何执行"],"tags":["SRE","可靠性"],"id":1748},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Helm K8s 包管理","content":"什么是 Helm？为什么需要 Helm 而非直接用 kubectl apply？","answer":"答案：Helm 是 K8s 的包管理器，通过 Chart 模板化管理和分发 K8s 资源\n\n解析：一个微服务通常需要 Deployment + Service + ConfigMap + Ingress 多个 YAML，跨环境（dev/staging/prod）还有很多重复配置。Helm Chart 用 Go 模板语法定义资源模板，values.yaml 注入环境差异。核心概念：Chart（包定义）、Release（运行实例）、Repository（仓库）。Helm install/upgrade/rollback 管理应用生命周期。\n\n扩展延伸：Helm vs Kustomize：Helm 是 Go 模板，功能强大但复杂；Kustomize（kubectl 内置）用 overlay 方式覆盖配置，不需学模板语法，但灵活性不如 Helm。生产建议：复杂应用用 Helm，简单项目用 Kustomize。Helm Hook（pre-install/post-install 等）可用于在部署前后执行数据库迁移等任务。注意：Helm 不管理 CRD 升级（可能造成数据丢失），helm template 可以本地渲染 YAML 用于审查。","hints":["Helm 的 values.yaml 如何在不同环境间复用","Helm 和 Kustomize 的选择标准"],"tags":["K8s","Helm"],"id":1749},{"category":"devops","difficulty":"easy","type":"short_answer","title":"容器安全最佳实践","content":"请列出容器化环境中的安全最佳实践。","answer":"答案：最小权限 + 镜像签名 + 运行时安全 + 网络隔离 + 漏洞扫描\n\n解析：1）最小权限——不以 root 运行（USER app）、readOnlyRootFilesystem: true、drop ALL Linux capabilities 再按需添加 2）镜像安全——使用可信基础镜像（Docker Official Images / distroless）、Trivy/Clair 定期漏洞扫描、镜像签名（cosign）防篡改 3）网络隔离——必要时 networkpolicy 限制 Pod 间通信、不暴露不必要的端口 4）运行时安全——Falco（行为监控）、Seccomp/AppArmor 限制系统调用 5）密钥管理——不把密码写在镜像里，用 K8s Secret、Vault 或外部密钥管理服务。\n\n扩展延伸：OWASP Docker Top 10 中最高危的问题包括：Host 文件系统挂载（docker run -v /:/host）、特权模式（-- privileged）、不验证镜像来源。Supply Chain Security（软件供应链安全）：构建镜像时锁定基础镜像 digest 而非 tag（FROM alpine@sha256:xxx），避免镜像被篡改。Docker Bench Security 脚本可自动检查 Docker 环境的安全配置。","hints":["docker run --privileged 有什么风险","Why distroless base images are more secure"],"tags":["Docker","安全"],"id":1750},{"category":"devops","difficulty":"hard","type":"short_answer","title":"混沌工程（Chaos Engineering）","content":"请解释混沌工程的核心原则和实践方法。","answer":"答案：混沌工程通过在系统中主动注入故障，验证系统在异常条件下的行为，发现隐藏的弱点。核心原则：先定义稳态 → 假设稳态不受影响 → 引入故障变量 → 验证假设。\n\n解析：混沌工程不是「随机搞破坏」，而是有假设驱动的实验。Netflix Chaos Monkey 最早实践：随机杀死生产环境中的实例，验证自动恢复机制是否正常。现代工具链：Chaos Mesh（K8s 原生，支持 Pod/网络/磁盘/压力注入）、LitmusChaos（开箱即用实验库）、Gremlin（商业版）。\n\n扩展延伸：混沌工程成熟度模型：1）手动实验（在测试环境 kill Pod 看效果）2）自动化实验（定期执行预设实验）3）集成 CI/CD（发布流水线中自动执行混沌实验，失败阻断发布）4）生产环境持续实验（卡诺斯原则——爆炸半径最小化，从影子流量到生产流量）。实际建议：不要在生产环境直接开始——先在 staging 环境验证实验的安全性，有完善的监控告警和回滚机制后再逐步扩展到生产。","hints":["混沌工程和传统测试的区别是什么","Netflix Chaos Monkey 如何保证爆炸半径可控"],"tags":["混沌工程","可靠性","SRE"],"id":1751},{"category":"devops","difficulty":"easy","type":"short_answer","title":"GitOps 与 ArgoCD","content":"请解释 GitOps 的核心思想以及 ArgoCD 的工作原理。","answer":"答案：GitOps 以 Git 仓库作为基础设施和应用的单一事实来源，Git 中的声明式配置与实际集群状态自动同步。ArgoCD 是实现 GitOps 的 K8s 工具，持续监控 Git 仓库和 K8s 集群状态，自动修复偏差。\n\n解析：GitOps 核心原则：1）声明式配置——整个系统的期望状态写在 Git 仓库中 2）不可变——所有变更通过 Pull Request 修改仓库，变更可审计可回滚 3）自动同步——Operator 持续将仓库状态应用到集群，集群偏差自动修复。ArgoCD 架构：Application CRD（定义 Git 源 + 目标集群 + 同步策略）→ Repo Server（拉取 Git 仓库 + 渲染 Helm/Kustomize）→ Application Controller（对比期望状态和实际状态，执行同步）。\n\n扩展延伸：GitOps vs 传统 CI/CD：传统 CI/CD（Jenkins/GitHub Actions）将产物推到目标环境，GitOps 的 CD Agent（ArgoCD）从 Git 仓库拉取配置。Push 模式（CI 推送到集群）权限过大，Pull 模式（集群 Agent 拉取 Git）更安全。ArgoCD 同步策略：手动/自动、Prune（删除集群中仓库不存在的资源）、Self-Heal（自动修复偏差）。注意：GitOps 不意味着不需要 CI——CI 仍然负责构建和测试，只是 CD 部分由 GitOps 接管。","hints":["GitOps 的「Push」模式和「Pull」模式有什么区别","ArgoCD 和 Flux 的设计理念差异"],"tags":["GitOps","ArgoCD","DevOps"],"id":1752},{"category":"devops","difficulty":"hard","type":"short_answer","title":"密钥管理方案（Secrets Management）","content":"微服务架构中如何安全管理密钥（数据库密码、API Key 等）？Vault 的工作原理是什么？","answer":"答案：密钥管理的目标是避免密钥以明文形式出现在代码仓库、配置文件和环境变量中。HashiCorp Vault 提供动态密钥生成、自动轮换和细粒度访问控制。\n\n解析：密钥管理的演进路径：1）写在配置文件里（最不安全）2）写在环境变量里（较安全但仍存泄露风险）3）K8s Secret（Base64 编码，需配合 etcd 加密和 RBAC）4）外部密钥管理服务（Vault/AWS Secrets Manager/Azure Key Vault）。HashiCorp Vault 核心能力：静态密钥存储（加密存储 + 细粒度 ACL）、动态密钥（数据库每次连接生成临时密码，用完自动吊销）、密钥轮换（自动定期替换）、审计日志。\n\n扩展延伸：与 K8s 集成：1）Vault Agent Sidecar——在 Pod 中注入 Sidecar 容器，负责从 Vault 拉取密钥注入到共享 Volume。2）External Secrets Operator——K8s CRD，将 Vault/AWS Secrets Manager 中的密钥同步为 K8s Secret 对象（K8s 原生方式引用密钥，应用无感知）。3）Secrets Store CSI Driver——通过 CSI 卷将密钥直接挂载到 Pod 中，不在 etcd 中持久化。实际建议：中小项目先上 External Secrets Operator（门槛低），大规模敏感场景上 Vault。","hints":["K8s Secret 的 etcd 加密需要额外配置","Vault 动态密钥相比静态密钥的优势"],"tags":["密钥管理","Vault","安全","Secrets"],"id":1753},{"category":"devops","difficulty":"medium","type":"short_answer","title":"镜像构建与仓库管理","content":"请介绍容器镜像构建的最佳实践和镜像仓库的治理策略。","answer":"答案：镜像构建的核心原则是可复现、最小体积、安全合规。仓库治理包括标签策略、清理策略和漏洞扫描。\n\n解析：镜像构建最佳实践：1）锁定基础镜像 digest 而非 tag（FROM alpine@sha256:xxx 而非 FROM alpine:latest）2）多阶段构建分离构建环境和运行环境 3）利用 BuildKit 的并发构建和缓存挂载（--mount=type=cache）4）最小化层数（合并 RUN 命令）和清理缓存。镜像仓库治理：1）标签策略——不可变标签（git commit SHA）、语义版本（v1.2.3）、latest 仅用于开发。2）清理策略——保留最近 N 个版本、未使用的镜像超过 30 天自动清理。3）镜像扫描——Trivy/Grype 扫描 CVE、阻断高危漏洞镜像部署。\n\n扩展延伸：OCI（Open Container Initiative）标准：所有容器运行时（Docker/containerd/podman）遵循 OCI 镜像规范和运行时规范，镜像可在不同运行时间通用。镜像签名：cosign（Sigstore 项目）对镜像签名和验证，确保构建到部署链路中镜像不被篡改。SBOM（Software Bill of Materials）——生成镜像的软件物料清单（syft 工具），用于追踪依赖和漏洞来源。注意：镜像大小不是越极端越好——distroless 镜像虽然更小更安全，但排障时没有 shell，需要 debug 容器辅助。","hints":["OCI 标准化对镜像跨平台有什么意义","镜像签名如何防 Supply Chain Attack"],"tags":["Docker","镜像","仓库","安全"],"id":1754},{"category":"devops","difficulty":"medium","type":"short_answer","title":"K8s Operator 模式进阶","content":"请解释 K8s Operator 模式和 Controller 的区别，以及如何编写一个简单的 Operator。","answer":"答案：Operator 比 Controller 更进一步——它不仅维持状态，还将特定应用的运维知识编码到 K8s 扩展中。Controller 是 K8s 通用的控制循环（Reconcile），Operator 是针对特定应用的 Controller + CRD（自定义资源）。\n\n解析：Controller（控制器）是 K8s 的核心模式——每个内置资源（Deployment/Service/Job）都由对应 Controller 驱动。控制循环（Reconcile Loop）：观察当前状态 → 与期望状态对比 → 执行操作使当前状态趋近期望状态。Operator 在 Controller 基础上扩展：定义 CRD（如 EtcdCluster）、在 Controller 中实现运维逻辑（自动备份、扩缩容、故障恢复）。\n\n扩展延伸：编写 Operator 的工具：1）Operator SDK（Red Hat，基于 Kubebuilder，Go 语言，最成熟）2）Kubebuilder（K8s SIG，原生 Go，最底层最灵活）3）Kopf（Python 框架）4）Java Operator SDK（Quarkus，Java 生态友好）。Operator 成熟度模型（Operator Capability Levels）：Level 1（基础安装）→ Level 2（升级）→ Level 3（生命周期/存储）→ Level 4（深度监控/指标/报警）→ Level 5（自动修复/弹性伸缩）。OLM（Operator Lifecycle Manager）管理 Operator 的安装和升级。开发建议：先用 Helm 部署，运维需求复杂化后再考虑迁移到 Operator——不用一开始就上 Operator。","hints":["Contorller 和 Operator 的本质区别","什么时候应该用 Operator 而不是 Helm"],"tags":["K8s","Operator","Controller","自动化"],"id":1755},{"category":"devops","difficulty":"hard","type":"short_answer","title":"Docker 底层原理：Namespace 与 Cgroup","content":"Docker 实现资源隔离和限制的底层技术是什么？Namespace 和 Cgroup 分别起什么作用？","answer":"答案：Docker 利用 Linux Namespace 实现资源隔离（容器看到独立的进程/网络/文件系统），利用 Cgroup 实现资源限制（CPU/内存/IO 配额）。UnionFS（OverlayFS）实现分层镜像。\n\n解析：Namespace 隔离的七种资源：1）PID Namespace——容器内进程树独立（PID 从 1 开始，看不到宿主机其他进程）。2）Network Namespace——独立网络栈（网卡、路由表、iptables）。3）Mount Namespace——独立文件系统挂载点。4）UTS Namespace——独立主机名和域名。5）IPC Namespace——独立进程间通信资源（信号量/消息队列）。6）User Namespace——独立用户 ID 映射（容器内 root 可映射为宿主机非 root 用户）。7）Cgroup Namespace（Linux 4.6+）——独立 Cgroup 视图。\n\n扩展延伸：Cgroup（Control Groups）资源限制：1）cpu.shares——CPU 时间分配权重。2）memory.limit_in_bytes——内存上限（超过触发 OOM Kill）。3）blkio.throttle.read_bps_device——磁盘 IO 读取速度限制。4）cpuset——绑定特定 CPU 核心（对性能敏感的容器使用）。Cgroup 版本：Cgroup v1（传统）和 Cgroup v2（Linux 4.5+，RHEL 8+/Ubuntu 21.10+ 默认）。v2 简化了层级结构（统一到一个层次树），解决了 v1 中不同控制器分属不同层级导致的问题。Docker 未实现的隔离——共享内核（所有容器共享宿主机内核），所以不能运行与宿主机不同操作系统的容器（如 Linux Docker 上不能跑 Windows 容器）。","hints":["Docker 的 Namespace 隔离为什么不包括时间","Cgroup v1 和 v2 的核心架构区别是什么"],"tags":["Docker","Namespace","Cgroup","容器原理"],"id":1756},{"category":"devops","difficulty":"easy","type":"short_answer","title":"CI 工具对比","content":"对比 Jenkins、GitHub Actions、GitLab CI 的核心差异和适用场景。","answer":"答案：Jenkins 老牌自托管 CI/CD、功能强大但运维复杂；GitHub Actions 云原生 CI（与 GitHub 仓库深度集成）；GitLab CI 一体化 DevOps 平台（代码仓库+CI/CD 集成度最高）。\n\n解析：1）Jenkins——最成熟的 CI 工具，插件生态极其丰富。Java 实现的 Master/Agent 架构，支持分布式构建。优势：灵活（Pipeline as Code 的 Groovy DSL、共享库），支持任意构建环境，插件 1800+。劣势：配置复杂（UI 配置多），需要自己维护 Master 和 Agent，插件版本兼容问题。适合：企业自建 CI/CD 已有大量存量 Pipeline。2）GitHub Actions——通过 .github/workflows/*.yml 定义流水线，HCL 语法。优势：零运维（云执行）、与 GitHub 原生集成（PR/Issue/Release 触发）、市场有大量共享 Actions。劣势：不支持自托管 Runner 时执行环境受限（硬盘/网络）、并发限制（免费版 20 并发）、调试不方便。适合：GitHub 托管的开源项目和中型团队。3）GitLab CI——.gitlab-ci.yml YAML 流水线。优势：一个平台管代码 + CI + CD + 容器仓库（无需集成多个系统），自托管 Runner 部署简单。适合：使用 GitLab 企业版的全栈 DevOps 团队。\n\n扩展延伸：现代 CI 核心诉求：速度（构建缓存、并行 Stage/Job、只构建变更部分）、开发者体验（Pull Request 内直接看到测试结果）、安全（密钥管理（Settings → Secrets）、Dependency Review）。CI 流水线设计的反模式：Pipeline 过长（超过 30 分钟应该考虑拆分）、在 CI 中跑 E2E 全量测试（应分层到不同的 Pipeline）、CI 与 CD 混在一起（CI 做构建测试校验，CD 做部署发布——职责分离）。","hints":["自托管 Runner 和云执行 Runner 的选择标准","CI Pipeline 速度和可靠性如何平衡"],"tags":["CI/CD","Jenkins","GitHub Actions","GitLab CI"],"id":1757},{"category":"devops","difficulty":"hard","type":"short_answer","title":"K8s 网络模型：CNI 与插件对比","content":"请解释 K8s 网络模型的基本要求。Calico、Flannel、Cilium 各自的特点和适用场景是什么？","answer":"答案：K8s 网络模型要求：每个 Pod 有独立 IP（Pod 间不经过 NAT 直接通信）、节点上 Pod 可访问所有节点上的所有 Pod。CNI（Container Network Interface）是实现这一模型的插件标准。\n\n解析：CNI 核心职责：1）分配 Pod IP（从 IP 池中取）。2）配置 Pod 网络（在 Pod 的网络命名空间中配置网卡/路由）。3）保证跨节点 Pod 通信。主流 CNI 插件对比：1）Flannel——覆盖网络（Overlay），使用 VXLAN 或 host-gw（网关模式）。最简配置，性能中等。适用：中小规模集群（< 50 节点），对网络性能不敏感、追求部署简单。2）Calico——基于 BGP 路由协议（没有 Overlay 封装，直接在三层路由），性能优（原生路由带宽损耗 < 5%）。支持 NetworkPolicy（K8s 原生网络策略），支持 eBPF（Calico v3.13+）提升性能。适用：大规模集群、对性能敏感、需要 NetworkPolicy 的场景。3）Cilium——基于 eBPF（Linux 内核扩展），所有网络/安全/可观测性功能都用 eBPF 实现。性能极高（绕过 iptables，直接在内核中处理转发）。支持 NetworkPolicy、可观测性（Hubble）、L7 协议感知（HTTP/gRPC/Kafka 流量可视化）。适用：K8s 1.20+、Linux 5.10+ 内核、追求极致性能和安全、需要深度可观测性的生产集群。\n\n扩展延伸：CNI 的选择因素：1）性能——Overlay（VXLAN）有封装开销（约 10-15% 带宽损失）。纯路由（BGP/Calico）或 eBPF（Cilium）接近原生性能。2）功能需求——需要 NetworkPolicy → Calico/Cilium。需要 L7 流量可视化 → Cilium + Hubble。需要多网络接口（Multus 插件）。3）基础设施——在公有云上（AWS/Azure/GCP），云厂商自带的 CNI（如 AWS VPC CNI、Azure CNI）集成度最高（Pod IP = VPC IP，不经过 NAT 或 tunneling）。建议：新集群首选 Cilium（eBPF 是未来趋势），中大规模 Calico 也是非常成熟稳定的选择。","hints":["Overlay 网络（VXLAN）为什么会有性能损耗","Calico 的 BGP 模式和 IPIP 模式有什么区别"],"tags":["K8s","CNI","Calico","Cilium","Flannel"],"id":1758},{"category":"devops","difficulty":"medium","type":"short_answer","title":"FinOps 与云成本优化","content":"什么是 FinOps？云原生架构下如何做成本优化和成本治理？","answer":"答案：FinOps（Finance + DevOps）是将财务责任引入云消费的文化和操作框架，核心是让工程团队对云成本负责。三阶段：Inform（可见性）→ Optimize（优化）→ Operate（持续运营）。\n\n解析：1）Inform（可见性）——建立成本分摊能力。关键做法：给所有云资源打标签（Tag/Label，如 team=payment, env=prod, project=order），按团队/服务/环境维度拆分成本。工具：多云成本管理平台。2）Optimize（优化）——识别浪费和降低成本。常见策略：利用预留实例（Reserved Instance）或节省计划（Savings Plans）可节省 30-60%、使用 Spot 实例处理无状态容错工作负载（节省 60-90%）、自动停止非生产环境的闲置资源（夜间/周末）、K8s 集群垂直/水平 Pod 自动伸缩（HPA/VPA 减少资源过量配置）。3）Operate（持续运营）——预算告警（设置预算阈值，超支自动通知）、成本异常检测（ML 驱动的成本异常告警）、定期成本审查会议（每周 Review 成本趋势和优化机会）。\n\n扩展延伸：K8s 成本优化实战：1）资源 requests/limits 合理性——KRR（Kubernetes Resource Recommender）根据历史数据推荐合理的资源申请，通常可减少 30-50% 资源浪费。2）Cluster Autoscaler 配置——确保节点池在低负载时自动缩容（避免长时间空跑）。3）利用 K8s 提供的成本分摊方案——OpenCost（CNCF 项目，按 Namespace/Deployment/Pod 粒度分摊成本）。4）对象存储替代持久卷——日志/备份等冷数据用对象存储（S3/OSS）替代 PV，成本降低 80%+。注意：成本优化不能以牺牲可靠性为代价——预留实例覆盖率不过高（留一定比例的按需应对突增）。","hints":["为什么强调成本分摊（Chargeback/Showback）是 FinOps 的第一步","OpenCost 如何计算 K8s 中每个 Pod 的精确成本"],"tags":["FinOps","成本","云原生","优化"],"id":1759},{"category":"devops","difficulty":"hard","type":"short_answer","title":"K8s 集群版本升级策略","content":"Kubernetes 集群升级的最佳实践是什么？如何安全地跨小版本升级？升级过程中应该注意哪些风险？","answer":"答案：K8s 升级遵循「Never Upgrade Two Minor Versions at Once」原则——只能逐小版本升级（如 1.27 → 1.28 → 1.29）。核心流程：先升级控制面组件，再升级节点。\n\n解析：升级前的准备工作：1）检查 API 弃用——每个版本会移除一些已弃用的 API 版本（APIRemoval）。用 `kubectl convert` 检查集群中是否还在使用即将移除的 API。2）备份 etcd——升级前对 etcd 做快照（etcdctl snapshot save），这是升级失败后的关键回滚手段。3）检查 Pod Security 策略——升级前后 PSS/PodSecurity 的行为可能变化。4）集群只读——升级期间避免关键变更。\n\n升级步骤（以 kubeadm 为例）：1）更新 kubeadm 版本 → kubeadm upgrade plan（查看可升级版本和注意事项）。2）升级控制面：kubeadm upgrade apply v1.28.x → 升级 kubelet/kubectl → 重启 kubelet。3）等待控制面稳定（所有 API Server/Scheduler/Controller-Manager Pod 正常）。4）升级 Worker 节点：先封锁节点（kubectl cordon）→ drain 驱逐 Pod → 升级 kubelet/kube-proxy → 重启 kubelet → 解除封锁（uncordon）。\n\n扩展延伸：升级风险与缓解：1）API 兼容性破坏——提前运行 `kubectl convert` + `kubent`（Kube No Trouble 工具）扫描已弃用 API。2）升级过程中断——控制面升级不影响已有 Pod（Pod 继续运行），只影响控制面自身的可用性（创建/更新资源不可用）。3）回滚——如果升级失败，用 etcd 快照恢复 + 降级 kubeadm/kubelet 版本。工具化升级：1）Kops——自动逐节点滚替，控制面先升级再节点。2）Kubespray——Ansible 驱动的升级，可配置升级策略。3）托管的 K8s（EKS/AKS/GKE）——云厂商一键升级，但 Worker 节点仍有滚动。注意：不要跨多个次版本升级（如 1.26 → 1.28）。如果确实需要，先升级到 1.27 再升 1.28。","hints":["控制面升级期间为什么已有 Pod 不受影响","kubeadm upgrade apply 和 kubeadm upgrade node 的区别"],"tags":["K8s","升级","运维","高可用"],"id":1760},{"category":"devops","difficulty":"medium","type":"short_answer","title":"基础设施即代码 Terraform","content":"Terraform 的核心概念（Provider/Resource/State/Module）是什么？Terraform State 文件的管理最佳实践有哪些？","answer":"答案：Terraform 通过声明式配置管理基础设施。Provider 连接云平台（AWS/Azure/GCP），Resource 声明基础设施对象（EC2/RDS/VPC），State 映射真实世界资源状态，Module 封装可复用的配置单元。\n\n解析：核心概念——1）Provider——云平台/服务的 API 适配器。每个 Provider 定义一组 Resources 和 Data Sources。配置：`provider \"aws\" { region = \"us-east-1\" }`。2）Resource——声明基础设施对象。示例：`resource \"aws_instance\" \"web\" { ami = \"ami-xxx\" instance_type = \"t3.micro\" }`。3）State——Terraform 将配置与真实资源映射的 JSON 文件。记录了资源 ID 和属性。Terraform 通过 State 知道哪些资源已存在、哪些需要更新、哪些需要删除。4）Module——封装可复用的基础设施模板。Terraform Registry 有社区模块（VPC/EC2/RDS 等的标准模块）。\n\n扩展延伸：State 文件管理——1）Remote State（远程存储）：S3/OSS/Azure Storage 作为 Backend。绝对不要用本地 State。2）State Locking：DynamoDB 作为锁表防止多人同时修改 State。3）State 文件包含敏感信息（数据库密码等以明文存储），需要加密和访问控制。4）Terragrunt——Terraform 的增强工具（减少重复配置、管理多个环境）。Terraform vs Pulumi：Terraform 用 HCL 语言（声明式、学习成本低），Pulumi 用通用语言（TypeScript/Python/Go，更灵活但可读性差）。","hints":["Terraform State 为什么是核心枢纽，Remote State + State Locking 如何保证团队协作","Terraform 的 Plan 命令在执行 apply 前做了什么——Dry Run 价值"],"tags":["DevOps","Terraform","IaC","基础设施"],"id":1761},{"category":"devops","difficulty":"hard","type":"short_answer","title":"容器网络 CNI 原理","content":"Kubernetes 的 CNI 网络模型如何工作？Flannel、Calico、Cilium 三种主流 CNI 方案的区别是什么？","answer":"答案：CNI（Container Network Interface）是 K8s 的容器网络标准。核心要求：每个 Pod 有独立 IP，所有 Pod 间可以直接通信（无需 NAT）。CNI 在 Pod 创建时进行网络配置（创建网卡、分配 IP、配置路由）。\n\n解析：K8s 网络模型——1）Pod 间的通信通过 Overlay 网络或路由实现。2）每个 Node 负责分配给其 Pod 的 IP 段（通常每个 Node 一个 /24 子网）。三种主流方案：Flannel——使用 VXLAN 或 host-gw 封装。vxlan：UDP 封装 Pod 流量（overlay，性能有损耗但简单）。host-gw：直接写 Node 路由表，不封装，性能好但只支持同 L2 网络。适用：中小集群，对性能要求不高。Calico——使用 BGP 路由协议（无 overlay，原生性能）。每个 Node 通过 BGP 将 Pod CIDR 路由广播给集群其他 Node。网络策略（NetworkPolicy）原生支持，丰富 ACL。适用：需要高性能和细粒度网络策略的集群。Cilium——基于 eBPF（Extended Berkeley Packet Filter）的内核级网络。替换 kube-proxy（eBPF 实现的 Service 负载均衡）。支持 Hubble 可视化流量。优势：性能极高、可观测性强、安全策略强大。\n\n扩展延伸：选型建议——Flannel：简单场景（开发、测试、中小集群）。Calico：生产标准，需要 NetworkPolicy。Cilium：大规模集群、对性能和可观测性要求极高、云原生网络策略。Service Mesh（Istio）与 CNI 是互补关系：CNI 解决 Pod 间 L3/L4 通信，Service Mesh 解决 L7 流量管理。Cilium 内置的 L7 策略可以和 Istio 协同使用。","hints":["VXLAN（Flannel）vs BGP（Calico）vs eBPF（Cilium）三种数据路径的性能差异","CNI 和 Service Mesh 各自解决什么问题——L3/L4 vs L7"],"tags":["K8s","CNI","网络","Flannel","Calico","Cilium"],"id":1762},{"category":"devops","difficulty":"easy","type":"short_answer","title":"GitOps 工作流","content":"什么是 GitOps？GitOps 与传统 CI/CD 的主要区别是什么？ArgoCD 和 Flux 的实现原理是怎样的？","answer":"答案：GitOps 是以 Git 仓库作为基础设施和应用的唯一真相源（Source of Truth），通过自动化工具确保集群状态与 Git 仓库的描述一致。核心原则：声明式描述 + 版本控制 + 自动同步。\n\n解析：传统 CI/CD：CI 构建镜像 → CD 工具（Jenkins/Spinnaker）将更新部署到环境。环境状态不在 Git 中体现，手动变更可能导致「配置漂移」。GitOps：开发人员只修改 Git 仓库中的 YAML 清单 → GitOps Operator（ArgoCD/Flux）检测到 Git 变更 → 自动将新状态同步到集群。Operator 持续监控集群，如果有人手动改了集群资源但没有改 Git，Operator 会将状态回滚到 Git 版本。\n\n扩展延伸：ArgoCD vs Flux——ArgoCD：Web UI 优秀（资源拓扑图直观展示），多集群管理（一个 ArgoCD 管理多个 K8s 集群），支持 App of Apps 模式（递归管理应用）。Flux：更轻量（只用一个 Operator），Cluster API 集成好（管理集群生命周期），支持 Image Update Automation（自动更新 Git 中的镜像版本）。GitOps 的局限：1）Git 不是实时同步工具，从 Push 到集群更新的延迟受 Git 扫描周期和 Operator 检测频率影响。2）密钥管理：Git 不适合存储明文密钥，需要 Sealed Secrets / External Secrets Operator / SOPS 加密。3）GitOps 适合无状态和配置型应用，对有状态应用（数据库）需要额外处理。","hints":["GitOps 的自动回滚能力——为什么在 GitOps 中手动修改集群资源会被 Git 仓库覆盖","密钥管理在 GitOps 中为什么成为挑战以及 SOPS 如何解决"],"tags":["GitOps","ArgoCD","Flux","CI/CD"],"id":1763},{"category":"devops","difficulty":"medium","type":"short_answer","title":"SRE 黄金指标与 SLI/SLO/SLA","content":"SRE 中的 SLI、SLO、SLA 分别定义了什么？Google 定义的四个黄金信号（Latency/Traffic/Errors/Saturation）如何指导监控和告警？","answer":"答案：SLI（Service Level Indicator）——衡量服务质量的指标（如延迟 P99 < 200ms）。SLO（Service Level Objective）——SLI 的目标值（如 99.9% 的请求延迟 < 200ms）。SLA（Service Level Agreement）——对客户的承诺（未达成有后果，如赔偿）。\n\n解析：四个黄金信号——1）Latency（延迟）——请求处理的时间。重点区分成功请求和失败请求的延迟（失败请求可能很快返回错误但这不是「快」）。P50/P90/P99 分位数比平均值更有意义。2）Traffic（流量）——系统承载的需求量。HTTP：QPS/RPS；数据库：查询速率；消息队列：消息吞吐量。流量的季节性/周期性规律——知道正常值才能定义异常。3）Errors（错误）——显式错误：HTTP 5xx、异常。隐式错误：返回 200 但内容是错误消息（如搜索结果为空时返回了错误的默认值）。4）Saturation（饱和度）——系统资源耗尽的程度。CPU 使用率、内存使用率、磁盘 IO、网络带宽。通常饱和超过 80% 就应告警（在资源完全耗尽前预留缓冲）。\n\n扩展延伸：SLO 的工程价值——1）错误预算（Error Budget）：SLO 99.9% 意味着每月最多 43 分钟的不可用时间。错误预算是衡量可用的。团队可以在错误预算剩余充足时大胆发布新功能，不足时优先稳定性。2）告警策略：把告警和 SLO 挂钩——当服务即将耗尽错误预算时触发告警，而非仅当某个指标超阈值。Google 的实践是「Page 一个人类」只在错误消耗快于预期、且人工介入能改善情况时才告警。避免告警疲劳。3）SLO 不是越高越好：99.99% 的成本是指数级增长的，对大多数内部服务 99.9% 已经足够。","hints":["为什么 Google 建议区分成功请求和失败请求的延迟——失败可能很快但掩盖了真正的问题","错误预算如何平衡「发布速度」和「系统稳定性」的矛盾"],"tags":["SRE","SLI","SLO","监控","可靠性"],"id":1764},{"category":"devops","difficulty":"hard","type":"short_answer","title":"混沌工程原理与实践","content":"混沌工程（Chaos Engineering）的核心原则是什么？Chaos Monkey 和 Litmus 如何实现故障注入？在生产环境做混沌实验需要注意什么？","answer":"答案：混沌工程是通过主动注入故障来验证系统韧性的学科。核心原则：先定义系统的「稳态」→ 假设系统在故障下仍然稳态 → 注入真实故障 → 验证假设 → 改进。要点：「混沌」不是随机破坏，而是有假设的实验。\n\n解析：混沌工程原则——1）定义稳态——系统的哪些指标表明系统是健康的（如 P99 延迟 < 500ms、错误率 < 1%）。用可量化的指标定义。2）提出假设——假设某个故障发生时系统仍然能维持稳态（如「一台机器宕机后 P99 仍然 < 500ms」）。3）引入故障——注入真实的故障（杀 Pod、网络延迟、磁盘满、CPU 压力、DNS 故障）。4）验证结果——记录故障注入期间和之后的稳态指标变化。5）修复和改进——找出薄弱环节并加固。6）持续运行——混沌实验应该是持续运行的，不是一次性活动。\n\n扩展延伸：工具——Netflix Chaos Monkey（随机终止 EC2 实例，是最早的混沌工具，属于 Simian Army 套件）。Litmus（云原生混沌工程，支持 K8s 环境，提供 Chaos Workflow 编排实验）。Gremlin（商业工具，界面友好，支持多种故障类型）。生产环境注意事项——1）最小化爆炸半径：先在下游非关键服务实验，再逐步扩大。2）自动化回滚/中止：实验应在达到阈值或超时后自动停止。3）从非生产环境开始：先在 Staging 跑通，再进入生产。4）有 On-Call 人在线：实验期间确保有 SRE 待命。5）最有效的实验：杀 Pod（验证 K8s 自愈）、网络延迟（验证超时重试机制）、节点宕机（验证多 AZ/高可用）。","hints":["混沌工程和生产故障的区别——有假设的实验 vs 意外事件","最小化爆炸半径为什么是生产混沌实验最重要的原则"],"tags":["混沌工程","Chaos Engineering","韧性","Chaos Monkey"],"id":1765},{"category":"devops","difficulty":"medium","type":"short_answer","title":"K8s 资源请求与限制","content":"Kubernetes 中 Pod 的 requests 和 limits 有什么区别？QoS 类别（Guaranteed/Burstable/BestEffort）是如何划分的？资源超卖（Overcommit）如何处理？","answer":"答案：requests 是容器保证能获得的资源量（调度依据），limits 是容器最多能使用的资源上限（限制依据）。QoS 划分——Guaranteed（requests=limits）、Burstable（requests<limits 或只设了 requests）、BestEffort（未设置任何 requests/limits）。\n\n解析：QoS 类别——1）Guaranteed（高优先级）：所有容器 requests=limits（CPU 和内存都相同）。Pod 不会被 OOM Killer 轻易杀死。适用于关键业务应用。2）Burstable（中优先级）：至少有一个容器设置了 requests 但未全部等于 limits。没有 limits 时可以使用节点剩余资源（超卖场景）。适用于大部分应用。3）BestEffort（低优先级）：没有设置任何 requests/limits。当节点资源紧张时被 OOM Killer 最先杀死。适用于批处理/离线任务。\n\n扩展延伸：资源管理机制——1）CPU：requests 和 limits 单位是 CPU 核数（1=1 核，100m=0.1 核）。CPU 是可压缩资源——限制过度的 Pod 会被 throttle（节流）而非杀死。2）内存：requests 和 limits 单位是字节（1Gi）。内存是不可压缩资源——超过 limits 的 Pod 会被 OOM Killer 杀死。3）调度器根据节点剩余 capacity 和 Pod 的 requests 做调度决策（不参考 limits）。4）超卖（Overcommit）是常见实践：设置 CPU requests 较低但 limits 较高（允许 Pod 在空闲时使用更多 CPU，在争用时被限制）。内存不建议超卖——超出即 OOM。监控——kubectl top node/pod 查看实际资源使用。Vertical Pod Autoscaler（VPA）可根据历史使用自动调整 requests/limits。","hints":["requests 是调度依据（保证值），limits 是上限值。CPU 超限被 throttle，内存超限被 OOM","QoS 降级顺序：BestEffort 最先被杀 → Burstable → Guaranteed 最后被杀"],"tags":["DevOps","K8s","QoS","资源管理"],"id":1766},{"category":"devops","difficulty":"hard","type":"short_answer","title":"K8s Service 与网络流量路径","content":"Kubernetes Service 有哪几种类型？ClusterIP 到 Pod 的流量路径是怎样的？iptables 和 IPVS 模式的区别？kube-proxy 的作用？","answer":"答案：Service 类型：ClusterIP（集群内可访问的虚拟 IP）、NodePort（节点端口映射到 ClusterIP）、LoadBalancer（云厂商 LB + NodePort/ClusterIP）、ExternalName（DNS CNAME 映射）。kube-proxy 负责维护节点上的网络规则（iptables/IPVS），将 Service 的 ClusterIP 流量转发到对应的 Pod。\n\n解析：流量路径（以 ClusterIP 为例）——1）客户端访问 Service 的 ClusterIP:Port。2）kube-proxy 在节点上写入 iptables/IPVS 规则，匹配到 Service IP 后 DNAT（目标地址转换）为选中的 Pod IP。3）请求发送到 Pod。Pod 的回包经过反向 SNAT（将 Pod IP 转换回 Service IP）使客户端感知不到 Pod 的存在。\n\n扩展延伸：iptables vs IPVS——1）iptables 模式：kube-proxy 为每个 Service 创建 iptables 规则。匹配规则链式遍历（从第一条到最后一条匹配）。当 Service 数量大（>1000）时规则性能下降明显（规则更新 O(N)）。2）IPVS 模式（推荐）：基于 Linux 内核的 L4 负载均衡（hash 表查找，O(1) 复杂度）。支持更多负载均衡算法（rr/wlc/lc）。高性能、支持大规模 Service。kube-proxy 的模式选择——通过 kube-proxy 的 --proxy-mode 参数设置。Service 的 sessionAffinity（会话保持）通过设置 iptables/IPVS 的源 IP 哈希实现。ExternalTrafficPolicy=Local 可保留客户端源 IP（不经过 SNAT，直接将流量转发给本地 Pod，但可能负载不均）。","hints":["iptables 模式规则遍历 O(N)——Cluster 规模大（>1000 Service）时推荐 IPVS 模式","ExternalTrafficPolicy=Local 保留客户端源 IP 但可能导致负载不均——流量只转发给同一节点上的 Pod"],"tags":["DevOps","K8s","Service","网络"],"id":1767},{"category":"devops","difficulty":"hard","type":"short_answer","title":"K8s HPA 与自动伸缩","content":"Kubernetes HPA（Horizontal Pod Autoscaler）的工作原理？基于 CPU/Memory 和自定义指标的伸缩策略？HPA 的扩容和缩容有什么策略和限制？Cluster Autoscaler 和 HPA 如何配合？","answer":"答案：HPA 根据 Pod 的 CPU/内存使用率或自定义指标自动调整 Pod 副本数。核心逻辑：desiredReplicas = ceil[currentReplicas * (currentMetricValue / desiredMetricValue)]。默认支持 CPU、内存利用率。通过 Custom Metrics API 和 External Metrics API 可接入 Prometheus 自定义指标。\n\n解析：配置和行为——1）CPU/Memory 指标：targetAverageUtilization（目标平均利用率，如 80%）。HPA 周期性地（默认 15s）获取 Pod 的当前利用率，计算目标副本数。2）自定义指标：需要部署 metrics adapter（如 Prometheus Adapter）。支持每秒请求数（QPS）、队列深度、连接数等业务指标。3）扩容策略：kube-controller-manager 的 --horizontal-pod-autoscaler-downscale-stabilization（默认 5min，缩容冷却）。--horizontal-pod-autoscaler-upscale-delay（默认 3min，扩容冷却）。\n\n扩展延伸：HPA + Cluster Autoscaler——1）HPA 增加 Pod 副本数 → Pod 因资源不足 Pending → Cluster Autoscaler 检查是否有 Pending Pod → 创建新的 Node → Pod 调度成功。2）HPA 缩容 Pod → 节点负载降低 → Cluster Autoscaler 检查节点利用率 → 如果低于阈值则缩容节点。3）行为约束（behavior）：HPA 可以配置扩容/缩容的速率限制（stabilizationWindowSeconds/policy/selectPolicy）。防止指标抖动导致的频繁扩缩容（thrashing）。注意——HPA 要求 Pod 设置了 requests（没有 requests 无法计算利用率）。HPA 对 StatefulSet 的支持有限——StatefulSet 的缩容是有序的（从最大序号开始），HPA 不改变此行为。","hints":["HPA 扩缩容公式——desiredReplicas = ceil(currentReplicas * currentValue / targetValue)","HPA + Cluster Autoscaler 联动——HPA 扩容导致 Pod Pending → Cluster Autoscaler 扩容节点"],"tags":["DevOps","K8s","HPA","自动伸缩"],"id":1768},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Docker 镜像构建优化","content":"如何优化 Docker 镜像的大小？多阶段构建（Multi-stage Build）的原理？有哪些减少镜像层的技巧？Docker 镜像安全扫描的最佳实践？","answer":"答案：多阶段构建是减少镜像大小的核心技术——第一个阶段编译和依赖安装（使用完整的基础镜像），第二个阶段只复制编译产物（使用精简基础镜像，如 alpine）。其他优化：选择合适的基础镜像（alpine/distroless）、合并 RUN 指令（减少镜像层）、清理缓存和临时文件。\n\n解析：多阶段构建——1）`FROM golang:1.20 AS builder`——编译阶段使用完整 Go 工具链。`RUN go build -o /app` 编译二进制。2）`FROM alpine:3.18`——运行阶段使用精简基础镜像。`COPY --from=builder /app /app`——只从 builder 阶段复制编译产物。3）最终镜像只包含运行需要的二进制和运行时依赖，不包含 Go 编译器、源码等构建工具。\n\n扩展延伸：镜像层与缓存——1）Dockerfile 的每条 RUN/COPY/ADD 指令创建一个新镜像层。合并指令可减少层数（`RUN apt-get update && apt-get install -y pkg1 pkg2 && apt-get clean` 连成一条 RUN）。2）层的缓存：Docker 构建时如果某层没有变化则使用缓存。不变的内容放前面（如 apt 安装放在 COPY 源码之前，只在依赖变化时才重装）。3）Dockerignore：`.dockerignore` 排除不需要的文件（node_modules、.git、.env），减少构建上下文大小。安全——1）镜像扫描：Trivy（Aqua）、Clair（CoreOS）、Docker Scan（Snyk）。2）减少攻击面：不用 root 用户运行；不用包含大量工具（bash、curl、wget）的镜像。3）Distroless 镜像（Google）：只有应用和运行时，没有 shell 和包管理器（攻击面最小化但调试困难）。","hints":["多阶段构建的精髓——编译阶段用完整工具链，运行阶段用最小依赖","Docker 镜像层缓存——不常变的内容放 Dockerfile 前面，经常变的源码放后面（最大化缓存利用）"],"tags":["DevOps","Docker","镜像优化","构建"],"id":1769},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Prometheus 监控体系","content":"Prometheus 的架构和数据模型？Pull 模型和 Push 模型各自的优缺点？PromQL 的四大核心数据类型（Counter/Gauge/Histogram/Summary）？Grafana 和 Prometheus 如何配合？","answer":"答案：Prometheus 采用 Pull 模型（主动从 Targets 抓取指标）。核心组件：Prometheus Server（抓取 + 存储 + 查询）、Exporters（暴露指标）、Alertmanager（告警管理）。数据模型基于带标签（Labels）的时间序列。\n\n解析：指标类型——1）Counter（计数器）：只增不减（如请求总数、错误总数）。适用于累加数据。rate() 和 irate() 函数计算增长率（QPS）。2）Gauge（仪表盘）：可增可减（如当前内存使用、在线人数、队列长度）。3）Histogram（直方图）：对观测值（如请求延迟）进行分桶统计。可计算 P50/P90/P99（`histogram_quantile()` 函数）。4）Summary（摘要）：类似于 Histogram，但在客户端计算分位数（Prometheus 服务端无需计算）。Histogram 可以在服务端聚合多个实例的分布，Summary 不行。\n\n扩展延伸：Pull vs Push——Pull 优势：更容易做健康检查（抓取失败即服务不可用）；中心化配置。Pull 劣势：Target 需要被 Prometheus 可访问（通过网络或 Service Discovery）。Push 场景（Pushgateway）：批处理任务（运行完就退出 → 无法 Pull）；网络隔离的 Target。Grafana——数据可视化（Dashboards）+ 告警（Unified Alerting）。Alertmanager——告警路由（分组/抑制/静默）。Thanos/Cortex——Prometheus 的长期存储和全局视图方案（解决 Prometheus 单实例的存储上限和 HA 问题）。","hints":["Counter 用 rate()/irate() 算 QPS，Gauge 直接看值，Histogram/Snapshot 用 histogram_quantile() 算 P99","Pull 模型让 Prometheus 控制抓取节奏——避免 Push 模式下 Target 过多导致 Server 过载"],"tags":["DevOps","Prometheus","监控","Grafana"],"id":1770},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Docker 多阶段构建与 Distroless 镜像","content":"Docker 多阶段构建如何优化最终镜像大小？为什么 Distroless 镜像比 Alpine 更安全？如何将容器镜像压缩到最小？","answer":"答案：多阶段构建将构建环境和运行环境分离——第一阶段用完整 SDK 编译，第二阶段用极简基础镜像只复制产物。Distroless 只包含应用和运行时依赖（无 shell、无包管理器、无工具），攻击面最小化。Go 静态编译 + scratch（空镜像）可达 KB 级；Java Spring Boot + GraalVM Native Image + Distroless 可压缩到 50MB 左右。\n\n解析：多阶段构建流程——Dockerfile 多个 FROM 语句，每个 FROM 开始新阶段，AS 命名。COPY --from=前一阶段名复制产物。以 Spring Boot 为例：Stage 1（maven:3.8-eclipse-temurin-17 编译 jar）→ Stage 2（eclipse-temurin:17-jre-alpine 复制 jar）→ 最终镜像约 180MB（对比完整 SDK 镜像 1.2GB）。Distroless vs Alpine——Alpine 基于 musl libc（约 5MB），有 apk 包管理器和 shell。Distroless（Google 维护）基于 Debian 但不含 shell、ls、curl 等工具。如果攻击者通过应用漏洞进入 Distroless 容器，无法执行命令（无 bash、无 apt、无 nc），极大限制横向移动。极端压缩策略——Go：CGO_ENABLED=0 静态编译 + FROM scratch，二进制 < 15MB。Java：Spring Boot + GraalVM Native Image + Distroless Base 约 50MB。\n\n扩展延伸：镜像安全工具——Docker Scout（CVE 匹配）、Trivy（多语言/OS 支持）、Snyk（深度依赖分析）。Distroless 的生产排查问题——无法 docker exec shell 进入容器排障。解决：单独的 debug 容器（同一 Pod 的 sidecar 带完整 shell 工具链）或临时 Ephemeral Container（K8s v1.23+）。GCR Distroless 镜像系列：distroless/java、distroless/nodejs、distroless/python、distroless/cc。生产建议：80% 场景用 Alpine + apk 已足够，高安全要求用 Distroless。","hints":["Distroless 镜像没有 shell 如何进容器排查问题","多阶段构建中 COPY --from 是如何跨阶段复制文件的"],"tags":["Docker","多阶段构建","Distroless","镜像安全"],"id":1771},{"category":"devops","difficulty":"medium","type":"short_answer","title":"服务可观测性三大支柱实战","content":"日志（Logs）、指标（Metrics）、链路追踪（Traces）三者如何协同工作？OpenTelemetry 如何统一可观测性？如何根据告警快速定位问题根因？","answer":"答案：三大支柱分工——日志记录离散事件（排障细节），指标聚合趋势（监控告警），链路追踪关联请求（全链路定位）。OpenTelemetry 统一采集 API 和导出标准（OTLP），覆盖三类数据。根因定位流程：告警触发 → 查指标确定影响范围 → 查链路追踪定位异常服务 → 查关联日志定位具体代码。\n\n解析：三大支柱详解——1）日志（Logs）：结构化 JSON 格式（timestamp/level/logger/thread/message/traceId/spanId）。通过 MDC 自动注入 traceId。采集：Filebeat → Logstash → Elasticsearch → Kibana（ELK）。2）指标（Metrics）：时间序列数据（metric, labels, value, timestamp）。Prometheus 四种指标类型——Counter（累计）、Gauge（可增减）、Histogram（延迟分布）、Summary（分位数）。Exporter 采集 → Prometheus Server 拉取 → Alertmanager 告警 → Grafana 展示。3）链路追踪（Traces）：Trace → Span（traceId/spanId/parentSpanId）。Zipkin/Jaeger 存储展示。采样策略——Head-based 采样（在入口处决定）或 Tail-based 采样（根据结果决定是否保留，更精准）。SRE 黄金指标转 PromQL——延迟 p99：histogram_quantile(0.99, rate(http_request_duration_seconds_bucket[5m]))。错误率：rate(http_requests_total{status=~\"5..\"}[5m])。饱和度：node_memory_MemAvailable / node_memory_MemTotal。\n\n扩展延伸：OpenTelemetry（CNCF 孵化）——合并 OpenTracing 和 OpenCensus。一次接入（API + SDK），可导出到多种后端。架构：OTel Collector（Agent/Gateway 模式）→ Processor（批处理/过滤/采样）→ Exporter → 后端。OTel 的自动埋点：Java Agent（字节码增强自动拦截框架调用）、Python/SDK、Go SDK。与 Prometheus 集成：OTel 可直接导出到 Prometheus 或通过 OTel Collector 的 Prometheus exporter。","hints":["OTel 的自动埋点和手动埋点分别什么时候用","Tail-based 采样相比 Head-based 有什么优势"],"tags":["可观测性","OpenTelemetry","Prometheus","链路追踪","SRE"],"id":1772},{"category":"devops","difficulty":"medium","type":"short_answer","title":"K8s 调度器原理与自定义调度策略","content":"Kubernetes 调度器如何选择 Pod 应当调度到哪个 Node？如何实现自定义调度、节点亲和性和资源超分？","answer":"答案：K8s 调度器通过两阶段选择节点——过滤（Filtering）排除不符合条件的节点，打分（Scoring）对剩余节点排序选最优。自定义调度通过 NodeSelector/NodeAffinity/PodAffinity/Taints & Tolerations 实现。资源超分通过设置 requests < limits 实现（存在 OOM 风险）。\n\n解析：调度流程——1）过滤阶段：检查节点资源充足（Pod requests 总和 < 节点可分配量）、端口不冲突、主机名和标签匹配（NodeSelector/NodeAffinity）、Taints/Tolerations（不匹配 taint 的 Pod 不能调度）、PodAffinity/AntiAffinity（同/反亲和性）、卷拓扑约束。2）打分阶段：默认策略 LeastRequestedPriority（资源利用率低的节点优先）和 BalancedResourceAllocation（CPU/内存均衡）。最终选最高分节点。高级调度——NodeSelector：简单的标签匹配。NodeAffinity：requiredDuringScheduling（硬）和 preferredDuringScheduling（软）。PodAffinity/AntiAffinity：将 Pod 调度到一起或分散在不同节点。Taints：NoSchedule/PreferNoSchedule/NoExecute。Tolerations：Pod 声明可容忍的污点。自定义调度器——编写扩展调度器（实现 Extender 接口）+ Scheduler Framework 插件（Filter/Score/PreScore 等扩展点）。\n\n扩展延伸：资源超分与 QoS 等级——Guaranteed（requests=limits，最高优先）、Burstable（requests<limits，中等）、BestEffort（无 requests/limits，节点压力时优先被驱逐）。建议：重要业务用 Guaranteed，批处理用 Burstable 超分。Descheduler 定期重平衡不合理的 Pod 分配。Cluster Autoscaler 基于调度失败事件自动扩缩节点池。Karpenter（AWS 开源）比 Cluster Autoscaler 创建节点更快（秒级 vs 分钟级），直接调用 EC2 API。","hints":["Taints 和 Tolerations 如何配合实现节点专用化","三种 QoS 等级在节点资源紧张时驱逐的先后顺序"],"tags":["K8s","调度器","亲和性","QoS","资源超分"],"id":1773},{"category":"devops","difficulty":"medium","type":"short_answer","title":"CI/CD 流水线安全实践","content":"CI/CD 流水线有哪些常见安全风险？如何保护流水线中的密钥和凭证？如何在流水线中集成安全扫描（SAST/DAST/SCA）？","answer":"答案：CI/CD 常见安全风险——密钥泄露（硬编码/明文传递）、供应链攻击（依赖被篡改）、镜像漏洞（基础镜像 CVE）、越权执行（PR 触发未授权部署）。密钥保护通过 CI/CD 内置 Secret 变量（加密存储，运行时注入）或外部密钥管理（HashiCorp Vault/AWS Secrets Manager）。安全扫描集成策略：SCA（依赖扫描）→ SAST（静态代码分析）→ 镜像扫描 → DAST（动态安全测试）按阶段依次插入。\n\n解析：六层安全防线——1）代码：SAST 工具（SonarQube/CodeQL/Semgrep）扫描 SQL 注入、XSS、硬编码密码。Quality Gate 设阻断阈值。2）依赖：SCA（Snyk/Dependabot/OWASP Dependency-Check）扫描三方库已知 CVE。Critical 漏洞阻断构建。3）镜像：Trivy/Clair 扫描漏洞。验证镜像签名（Cosign）、非 root 运行。4）部署：策略即代码——OPA/Gatekeeper/Kyverno 验证部署清单（禁止 latest 镜像、必须设资源限制）。5）运行时：Falco（异常检测）、kube-bench（CIS 检查）。6）密钥管理——内置 Secret（GitHub Actions Secrets/GitLab CI/CD Variables）。外部方案：Vault 动态密钥 + 自动轮转。GitHub Actions 中 OIDC token 替代长期密钥（Workload Identity Federation）。\n\n扩展延伸：供应链安全 SLSA 框架——SLSA L1（有构建过程）→ L2（构建隔离 + 出处证明）→ L3（可复现 + 不可变构建）。Sigstore（Cosign 签名 + Fulcio 证书 + Rekor 透明日志）。GitHub Actions 最小权限——每个 Job 独立 token，scope 最小化。零信任 CI/CD——每个步骤最小权限、短期凭证、审计日志、不可变构建。知名攻击案例——Codecov（修改 bash uploader 窃取 CI 环境变量）、SolarWinds（构建系统被植入后门）、log4j（供应链依赖漏洞）。","hints":["SLSA 框架在供应链安全中定义了几个等级","为什么 CI/CD 中的密钥要用外部密钥管理而非环境变量"],"tags":["CI/CD","安全","SAST","供应链","密钥管理"],"id":1774},{"category":"devops","difficulty":"hard","type":"short_answer","title":"K8s HPA 与弹性伸缩体系","content":"Kubernetes HPA 如何基于指标自动伸缩 Pod 副本数？如何确定合理的资源请求和限制？HPA、VPA、Cluster Autoscaler 如何配合实现完整弹性伸缩？","answer":"答案：HPA 周期性检查 Pod 指标（CPU/内存/自定义指标）使用率，计算期望副本数（currentMetricValue / desiredMetricValue x currentReplicas），修改 Deployment replicas 实现水平伸缩。资源 requests 基于历史 p99 使用量，limits 按 requests 的 1.5-2 倍设定。HPA（水平 Pod 伸缩）+ VPA（垂直调整 requests/limits）+ Cluster Autoscaler（节点伸缩）三件套实现完整弹性。\n\n解析：HPA 原理——1）默认 15 秒间隔从 Metrics Server 读取 Pod 指标。2）算法：desiredReplicas = ceil[currentReplicas x (currentMetricValue / desiredMetricValue)]。3）冷却逻辑：扩容无延迟，缩容默认 5 分钟冷却（--horizontal-pod-autoscaler-downscale-stabilization）。4）多指标时取最大副本数。自定义指标——Prometheus Adapter 提供 custom.metrics.k8s.io 接口，支持基于 QPS、队列深度、延迟等业务指标伸缩。KEDA（KEDA.sh）扩展事件源——Kafka/RabbitMQ/SQS/Prometheus。资源设定——requests 根据 99 分位历史用量定（保证调度），limits 按 1.5-2 倍设（允许突发峰值）。VPA 的 Recommendation 模式自动分析历史用量给出建议值。Goldilocks 工具可视化推荐值。\n\n扩展延伸：三件套协同流程——1）VPA 离线分析历史数据调整 requests。2）HPA 根据实际用量伸缩 Pod 数。3）Pod 因资源不足 Pending → Cluster Autoscaler 扩容节点池。4）低谷 → HPA 缩容 → CA 识别低负载节点迁移 Pod 后缩容节点。注意：VPA 和 HPA 共用 CPU/内存指标时冲突，标准做法是互斥使用（VPA 管 CPU/内存，HPA 管自定义指标）。Karpenter（AWS）比 Cluster Autoscaler 更快（秒级响应），直接管理 EC2 实例而非节点组。","hints":["HPA 计算期望副本数时多条指标如何决定最终值","VPA 和 HPA 为何不能共享 CPU/内存指标"],"tags":["K8s","HPA","VPA","Cluster Autoscaler","弹性伸缩"],"id":1775},{"category":"devops","difficulty":"medium","type":"short_answer","title":"GitOps 工作流与 ArgoCD","content":"什么是 GitOps？它与传统 CI/CD 有什么本质区别？GitOps 的核心原则是什么？ArgoCD 如何实现 GitOps？","answer":"答案：GitOps 以 Git 仓库作为声明式基础设施和应用的唯一真相来源（Single Source of Truth），所有环境状态变更通过 Git 操作（Pull Request）驱动，自动同步到目标集群。核心区别：GitOps 是 Pull-based（Agent 从 Git 拉取期望状态），传统 CI/CD 是 Push-based（CI 工具推送到环境）。\n\n解析：GitOps 的核心原则（Weaveworks 定义）——1）声明式描述：整个系统用声明式配置文件定义（K8s YAML、Terraform、Helm Chart），而不是命令式脚本。2）Git 作为唯一真相来源：所有环境（开发、预发、生产）的期望状态都存储在 Git 中。3）自动同步：GitOps Operator（如 ArgoCD、Flux CD）持续对比 Git 中的期望状态和集群中的实际状态，自动（或手动批准）将集群同步到期望状态。4）自愈机制：如果有人在集群中手动修改了资源（配置漂移），Agent 会检测到偏差并自动回滚到 Git 中的状态。\n\n扩展延伸：GitOps 的实践——1）ArgoCD 工作流程：开发修改 K8s Manifest -> PR 审批合并到 main -> ArgoCD 检测到 Git 变更 -> 自动同步到集群（可通过 Sync Policy 控制自动/手动同步）。2）GitOps vs CI/CD：CI/CD 负责「构建和验证」（CI 阶段和 CD 初始化阶段），GitOps 负责「部署和同步」（持续保证集群与 Git 一致）。两者互补。3）多环境管理：Kustomize overlay 或 Helm Value 文件区分开发/预发/生产环境配置。4）渐进式交付：结合 Argo Rollouts 实现蓝绿部署、金丝雀发布、自动化回滚。GitOps 的优势：操作可审计（所有变更通过 Git 有记录）、更好的故障恢复（回滚 = git revert）、开发自服务。","hints":["GitOps 中的 Pull-based 部署比 Push-based 有什么优势","ArgoCD 如何检测和修复配置漂移"],"tags":["GitOps","ArgoCD","CI/CD","K8s"],"id":1776},{"category":"devops","difficulty":"medium","type":"short_answer","title":"蓝绿部署与金丝雀发布","content":"蓝绿部署（Blue-Green Deployment）和金丝雀发布（Canary Release）的策略是什么？各自解决什么问题？如何选择？","answer":"答案：蓝绿部署维护两套完全相同的生产环境（蓝和绿），新版本部署到空闲环境后，通过切换流量一次性升级。金丝雀发布新版本先让少量用户使用，观察无问题后逐步扩大流量比例。两种策略的目标都是降低发布风险。\n\n解析：蓝绿部署——两套环境：绿环境（当前线上版本），蓝环境（新版本）。部署流程：1）在蓝环境部署新版。2）运行验证测试（smoke test 或健康检查）。3）切换路由/负载均衡器将流量从绿切换到蓝。4）出现问题立即切回绿。优点：切换快（秒级），回滚速度快。缺点：资源成本翻倍（需运行两套环境），数据库兼容（数据库架构变更需向前/向后兼容）。金丝雀发布——1）初始阶段：将 1%-5% 的流量导向新版本（金丝雀实例）。2）监控：观察新版本的错误率、延迟、业务指标。3）逐步扩量：10% -> 25% -> 50% -> 100%。4）评估指标并在任何阶段发现问题时自动回滚。优点：风险可控，影响范围小。缺点：发布周期长，需要完善的监控和自动化。\n\n扩展延伸：选择建议——1）蓝绿部署适合：发布频率低、环境稳定、资源充足的项目。2）金丝雀发布适合：高流量业务、需要灰度验证、对稳定性要求极高的系统（如支付宝、Google 搜索）。3）混合策略：先用金丝雀验证（小流量），确认无误后蓝绿全量切换。K8s 实现——蓝绿：通过 Service Selector 切换 label（version=v1 -> version=v2）。金丝雀：通过 Deployment 创建多个版本 Pod，Service 加权分发（如 Istio/Argo Rollouts 控制流量比例）。","hints":["蓝绿部署中数据库变更（Schema Migration）如何兼容——向前兼容和向后兼容","K8s 原生 Service 能做金丝雀发布吗——为什么需要 Service Mesh（如 Istio）"],"tags":["蓝绿部署","金丝雀发布","发布策略","Argo Rollouts"],"id":1777},{"category":"devops","difficulty":"hard","type":"short_answer","title":"容量规划与弹性伸缩","content":"什么是容量规划（Capacity Planning）？它的核心目标和方法是什么？如何结合水平伸缩（HPA）和垂直伸缩（VPA）实现弹性？容量规划中常见的陷阱有哪些？","answer":"答案：容量规划是通过分析历史负载趋势、设定资源预算、规划未来扩容方案，确保系统在成本可控的前提下满足业务增长和突发流量。核心方法包括业务驱动预测、压测峰值估算、资源利用率建模。弹性伸缩使系统能够根据实际负载自动调整资源。\n\n解析：容量规划的步骤——1）数据收集：采集 CPU/内存/磁盘/网络的使用率、QPS 趋势、请求延迟分布、每月增长速率。2）预测建模：线性回归（稳定增长）、周期性分析（电商有 11.11 高峰，教育有寒暑假高峰）、指数平滑。3）设定阈值和预留：确定资源利用率的预警水位（如 CPU > 70% 预警）、目标水位（如 CPU 目标利用率 50%）、紧急水位（如 CPU > 90% 触发扩缩容）。4）弹性伸缩策略——水平伸缩（HPA，Horizontal Pod Autoscaler）：增加/减少实例数量，受启动时间（冷启动）限制。垂直伸缩（VPA，Vertical Pod Autoscaler）：增加/减少单个实例的资源（CPU/内存），需要重启实例。组合策略：VPA 保证单个 Pod 的资源充足，HPA 保证整体容量弹性。5）突发流量预案：提前预热缓存、扩容临时集群、降级非核心服务、限流保护。\n\n扩展延伸：容量规划的常见陷阱——1）过度规划（Over-provisioning）：按峰值容量长期运行，成本浪费 50%-70%。解决方案：弹性 + 按需购买（云原生）。2）预测偏差：业务增长预测不准（涨得太快或太慢）。解决方案：定期重新评估（每季度/每月）。3）冷启动问题：HPA 扩容时需要拉镜像、JVM 预热，耗时 1-5 分钟。突发流量在这段时间内可能打垮现有实例。解决方案：预先保持适量冗余（Buffer）、使用 PDB（Pod Disruption Budget）保护核心实例、结合 KEDA（基于事件驱动）提前扩容。4）资源争抢：不同业务混部时，一个业务的突发影响其他业务。解决方案：资源隔离（Namespace ResourceQuota）、服务质量分级（Guaranteed/Burstable/BestEffort）。","hints":["水平伸缩和垂直伸缩各自适合什么场景——JVM 应用为什么冷启动慢","Kubernetes HPA 基于 CPU/Metrics 的扩缩容为什么有时不够及时"],"tags":["容量规划","HPA","VPA","弹性伸缩"],"id":1778},{"category":"devops","difficulty":"medium","type":"short_answer","title":"可观测性三大支柱","content":"可观测性（Observability）的三大支柱是什么？它们各自的定位、数据模型和典型工具是什么？可观测性和传统监控的区别是什么？","answer":"答案：可观测性三大支柱：指标（Metrics）、日志（Logs）、链路追踪（Traces）。传统监控关注「已知可能出问题的地方」（设置阈值告警），可观测性关注「未知的问题」（没有预设阈值的探索式分析），让你在任何时候都能回答「系统现在为什么是这个状态」。\n\n解析：三大支柱详解——1）指标（Metrics）——时序数据，记录系统状态随时间变化。数据模型：指标名 + 标签（Label/Tag）+ 时间戳 + 值。类型：Counter（累计计数，如请求总数）、Gauge（可增可减，如当前连接数）、Histogram（分布统计，如请求延迟分位数 P50/P99）、Summary（预计算的分位数聚合）。典型工具：Prometheus + Grafana。2）日志（Logs）——带时间戳的离散事件，记录应用运行过程中发生的事件。原始格式：非结构化文本或结构化 JSON。集中方案：ELK（Elasticsearch + Logstash + Kibana）/ EFK（Fluentd 替代 Logstash）/ Loki（轻量级日志聚合，与 Prometheus 标签一致）。上下文关联：有 Correlation ID（Trace ID）的日志才能关联到具体请求。3）链路追踪（Traces）——记录一个请求在分布式系统中的完整调用路径。Span：一次远程调用或方法执行（含开始时间、耗时、状态）。Trace：由多个 Span 组成的有向无环图（DAG）。上下文传播：Trace ID 通过 HTTP Header（如 W3C traceparent）在服务间传递。典型工具：Jaeger、Zipkin、OpenTelemetry。\n\n扩展延伸：三大支柱的关联——1）黄金信号：USE（Utilization、Saturation、Errors）、RED（Rate、Errors、Duration）。2）发展方向：OpenTelemetry（统一数据采集标准）。3）成本和选型：小团队 Prometheus + 简单的日志工具 + 有限的链路追踪就够了，不需要一开始上全栈。警惕过度可观测性——每个请求打印十几行日志、采集数十个指标，最终成本远超预期。","hints":["Metrics 和 Logs 的区别——什么时候看指标，什么时候看日志","分布式链路追踪中 Trace ID 如何在服务间传递"],"tags":["可观测性","Prometheus","链路追踪","OpenTelemetry"],"id":1779},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Jenkins Pipeline 共享库设计","content":"请详细说明 Jenkins Pipeline 共享库（Shared Libraries）的结构设计、加载方式（动态加载 vs 静态加载），以及在大型团队中如何组织共享库实现流水线标准化。","answer":"答案：Jenkins Shared Library 是一种将流水线公共逻辑抽取为可复用模块的机制。共享库目录结构包括：vars/（定义全局变量/函数，每个 .groovy 文件对应一个可调用步骤）、src/（标准 Java 类结构，用于更复杂的逻辑封装）、resources/（外部资源文件）。团队可将构建、部署、测试等通用步骤封装为共享库，各项目 Jenkinsfile 仅需几行调用即可。\n\n解析：两种加载方式：1) 隐式加载（Global Pipeline Libraries）—— 系统管理员配置共享库名称和仓库地址，所有流水线自动加载，适合组织级通用步骤；2) 动态加载（@Library 注解）—— 每个 Jenkinsfile 通过 @Library('my-shared-lib@version') _ 显式引用，_ 号表示引入所有全局变量。版本管理通过 Git Tag 或分支实现（@Library('my-shared-lib@v1.2.3')）。共享库设计最佳实践：函数的入参使用 Map 参数兼容扩展（如 def call(Map args)）；每个步骤包含版本号用于追溯；步骤内调用其他步骤形成组合模式。\n\n扩展延伸：大型团队中共享库治理要素：1) 版本化 —— 使用 SemVer 管理共享库版本，不同项目可锁定不同版本避免升级影响；2) 测试 —— 引入共享库的单元测试（JenkinsPipelineUnit 框架）确保步骤正确性；3) 评审制度 —— 共享库变更需经过 Code Review，因为一次修改会影响所有引用项目；4) 模块拆分 —— 按场景拆分（构建库、部署库、安全扫描库），避免单一共享库过于庞大；5) 配合 Configuration as Code（JCasC）实现全局配置声明化管理。","hints":["vars/ 目录下的 .groovy 文件自动成为流水线可调用的步骤","隐式加载方便但难以管理版本，动态加载更适合跨版本共存","JenkinsPipelineUnit 可对共享库步骤编写单元测试"],"tags":["DevOps","Jenkins","共享库","Pipeline"],"id":1780},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Trunk-Based 开发模式与 Feature Flags","content":"请说明 Trunk-Based Development（主干开发）的核心原则、短生命周期分支实践，以及 Feature Flags（特性开关）如何配合主干开发实现\"未完成功能\"的安全合入。","answer":"答案：Trunk-Based Development（TBD）是一种 Git 分支策略，开发者直接或在极短生命周期（<1天）的特性分支上工作，频繁合并到主干（main/trunk）。核心原则是\"频繁提交、小批量合并、减少并行分支\"。TBD 与 GitFlow 等长分支策略形成鲜明对比 —— GitFlow 的 develop/release/hotfix 分支在 TBD 中被简化为只有主干+临时特性分支。\n\n解析：TBD 的关键实践：1) 特性分支不超过 1-2 天，避免分支与主干偏离过大导致合并冲突；2) 每次提交保持可发布状态（deployable），必须通过 CI 验证；3) 未完成的功能通过 Feature Flags（特性开关）隐藏 —— 代码已合入主干但功能未对用户开放。Feature Flags 的实现方式：if (featureToggle.isEnabled(\"new-checkout\")) { newLogic() } else { oldLogic() }。托管服务有 LaunchDarkly、Split.io，也可自建基于配置中心的方案。Feature Flags 分多种类型：发布开关（控制功能发布）、实验开关（A/B 测试）、权限开关（白名单用户可见）、运维开关（动态降级能力）。\n\n扩展延伸：Feature Flags 的风险和最佳实践：1) 技术债 —— 废弃的开关代码需及时清理，避免\"Flags 腐化\"；2) 嵌套开关 —— 多个开关组合的测试组合爆炸，需限制同时活跃的开关数量；3) 开关配置中心 —— 生产环境慎用运行时开关变更，需有权限审批和审计日志；4) TBD + Feature Flags 配合 CI/CD 可实现\"持续发布\"而非\"持续部署\" —— 功能合入主干后，通过开关控制逐步开放给用户，发现问题立即关闭开关回退；5) 推荐使用 LaunchDarkly 等专业平台而非自建复杂的开关系统。","hints":["TBD 要求特性分支存活时间不超过 1-2 天","Feature Flags 让未完成的功能可安全合入主干","废弃的 Feature Flags 需要纳入技术债管理"],"tags":["DevOps","TBD","Feature Flags","Git策略"],"id":1781},{"category":"devops","difficulty":"hard","type":"short_answer","title":"SAST/DAST 与代码安全扫描","content":"请解释 SAST（静态应用安全测试）和 DAST（动态应用安全测试）的区别、CI/CD 流水线中的集成时机，以及依赖扫描（SCA）和容器镜像扫描在软件供应链安全中的角色。","answer":"答案：SAST（白盒测试）在开发阶段分析源代码，无需运行程序即发现 SQL 注入、XSS、硬编码密钥等安全漏洞。DAST（黑盒测试）在测试或预发布阶段对运行中的应用发起模拟攻击，检测运行时安全问题（如配置错误、认证绕过）。SCA（Software Composition Analysis）扫描开源依赖的已知漏洞（通过 CVE/NVD 数据库匹配），容器镜像扫描检查基础镜像中的漏洞包。\n\n解析：在 CI/CD 流水线中的集成位置：1) SAST 在开发者提交代码后立即触发（Pre-commit hook 或 CI 的第一步），反馈最快但可能产生误报。常用工具：SonarQube（支持多种语言安全分析）、Semgrep（可自定义规则）、Checkmarx/Fortify（商业）。2) SCA 在依赖安装阶段执行，扫描 pom.xml/package.json/go.mod 等锁定文件。常用工具：OWASP Dependency-Check、Snyk、GitHub Dependabot。3) DAST 在测试环境部署后执行（集成测试阶段）。常用工具：OWASP ZAP、Burp Suite。4) 容器镜像扫描在镜像构建后触发，优先推荐在 Push 到仓库时扫描（Trivy、Clair、Anchore）。\n\n扩展延伸：安全扫描的门禁策略：1) 严重漏洞阻断 —— 发现 CVSS >= 9.0 的漏洞立即阻断流水线；2) 误报管理 —— 建立 Suppression 机制标记误报并附带原因说明；3) 时间窗口 —— 对于无已知利用的高危漏洞可设置修复宽限期（如 7 天）；4) SBOM（Software Bill of Materials）—— 生成 SPDX/CycloneDX 格式的 SBOM 并归档，满足供应链安全合规要求；5) 镜像签名和验证 —— 使用 cosign 对镜像签名，部署时验证签名确保镜像未被篡改。","hints":["SAST 在编码阶段执行，DAST 在运行时执行，两者互补","SCA 扫描的漏洞库需要定期更新才能检测最新漏洞","SBOM 已成为供应链安全合规的必备产出"],"tags":["DevOps","SAST","DAST","安全扫描","SCA"],"id":1782},{"category":"devops","difficulty":"easy","type":"short_answer","title":"Artifactory/Nexus 制品仓库管理","content":"请介绍制品仓库（Artifact Repository）在 DevOps 中的作用，对比 Sonatype Nexus 和 JFrog Artifactory 的特性，并说明构建物版本管理与清理策略的最佳实践。","answer":"答案：制品仓库是 DevOps 流水线的核心组件，用于存储和管理构建产物（JAR/WAR、Docker 镜像、npm 包、Python 包等）。它不仅解决了\"依赖从哪里来\"的问题，还承担了版本管理、元数据存储、安全扫描等职责。Nexus Repository OSS（免费开源版）和 JFrog Artifactory（有免费层）是最主流的两种制品仓库。\n\n解析：Nexus 和 Artifactory 的对比：Nexus 支持 Maven、npm、Docker、PyPI、NuGet 等主流格式，开源版功能足够大部分团队使用；Artifactory 支持更多包格式（Helm、Conan、Vagrant 等），提供更丰富的元数据管理和先进的构建集成（Build Integration —— 记录构建的依赖关系和产物映射）。两者都支持代理远程仓库（缓存公网依赖，加速 CI 构建）和本地仓库（存储自研产物）。Nexus 的 Blob Store 实现存储分层（可配置冷热数据分离），Artifactory 支持多站点复制（适合跨国团队）。\n\n扩展延伸：制品管理最佳实践：1) 版本策略 —— 采用 SemVer 语义化版本，快照版本（SNAPSHOT/-SNAPSHOT）仅用于开发迭代，发布版本用 release 仓库；2) 清理策略 —— 设置保留策略（如保留最近 N 个快照版本，定期删除超过 30 天的快照），避免磁盘膨胀；3) 二进制安全 —— 制品上传前自动触发病毒扫描和漏洞扫描；4) 制品签名 —— 使用 GPG 签名确保完整性和来源可信；5) 集成 CI/CD —— 构建成功后自动上传到制品仓库，部署时从制品仓库拉取指定版本。","hints":["制品仓库代理上游公共仓库可以显著提升 CI 构建速度和稳定性","快照版本的自动清理是磁盘空间管理的关键","构建信息（Build Info/Integrations）是制品追溯的\"黑匣子\""],"tags":["DevOps","Nexus","Artifactory","制品管理"],"id":1783},{"category":"devops","difficulty":"hard","type":"short_answer","title":"策略即代码（OPA/Gatekeeper）","content":"请解释策略即代码（Policy as Code）的理念，详细说明 OPA（Open Policy Agent）和 Gatekeeper 的架构、Rego 策略语言的核心概念，以及在 Kubernetes 场景中的常见策略场景。","answer":"答案：策略即代码（Policy as Code）是一种将安全策略、合规规则、治理要求以代码形式声明、版本化和自动执行的方法。OPA（Open Policy Agent）是 CNCF 毕业项目，提供统一的策略评估引擎，将策略从具体服务中解耦。Gatekeeper 是基于 OPA 的 Kubernetes Admission Webhook，用于在 K8s 集群中执行策略约束。\n\n解析：OPA 的架构核心是策略决策（Policy Decision）与策略执行（Policy Enforcement）的分离：1) 服务将查询（Query）发给 OPA，传入 JSON 格式的输入数据；2) OPA 根据 Rego 策略计算出决策（allow/deny/自定义）并返回。Rego 语言基于 Datalog 逻辑编程范式，支持数据嵌套遍历、规则映射、否定存在检查等强大表达。Gatekeeper 的工作流：用户创建 ConstraintTemplate（定义策略逻辑的 Rego 模板）→ 创建 Constraint（实例化模板，指定参数和生效范围）→ 资源创建时 Mutation/Validation Webhook 拦截请求 → OPA 进行评估 → 审查通过/拒绝。常见策略：确保所有 Pod 设定 resource limits/requests；禁止 privileged 容器；要求 Pod 指定 securityContext；限制 Ingress 只能使用加密的 TLS；所有镜像必须来自信任仓库。\n\n扩展延伸：Rego 策略编写技巧：1) 使用 deny 变量的赋值（deny[msg]）收集所有违规信息，而非一次性 fail；2) 善用 data.inventory 获取集群全景信息（如检查 Namespace 是否存在）；3) 使用 mock 和测试框架（opa test）为策略编写单元测试。Gatekeeper 的 Dry-Run 模式允许在不阻断的情况下预览策略影响，是推广策略的推荐方式。OPA 不仅用于 K8s，还可用于 Terraform 计划验证（terraform plan 阶段检查基础设施合规性）、API 授权（通过 OPA Envoy Plugin 集成 Envoy）、数据过滤等场景。","hints":["OPA 做决策，Gatekeeper 做 K8s 准入控制","Rego 的 deny[msg] 模式可以收集多条违规信息","Gatekeeper 的 Dry-Run 模式适合策略的灰度推广"],"tags":["DevOps","OPA","Gatekeeper","Policy as Code","安全"],"id":1784},{"category":"devops","difficulty":"medium","type":"short_answer","title":"GitOps 与 ArgoCD 实践","content":"请介绍 GitOps 的概念、核心原则以及 ArgoCD 的工作原理和关键特性。","answer":"答案：GitOps 是由 Weaveworks 提出的云原生运维模式，以 Git 仓库作为声明式基础设施和应用的唯一真实来源。核心原则：1) 声明式描述——整个系统的期望状态以 Kubernetes manifests、Helm Chart 或 Kustomize 形式定义在 Git 仓库中；2) 版本化和可审计——Git 历史记录每一次变更；3) 自动同步——Operator/GitOps Agent 持续比较集群实际状态与 Git 期望状态；4) Pull-based 部署——Agent 从 Git Pull 而非 CI Push 到集群。ArgoCD 是 CNCF 毕业项目，工作原理：1) 通过 Git Repository Connection 连接到 Git；2) 使用 Application CRD 定义从哪个 Repo 的哪个路径部署到哪个目标集群；3) Controller 持续运行 Diff 循环，比较集群状态和 Git 状态；4) Auto Sync + Auto Prune 自动删除 Git 中已移除的资源。\n\n解析：ArgoCD 与 Flux v2 的主要区别：ArgoCD 提供功能全面的 Web UI + Dashboard，适合团队可视化运维；Flux v2 更注重轻量和 sdk-led 设计，使用 Kubernetes 扩展资源，不依赖 CRD 之外的组件。选择依据：需要 Web UI 和 ApplicationSet 选 ArgoCD；追求轻量、使用 OCI 制品、希望与 Flux 的 SOPS 原生集成选 Flux v2。ArgoCD 的 App of Apps 模式适合大规模多团队集群。\n\n扩展延伸：GitOps 进入生产环境的常见模式：1) 单一仓库——所有环境配置在同一个 Git 仓库中，通过目录划分；2) 应用仓库 + 配置仓库分离；3) 配合 Kustomize Overlay 实现环境差异化。安全性增强：通过 ArgoCD Vault Plugin / Sealed Secrets 管理敏感配置。推荐阅读：ArgoCD 的 Progressive Delivery with Analysis（蓝绿发布 + 自动回滚）功能。","hints":["GitOps 的 Push-based 和 Pull-based 部署模式区别","ArgoCD 持续 Diff 的调和逻辑"],"tags":["DevOps","GitOps","ArgoCD"],"id":1785},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Helm Chart 最佳实践","content":"请介绍 Helm Chart 的最佳实践，包括 Values 设计、模板化技巧和 Chart 版本管理。","answer":"答案：Helm Chart 是 Kubernetes 应用的包管理格式，最佳实践涵盖以下方面：1) Values 设计——a) 使用全局和特定值分离的原则，global 值可以被子 Chart 继承；b) 为每个重要字段提供注释说明；c) 使用 YAML 锚点和别名减少重复；d) 定义完整示例 values.yaml。2) 模板化技巧——a) 优先使用 include 而非 template；b) 使用 named templates 封装重复逻辑；c) 使用 required 确保关键值存在；d) 使用 toYaml 输出结构化配置段；e) 使用 lookup 函数实现条件式创建。3) Chart 版本——a) 遵循 SemVer2，appVersion 和 chartVersion 分开；b) 使用 Chart.lock 锁定依赖版本。\n\n解析：Helm Chart 的典型文件结构：Chart.yaml（元信息）/values.yaml（默认配置）/charts/（依赖子 Chart）/templates/（Go 模板）/templates/NOTES.txt。最佳实践补充：使用 _helpers.tpl 定义通用命名模板；hooks 使用 annotation helm.sh/hook-weight 控制执行顺序；使用 condition 和 tags 控制可选依赖。避免：硬编码 Namespace、在模板中使用 .、忽略资源请求限制的配置项。\n\n扩展延伸：生产级 Helm 工作流：使用 helm-template 插件 + CI 验证模板渲染结果；使用 helm-docs 自动从 values.yaml 注释生成 README；使用 helm-unittest 插件测试模板输出；将 Chart 发布到 OCI Registry；使用 helmfile 或 ArgoCD 管理 Helm Release 的生命周期。CNCF Artifact Hub 是 Helm Chart 的分发中心。安全检查：helm lint + kubeval 在 CI 中验证 Chart 的合法性。","hints":["Values 文件中 global 字段的作用","include 和 template 在 Helm 模板中的区别"],"tags":["DevOps","Helm","Kubernetes"],"id":1786},{"category":"devops","difficulty":"medium","type":"short_answer","title":"GitOps 工作原理","content":"请解释 GitOps 的工作原理和核心优势。GitOps 与传统 CI/CD 在部署方式上有什么本质区别？ArgoCD 是如何实现 GitOps 的？","answer":"答案：GitOps 是以 Git 仓库作为唯一的声明式基础设施和应用的真相来源（Source of Truth）的运维模式。\n\n工作原理：\n1. 运维人员在 Git 仓库中声明期望的系统状态（K8s YAML、Helm Chart）\n2. GitOps Operator（如 ArgoCD、Flux）持续监控 Git 仓库的变化\n3. 当 Git 仓库发生变化时，Operator 自动将集群状态同步到 Git 中描述的状态\n4. 如果集群状态被手动修改，Operator 会自动恢复到 Git 中声明的状态（自愈）\n\nGitOps vs 传统 CI/CD：\n- 传统 CI/CD：CI 构建产物（镜像），CD 推送到集群（推模式 Push-based）\n- GitOps：Git 仓库存储期望状态，Operator 从 Git 拉取并同步（拉模式 Pull-based）\n- GitOps 不依赖 CI 系统的网络连接到集群，安全性更好\n\nArgoCD 实现：\n1. 应用定义（Application CRD）：指定 Git 仓库路径、目标集群、同步策略\n2. Sync 机制：将 Git 仓库中的 manifest 应用到集群\n3. Sync 策略：自动/手动/自动修剪（Prune）\n4. 健康检查：评估应用的健康状态并进行回滚\n\n扩展延伸：GitOps 的核心优势——可审计（所有变更都在 Git 中）、可回滚（git revert）、团队协作（PR 审查）。Flux 是另一个流行的 GitOps 工具（更轻量）。GitOps 不仅适用于 K8s，也适用于 Terraform 等基础设施管理（如 Terraform Cloud 的 VCS-driven workflow）。","hints":["GitOps = Git 仓库作为 Source of Truth + Operator 持续同步","ArgoCD 采用 Pull-based 模式，不依赖 CI 网络连接到集群"],"tags":["DevOps","GitOps","ArgoCD","持续部署"],"id":1787},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Terraform 状态管理","content":"请解释 Terraform 的状态（State）文件的作用和远程状态管理方案。Terraform 如何处理团队协作中的状态冲突？State Locking 是如何实现的？","answer":"答案：Terraform 状态文件记录基础设施的当前状态，是 Terraform 决定如何变更的核心依据。\n\nState 文件的作用：\n1. 将配置中的资源与真实世界的基础设施进行映射\n2. 存储元数据（依赖关系、属性值）\n3. 性能优化——避免每次 plan 都调用云 API 列出所有资源\n\n远程状态管理方案：\n1. S3 + DynamoDB（AWS）：最常用的方案\n2. Terraform Cloud/Enterprise：托管的远程状态和锁\n3. Azure Storage Blob + Lease\n4. Google Cloud Storage + Object Versioning\n\n状态冲突处理：\n1. State Locking：在运行 terraform apply 时锁定状态，防止并发操作\n2. 后端类型：DynamoDB（AWS）、Consul、Terraform Cloud 提供锁定\n3. 如果锁被占用，terraform 会等待并重试\n4. 强制解锁：terraform force-unlock <LOCK_ID>（需要谨慎使用）\n\nState Locking 实现：\n- DynamoDB：使用 DynamoDB 的 ConditionExpression（attribute_not_exists(LockID)）实现原子操作\n- 获取锁：PutItem（条件写入）\n- 释放锁：DeleteItem\n- 锁超时：通常没有自动超时，防止被异常释放\n\n扩展延伸：Terraform Workspace 管理不同环境（dev/staging/prod）的状态隔离。状态文件包含敏感信息（如数据库密码），需要加密存储。Terragrunt 是 Terraform 的封装工具，提供 DRY 配置和更好的状态管理。","hints":["Terraform 状态文件映射配置与真实资源，是变更的核心依据","DynamoDB 通过 ConditionExpression 实现 State Locking"],"tags":["DevOps","Terraform","状态管理","IaC"],"id":1788},{"category":"devops","difficulty":"medium","type":"short_answer","title":"容器镜像安全扫描","content":"请介绍容器镜像安全扫描的实践方法。如何在 CI/CD 流水线中集成镜像安全扫描？Trivy 和 Snyk 有什么区别？","answer":"答案：容器镜像安全扫描是 DevSecOps 的核心实践。\n\n扫描内容：\n1. 操作系统漏洞（CVE）：检测基础镜像中的已知漏洞\n2. 依赖库漏洞：检测应用依赖（npm、pip、maven）中的已知漏洞\n3. 密钥泄漏：检测镜像中是否包含密钥、Token 等敏感信息\n4. 恶意软件：检测镜像中是否包含恶意文件\n5. 许可证合规：检测依赖的开源许可证\n\nCI/CD 集成：\n1. Push 时扫描：代码提交后自动构建并扫描镜像\n2. 合并门禁：扫描结果中高危漏洞数量超过阈值时阻止合并\n3. 定期扫描：对已部署的镜像进行定期扫描\n4. 运行时扫描：使用 Falco 等工具检测容器运行时异常\n\nTrivy vs Snyk：\n- Trivy：开源免费，使用 Aqua 维护的漏洞数据库。速度快，集成简单（单二进制文件）。适合自建 DevSecOps 流水线。\n- Snyk：商业产品，有免费层。漏洞数据库更全面。提供 IDE 插件、PR 检查和修复建议。适合企业级全面安全方案。\n\n扩展延伸：Docker Scout 是 Docker 官方的镜像安全分析工具。Google Container Analysis 与 Artifact Registry 集成。最小化基础镜像（Distroless、Alpine、Scratch）从源头减少漏洞面。多阶段构建确保最终镜像不包含构建工具。Sigstore（Cosign）实现镜像签名和验证。","hints":["Trivy 开源免费轻量，Snyk 商业全面提供修复建议","多阶段构建和最小基础镜像从源头减少漏洞面"],"tags":["DevOps","安全","容器","Trivy"],"id":1789},{"category":"devops","difficulty":"medium","type":"short_answer","title":"K8s RBAC 最佳实践","content":"请解释 Kubernetes RBAC（基于角色的访问控制）的设计原则和最佳实践。如何实现最小权限原则？ServiceAccount 和 User 的区别是什么？","answer":"答案：K8s RBAC 通过 Role/ClusterRole 和 RoleBinding/ClusterRoleBinding 控制对集群资源的访问。\n\n核心概念：\n- Role：命名空间内的权限规则（如对 Pod 的 get/list/watch 权限）\n- ClusterRole：集群级别的权限规则（如对 Node、PV 的访问，或对所有命名空间资源的访问）\n- RoleBinding：将 Role 绑定到 User/Group/ServiceAccount\n- ClusterRoleBinding：将 ClusterRole 绑定到集群级别的 User/Group/ServiceAccount\n\nServiceAccount vs User：\n- User：真实的人。通过外部认证（OIDC、X.509 证书）管理，K8s 没有 User 资源对象\n- ServiceAccount：Pod 使用的身份。有对应的 K8s 资源对象，自动挂载到 Pod\n- Pod 通过 /var/run/secrets/kubernetes.io/serviceaccount/token 使用 SA Token\n\n最小权限原则：\n1. 从零开始：不给任何权限，按需授予\n2. 使用 Role 而非 ClusterRole：除非确实需要集群级别的权限\n3. 细化资源粒度：verbs（get/list/watch/create/update/delete）和 resources（pods/services）具体化\n4. 只开放需要的 API 组：apps/v1、batch/v1、networking.k8s.io/v1\n5. Aggregation Rule：通过 ClusterRole 聚合组合多个 Role\n6. 定期审计：使用 kubectl auth can-i --list 或 kubectl audit\n\n扩展延伸：RBAC 不足以覆盖所有安全需求——配合 Pod Security Admission（PSA）、NetworkPolicy、OPA/Gatekeeper 实现多层安全。审计日志（Audit Log）记录所有 API 请求，用于安全审计。kubectl auth reconcile 同步 RBAC 配置。","hints":["SA 是 Pod 的身份，User 是人的身份","最小权限：从零开始，按需授予，定期审计"],"tags":["DevOps","K8s","RBAC","安全"],"id":1790},{"category":"devops","difficulty":"medium","type":"short_answer","title":"容器镜像构建优化","content":"请介绍 Docker 镜像构建的优化策略。多阶段构建（Multi-stage Build）如何减小镜像体积？如何利用构建缓存加速构建？","answer":"答案：Docker 镜像优化核心是减少层数和体积。\n\n多阶段构建（Multi-stage Build）：\n- 使用多个 FROM 语句，每个 FROM 是一个独立的构建阶段\n- 第一阶段（build）：包含编译工具链（JDK/Go SDK/npm），编译出 artifact\n- 第二阶段（runtime）：只包含运行时环境（JRE/空镜像），从第一阶段 COPY artifact\n- 最终镜像只包含运行时环境和 artifact，不包含编译工具\n\n示例（Go）：\nFROM golang:1.20 AS builder\nWORKDIR /app\nCOPY go.mod go.sum ./\nRUN go mod download\nCOPY . .\nRUN go build -o app .\n\nFROM alpine:3.18\nCOPY --from=builder /app/app /app\nCMD [\"/app\"]\n\n构建缓存利用：\n- Docker 构建时逐层缓存——如果某层未变化，直接使用缓存\n- 优化技巧：先复制不常变的文件（go.mod/go.sum），再复制源代码\n- COPY go.mod go.sum ./（缓存命中）→ RUN go mod download（缓存命中）→ COPY . .（源代码变了才重新构建）\n- .dockerignore 排除不需要的文件（node_modules、.git、.env）\n\n基础镜像选择：\n- alpine（5MB）：最小，但 musl libc 可能不兼容\n- distroless（Google）：只包含应用和运行时依赖（无 shell、无包管理器），安全\n- slim（Debian 精简版）：兼容性好\n\n扩展延伸：镜像分析工具——dive（分层分析）、docker-slim（自动瘦身）。Docker BuildKit——新一代构建引擎（DOCKER_BUILDKIT=1），支持并行构建和更好的缓存。OCI 镜像标准——多架构镜像（manifest list）支持同一镜像在不同架构上运行。","hints":["多阶段构建 = build 阶段（工具链）+ runtime 阶段（仅 artifact），镜像大幅减小","缓存优化：先复制依赖文件（go.mod/package.json），后复制源码"],"tags":["DevOps","Docker","镜像","构建"],"id":1791},{"category":"devops","difficulty":"medium","type":"short_answer","title":"持续部署策略对比","content":"请对比不同的持续部署（Continuous Deployment）策略。滚动更新、蓝绿部署、金丝雀发布和 A/B 测试各有什么适用场景？","answer":"答案：四种部署策略各有侧重，选择取决于业务需求和风险容忍度。\n\n滚动更新（Rolling Update）：\n- 逐步替换旧版本实例为新版本（每次替换 1 个或少量实例）\n- K8s 默认策略：设置 maxSurge（最多超过期望的实例数）和 maxUnavailable（最多不可用实例数）\n- 优点：不需额外资源，最经济\n- 缺点：回滚慢（需要逐步替换回去），发布期间新旧版本共存\n- 适用：内部服务、非关键业务、资源敏感场景\n\n蓝绿部署（Blue-Green）：\n- 维护两套完整环境（蓝=旧、绿=新），一次性切换流量\n- 优点：切换瞬间完成（秒级），回滚极快（切回蓝环境即可）\n- 缺点：需要两倍资源，数据库需向前兼容\n- 适用：关键业务、数据库迁移（需要保持旧版本对新版本数据的兼容）\n\n金丝雀发布（Canary）：\n- 新版本先接收少量流量（5%），验证后再逐步扩展到 100%\n- 结合监控指标决定是否继续或回滚\n- 适用：面向用户的 Web 服务、高变更风险的发布\n\nA/B 测试（A/B Testing）：\n- 让不同用户群体体验不同版本，收集业务指标决定哪个版本更好\n- 目的不是降低发布风险，而是对比功能效果\n- 适用：UI 改版、算法实验、推荐系统对比\n\n安全发布的核心原则：\n- 灰度发布流程：内部测试（5%）→ 内部全量（20%）→ 外部灰度（50%）→ 全量（100%）\n- 自动回滚条件：错误率上升 > 5%、P99 延迟增加 > 20%、关键业务指标下降","hints":["滚动更新（最经济，回滚慢）→ 蓝绿（资源翻倍，瞬间切换）→ 金丝雀（逐步放量，验证后全量）→ A/B（对比功能效果）","灰度发布渐进：5%内部→20%内部→50%外部→100%全量，错误率上升自动回滚"],"tags":["DevOps","部署","金丝雀","蓝绿部署"],"id":1792},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Helm 包管理","content":"请介绍 Helm——Kubernetes 的包管理工具。Chart、Release 和 Repository 的概念是什么？Helm 模板如何实现参数化部署？","answer":"答案：Helm 将 K8s 资源打包为 Chart，通过参数化模板简化 Kubernetes 应用部署。\n\n核心概念：\n- Chart：一个 Helm 包，包含一组 K8s 资源定义（YAML 模板 + 默认值）\n- Release：Chart 的一次部署实例（同一 Chart 可以部署多次，每次是一个 Release）\n- Repository：Chart 的存储仓库（如 Artifact Hub / Harbor）\n\nChart 目录结构：\nmyapp/\n├── Chart.yaml          # Chart 元数据（名称、版本、依赖）\n├── values.yaml         # 默认配置值\n├── templates/          # Go Template 模板文件\n│   ├── deployment.yaml\n│   ├── service.yaml\n│   ├── _helpers.tpl    # 可复用的命名模板\n│   └── NOTES.txt       # 安装后的提示信息\n└── charts/             # 子 Chart（依赖）\n\n模板引擎（Go Template）：\n- {{ .Values.replicaCount }} ——引用 values.yaml 中的值\n- {{ .Release.Name }} ——内置对象（Release 名称）\n- {{ .Chart.Name }} ——Chart 元数据\n- {{ include \"myapp.fullname\" . }} ——复用 _helpers.tpl 中定义的模板\n- 控制结构：{{- if .Values.service.enabled }} ... {{- end }}\n- 范围遍历：{{- range .Values.ports }} ... {{- end }}\n\nHelm 操作：\n- helm install myapp ./myapp-chart ——安装 Chart 创建 Release\n- helm upgrade myapp ./myapp-chart ——升级 Release\n- helm rollback myapp 1 ——回滚到第 1 个版本\n- helm uninstall myapp ——卸载 Release\n- helm template ./myapp-chart ——本地渲染模板（不部署到集群）\n\n扩展延伸：Helm 2 vs Helm 3——Helm 2 需要 Tiller（服务端组件），Helm 3 移除 Tiller（更安全、更简单）。Helm Hooks——在 Release 生命周期的特定点执行 Job（如数据库迁移）。Helm 依赖管理——通过 dependencies 字段管理子 Chart。Kustomize——Helm 的替代方案（不依赖模板，使用原生 YAML + patch）。","hints":["Helm = Chart（包）+ Release（实例）+ Repository（仓库）","Go Template：values.yaml 提供参数，templates/ 渲染为 K8s YAML"],"tags":["DevOps","Helm","Kubernetes","包管理"],"id":1793},{"category":"devops","difficulty":"medium","type":"short_answer","title":"CI/CD 管道设计","content":"请设计一个现代化的 CI/CD 管道。CI 阶段和 CD 阶段的职责分别是什么？CI 中的制品（Artifact）管理如何实现版本追溯？","answer":"答案：CI/CD 管道自动化代码从提交到生产的全过程。\n\nCI（持续集成）阶段：\n1. 代码检出：从 Git 仓库拉取代码\n2. 依赖安装：下载项目依赖（npm install / pip install / go mod download）\n3. 代码检查：Lint（ESLint/Pylint）、格式化检查（Prettier）、类型检查（TypeScript）\n4. 单元测试：运行单元测试 + 生成覆盖率报告\n5. 构建：编译代码（npm build / go build / mvn package）\n6. 安全扫描：依赖漏洞扫描（Snyk/Trivy）、SAST（静态安全分析）\n7. 制品生成：将构建产物打包为 Docker 镜像或 JAR/WAR\n8. 制品上传：推送到制品仓库（Docker Registry / Nexus / Artifactory）\n\nCD（持续交付/部署）阶段：\n1. 部署到测试环境：自动化部署到 staging/QA 环境\n2. 集成测试：运行集成测试、E2E 测试\n3. 性能测试：压力测试、基准测试（可选）\n4. 审批门：手动或自动审批（成功率 > 90%、延迟 < 阈值）\n5. 灰度部署：部署到生产环境的部分节点（金丝雀发布）\n6. 健康检查：监控部署后的错误率、延迟、业务指标\n7. 全量发布：验证通过后将流量切换到新版本\n\n制品版本追溯：\n- 每个构建生成唯一版本号（git commit SHA / 语义版本号）\n- 制品标签包含：版本号 + 构建时间 + Git Commit + 分支名\n- 从版本号可追溯到：代码提交、代码审查、构建日志、测试结果\n- 实现：Git Tag → CI Build → 制品仓库（Docker Image Tag 与 Git Commit 一一对应）\n\n扩展延伸：CI/CD 平台对比——Jenkins（可定制最强）、GitHub Actions（生态好，配置简单）、GitLab CI（一体化）、CircleCI（速度快）。Pipeline as Code——将管道定义写入代码仓库（.github/workflows/*.yml / .gitlab-ci.yml / Jenkinsfile）。","hints":["CI = 代码检查 + 测试 + 构建 → 制品；CD = 部署 + 验证 + 灰度 + 全量","制品版本追溯：版本号 = Git Commit SHA → 可追踪到代码/审查/构建日志/测试"],"tags":["DevOps","CI/CD","管道","自动化"],"id":1794},{"category":"devops","difficulty":"medium","type":"short_answer","title":"服务网格与服务治理","content":"请介绍服务网格（Service Mesh）的原理和架构。Sidecar 模式如何实现流量管理、可观测性和安全通信？Istio 的核心组件有哪些？","answer":"答案：服务网格通过 Sidecar 代理实现微服务间通信的控制，将流量管理、可观测性和安全策略从业务代码中剥离到基础设施层。\n\n核心架构：\n1. 数据平面（Data Plane）：每个服务实例旁部署 Sidecar 代理（Envoy），拦截所有进出流量\n2. 控制平面（Control Plane）：集中管理 Sidecar 的配置和策略\n\nIstio 核心组件：\n- Pilot：服务发现和流量管理（路由规则、故障注入、超时重试）\n- Citadel：证书管理和 mTLS 通信\n- Galley：配置验证和分发\n- Envoy：Sidecar 代理，实现实际的流量拦截和转发\n\n核心能力：\n1. 流量管理：蓝绿部署、金丝雀发布、灰度路由、故障注入（延迟/中断）\n2. 可观测性：分布式追踪（Jaeger/Zipkin）、指标（Prometheus）、日志\n3. 安全：mTLS 服务间加密通信、RBAC、JWT 认证\n4. 韧性：重试、超时、熔断、限流、健康检查\n\nSidecar 注入方式：\n- 手动注入：在 Deployment 中添加 Sidecar 容器\n- 自动注入：利用 Admission Webhook 自动注入 Sidecar\n\n扩展延伸：服务网格的争议——引入 Envoy Sidecar 会增加延迟（5-10ms）和资源消耗（每个 Sidecar ~50MB 内存）。是否有必要？简单场景用 K8s Service + Istio 就够了。性能敏感场景可用 eBPF 方案（Cilium Service Mesh）替代 Sidecar 模式。WASM 扩展——Envoy 支持 WASM Filter 实现自定义流量处理逻辑。","hints":["服务网格 = Sidecar（数据平面）+ 控制平面，将通信层剥离出业务代码","Istio 核心：Pilot（路由）+ Citadel（mTLS 证书）+ Envoy（Sidecar 代理）","性能争议：Sidecar 模式增加 5-10ms 延迟和内存消耗，eBPF 方案正在兴起"],"tags":["DevOps","服务网格","Istio","Sidecar"],"id":1795},{"category":"devops","difficulty":"medium","type":"short_answer","title":"GitOps 工作流与工具链","content":"请介绍 GitOps 的核心原则和主流的 GitOps 工具链。","answer":"答案：GitOps 是一种以 Git 仓库为唯一事实来源（Single Source of Truth）的运维模式。\n\n核心原则：\n1. 声明式配置：系统的期望状态用配置（YAML/JSON）声明\n2. 版本控制：所有配置存储在 Git 中，不可变、可审计\n3. 自动同步：变更推送到 Git 后，自动同步到实际环境\n4. 自愈：实际环境偏离 Git 状态时自动修复（Drift Detection）\n\n工作流：\n1. 开发者修改 K8s YAML → 提交 PR\n2. 代码审查（CI 检查 + 人工 review）\n3. 合并到主分支\n4. GitOps Operator 检测到 Git 变更\n5. Operator 将新状态应用到 K8s 集群\n6. 持续监控（Drift Detection + 自愈）\n\n工具链：\n\n1. Argo CD：\n   - 最流行的 K8s GitOps 工具\n   - 支持多集群管理\n   - Web UI 直观\n   - Sync 策略：自动/手动\n2. Flux：\n   - 轻量级、无需数据库\n   - 深度 K8s 集成（Kustomize、Helm 原生支持）\n   - 支持多租户\n3. Jenkins X：\n   - 全栈 CI/CD + GitOps\n   - 自动化环境管理和预览环境\n   - 学习成本高\n\nGit vs OCI 存储：\n- 传统 GitOps：YAML 存储在 Git\n- OCI 制品（如 Helm Chart）：存储在 OCI Registry\n- 趋势：Git 存源码 + Helm/Manifest，OCI Registry 存构建产物\n\n扩展延伸：GitOps 的价值不仅在于自动化部署——更关键的是灾难恢复（从 Git 重建整个集群）和审计合规（每一次变更都有 Git commit 记录）。","hints":["核心原则：Git 为唯一事实源 + 声明式配置 + 自动同步 + 漂移自愈","主流工具：Argo CD（最流行，多集群）、Flux（轻量，K8s 原生）","关键价值：灾难恢复（从 Git 重建集群）和审计合规（Git commit 记录）"],"tags":["DevOps","GitOps","Argo CD","Flux"],"id":1796},{"category":"devops","difficulty":"medium","type":"short_answer","title":"CI/CD 流水线设计原则","content":"请介绍 CI/CD 流水线的设计原则以及常见的流水线阶段拆分。","answer":"答案：CI/CD 流水线是软件交付的核心基础设施，设计质量直接影响交付效率。\n\n设计原则：\n\n1. 快速反馈：\n   - 构建和测试应在 10 分钟内完成\n   - 失败时立即通知（Slack/邮件）\n   - 分阶段：快速检查在前，耗时验证在后\n\n2. 幂等性：\n   - 同一代码版本、同一流水线 → 同样结果\n   - 重复运行不产生副作用\n   - 依赖是显式的（不依赖环境状态）\n\n3. 不可变产物：\n   - 构建一次，多次部署（Build Once, Deploy Many）\n   - 产物带版本号（semver 或 commit SHA）\n   - 产物仓库（Nexus/Artifactory/Docker Registry）\n\n4. 左移（Shift Left）：\n   - 问题越早发现成本越低\n   - 静态检查、单元测试在提交阶段\n   - 安全扫描、性能测试在前置阶段\n\n典型流水线阶段：\n\n1. 代码提交：\n   - lint / format check\n   - 静态类型检查\n   - 单元测试 + 覆盖率收集\n\n2. 构建和集成：\n   - 编译/打包\n   - 构建 Docker 镜像\n   - API 集成测试\n   - 安全扫描（SAST/SCA）\n\n3. 测试环境部署：\n   - 部署到 Dev/Test 环境\n   - 端到端测试\n   - 性能基线测试\n   - 安全扫描（DAST）\n\n4. 预发布验证：\n   - Staging 环境部署\n   - 集成验收测试\n   - 数据迁移验证\n   - 回滚演练\n\n5. 生产发布：\n   - 金丝雀/蓝绿发布\n   - 监控观察（错误率、延迟）\n   - 自动回滚条件\n\n工具选型：\n- CI 引擎：GitHub Actions（推荐）、GitLab CI、Jenkins\n- 产物存储：Docker Registry、Nexus\n- 安全扫描：SonarQube（SAST）、Trivy（容器扫描）、Snyk（SCA）\n- 发布策略：Argo Rollouts、Flagger\n\n扩展延伸：流水线的效率瓶颈通常不是工具本身，而是测试速度。合理的做法是做测试分层——单元测试快跑（必须通过）、集成测试精选（核心路径）、E2E 测试按需触发。","hints":["原则：快速反馈（10 分钟内）、幂等性、不可变产物、左移","阶段：提交检查 → 构建+安全扫描 → 测试部署 → 预发布 → 金丝雀→ 全量","瓶颈通常是测试速度——测试分层：单元快跑、集成精选、E2E 按需"],"tags":["DevOps","CI/CD","流水线","GitHub Actions"],"id":1797},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Docker 镜像构建最佳实践","content":"请列出 Docker 镜像构建的最佳实践及其原因。","answer":"答案：良好的 Docker 镜像构建直接影响构建速度、镜像大小和安全性。\n\n1. 多阶段构建（Multi-stage Build）：\n   - 示例：第一阶段（用 Maven 镜像编译 + 测试），第二阶段（用 JRE 镜像运行）\n   - 好处：最终镜像只包含运行所需内容，不包含构建工具\n   - 效果：可减少 50-80% 的镜像大小\n\n2. 优化层缓存（Layer Caching）：\n   - 将很少变更的层放在前面（系统依赖 → 包安装 → 应用代码）\n   - 常用技巧：先 COPY package.json 再 RUN npm install，最后 COPY 源码\n   - 原因：Docker 层的 Cache 机制——层变更后所有后续层都需要重构建\n\n3. 选择基础镜像：\n   - Alpine：最小（5MB），但有 C 库兼容问题\n   - Slim：Debian 精简版，兼容性好\n   - Distroless（Google）：不可变，安全性最高\n   - 原则：够用就好，不需要完整 OS\n\n4. 安全实践：\n   - 以非 root 用户运行（USER appuser）\n   - 定期扫描 CVE（Trivy / Grype）\n   - 固定基础镜像版本（不用 latest）\n   - 最小化安装（--no-install-recommends）\n\n5. .dockerignore：\n   - 忽略 node_modules、.git、.env、__pycache__ 等\n   - 减少构建上下文大小\n   - 避免敏感文件不小心打包进镜像\n\n6. HEALTHCHECK：\n   - 定义健康检查命令\n   - K8s 自动检测容器健康状态\n\n7. LABEL 元数据：\n   - 添加 maintainer、构建日期、git commit、version 等\n   - 便于运维管理和问题排查\n\n示例 Dockerfile 结构：\n```dockerfile\nFROM node:20-slim AS build\nWORKDIR /app\nCOPY package.json .\nRUN npm ci --only=production\nFROM gcr.io/distroless/nodejs20-debian12\nCOPY --from=build /app /app\nUSER 1000\nEXPOSE 3000\nHEALTHCHECK --interval=30s CMD wget --no-verbose --tries=1 localhost:3000/health\nCMD [\"app.js\"]\n```\n\n扩展延伸：现代容器构建的趋势是使用 BuildKit（Docker 内置，支持并行构建和更好的缓存）和 Kaniko（在 K8s 内安全构建镜像，无需 Docker daemon）。","hints":["多阶段构建大幅减少镜像大小，分层顺序优化缓存命中","选择合适的基础镜像（Alpine 最小、Slim 兼容、Distroless 最安全）","关键实践：非 root 用户、.dockerignore、固定版本、CVE 扫描"],"tags":["DevOps","Docker","容器","镜像优化"],"id":1798},{"category":"devops","difficulty":"medium","type":"short_answer","title":"SRE 的核心原则与实践","content":"请介绍 SRE（Site Reliability Engineering）的核心原则和关键实践。","answer":"答案：SRE 是 Google 提出的将软件工程应用于运维的方法论。\n\n核心原则：\n\n1. 服务等级目标（SLO）：\n   - SLI（服务质量指标）：延迟、错误率、吞吐、饱和度\n   - SLO（目标）：99.9% 请求在 200ms 内完成\n   - SLA（协议）：对客户的承诺，通常比 SLO 宽松\n   - 错误预算 = 100% - SLO（如 99.9% SLO → 0.1% 的允许错误）\n\n2. 错误预算（Error Budget）：\n   - 核心思想：可用性是产品特性，不是绝对目标\n   - 消耗完错误预算 → 冻结新功能发布（专注稳定性）\n   - 平衡可靠性和创新速度\n\n3. 减少运维琐事（Toil）：\n   - 手工操作如重启、扩容等应通过自动化\n   - 目标：运维工程时间 ≤ 50%\n\n4. 监控和告警：\n   - 日志（Logs）：发生了什么\n   - 指标（Metrics）：计量什么\n   - 追踪（Traces）：单个请求的路径\n   - 告警规则：Page（立即处理）→ Ticket（工作时间处理）→ Log（记录不告警）\n\n5. 变更管理：\n   - 渐进式发布（金丝雀 → 逐步放量）\n   - 自动化回滚\n   - 变更评审\n\n5. 应急响应：\n   - 不可变基础设施：出现问题时直接替换而非修复\n   - 事后总结（Postmortem）：无责备的文化\n   - 行动项跟踪落地\n\n关键实践：\n\n1. 容量规划：基于 SLO 的容量预测和自动扩缩\n2. 混沌工程（Chaos Engineering）：主动注入故障验证系统韧性\n3. 部署自动化：滚动更新、蓝绿部署\n4. 自愈系统：自动检测和恢复常见故障\n\n扩展延伸：SRE 和传统运维的区别——SRE 不是岗位名称而是方法论。核心区别在于：SRE 用软件工程的方法解决运维问题（写代码替代手动操作），传统运维偏重流程和规则管理。","hints":["三大核心：SLO（目标）、SLI（指标）、错误预算（可用性容忍度）","关键原则：减少 Toil、监控三支柱（Logs/Metrics/Traces）、事后无责备","SRE ≠ 运维岗位——是用软件工程方法解决运维问题的方法论"],"tags":["DevOps","SRE","可靠性","监控"],"id":1799},{"category":"devops","difficulty":"medium","type":"short_answer","title":"基础设施即代码的工具链","content":"请对比 Terraform、Pulumi 和 Ansible 三种基础设施即代码（IaC）工具的设计理念和使用方式。","answer":"答案：三种工具代表了 IaC 的不同设计方向——声明式、编程式和配置管理。\n\nTerraform：\n\n类型：声明式 IaC（Hashicorp Configuration Language）\n\n原理：\n- 通过 HCL 声明期望状态\n- Terraform Core 解析配置 → 构建资源图 → 生成执行计划 → Apply\n- 维护状态文件（State）跟踪实际资源\n\n特点：\n- 不可变基础设施（资源被修改时先销毁再重建）\n- Provider 插件化（AWS、Azure、GCP、K8s 等数千个）\n- 状态文件管理（本地/远程 + 锁）\n- 模块化和工作空间（Module / Workspace）\n- 适用：云资源创建和管理\n\nPulumi：\n\n类型：编程式 IaC（通用编程语言：TS/ Python/Go/Java）\n\n原理：\n- 使用 Python/TypeScript/Go 等语言编写基础设施配置\n- 自动推断依赖关系和执行顺序\n- 自动管理状态\n\n特点：\n- 通用编程语言的表达能力（循环、条件、函数、类）\n- 不需要学习 DSL（已有语言技能）\n- 可测试性（单元测试基础设施代码）\n- 适用：需要复杂逻辑的基础设施编排\n\nAnsible：\n\n类型：配置管理 + 编排（声明式 Playbook + 命令式模块）\n\n原理：\n- 通过 SSH 连接到目标机器执行任务\n- 幂等性设计（多次执行结果一致）\n- Agentless（不需要在目标机安装代理）\n\n特点：\n- YAML Playbook 语法\n- 面向现有服务器的配置管理\n- 应用部署和配置编排\n- 适用：服务器配置、应用部署\n\n对比：\n| 维度 | Terraform | Pulumi | Ansible |\n|------|-----------|--------|--------|\n| 范式 | 声明式 DSL | 编程式 | Playbook |\n| 状态管理 | 有（State File） | 有 | 无（幂等） |\n| 执行方式 | API 调用 | API 调用 | SSH 执行 |\n| 不可变 | 是 | 是 | 否（可变） |\n| 学习成本 | 中（HCL） | 高（语言+库） | 低（YAML） |\n\n选择建议：\n- 云资源管理 → Terraform（最成熟的生态）\n- 需要编程逻辑 → Pulumi\n- 服务器配置管理 → Ansible\n- 完美组合：Terraform 创建基础设施 + Ansible 配置服务器","hints":["Terraform：HCL 声明式，不可变基础设施，状态文件管理，最成熟的 IaC 生态","Pulumi：通用编程语言（TS/Python/Go），表达能力更强","Ansible：Agentless SSH 配置管理，适合服务器配置而非云资源创建"],"tags":["DevOps","Terraform","Pulumi","Ansible","IaC"],"id":1800},{"category":"devops","difficulty":"medium","type":"short_answer","title":"DevOps 度量指标 DORA 与 SPACE","content":"请解释 DORA 和 SPACE 两种 DevOps 度量框架的核心指标。","answer":"答案：DORA 关注交付速度与稳定性指标，SPACE 补充了人本和组织维度的度量\n\n解析：DORA（2014 年 Google DevOps 报告）四项关键指标：1）部署频率（Deploy Frequency）— 吞吐量指标，精英团队按需部署，低效团队月/季度部署 2）变更前置时间（Lead Time for Change）— 从代码提交到生产上线的时长 3）变更失败率（Change Fail Rate）— 部署导致的服务降级/故障比例 4）故障恢复时间（Time to Restore Service）— 从故障发现到恢复的时长。DORA 根据指标表现将团队分为精英、高、中、低四个级别。SPACE（2021 年 Nicole Forsgren 等提出）补充了 DORA 未覆盖的五个维度：S（满意度与福祉）、P（绩效）、A（活动）、C（沟通协作）、E（效率与流程）。\n\n扩展延伸：实际落地：1）不追求所有指标同时最优——部署频率提高可能增加变更失败率，需找到组织的平衡点 2）指标需要结合行业和团队上下文，如金融行业变更失败率应远低于创业公司 3）避免指标游戏化（只看数据不看人）和局部优化（只提频次不考虑质量）。DORA 基准（精英团队）：部署频率每日多次、前置时间 <1天、变更失败率 <5%、恢复时间 <1小时。工具链：GitLab DORA API（自动从 Git 事件和部署计算）、Harness（DevOps 平台集成 DORA）、自定义（从 Jira + Jenkins + PagerDuty 聚合数据）。SPACE 的满意度/福祉指标需通过 匿名调查收集，不能完全靠自动化数据。","hints":["为什么部署频率和变更失败率是矛盾的","DORA 精英团队的四项指标基准线是多少"],"tags":["DevOps","度量","DORA"],"id":1801},{"category":"devops","difficulty":"hard","type":"short_answer","title":"ArgoCD 与 GitOps 实践","content":"请解释 ArgoCD 的工作原理及其在 GitOps 流程中的核心作用。","answer":"答案：ArgoCD 是 K8s 上实现 GitOps 的工具，确保集群状态与 Git 仓库中的声明式配置一致\n\n解析：核心原理：ArgoCD 通过持续监控 Git 仓库中的 K8s 清单（Helm/Kustomize/纯 YAML），将仓库中的期望状态与集群中的实际状态对比，检测到差异时自动同步（Auto Sync）或提示手动同步。架构：ArgoCD 以 Operator 模式运行在 K8s 集群中（argocd-server + argocd-repo-server + argocd-application-controller），提供 Web UI 和 CLI 管理应用。Repository 存储应用定义的配置，通过 webhook 实现自动同步（当 Git 仓库有变更时触发 ArgoCD 同步）。同步策略：1）Prune（删除集群中不在 Git 中的资源）2）Self-Heal（检测到集群状态被人为修改时自动恢复）3）Sync Waves（控制资源创建/更新的顺序）。\n\n扩展延伸：多环境管理：Staging 和 Production 共用同一 repo 但分支不同（staging/main），Staging 用自动同步，Production 用手动同步 + 审批。应用集：ArgoCD ApplicationSet 利用模板生成多个 Application（每个环境/集群一个），简化多集群管理。与 Kustomize 配合：Git 仓库 base/overlays 目录结构（base 定义通用资源，overlays/dev/staging/prod 各环境的 patch）。与 Helm 配合：repo 中存储 values 文件，Chart 引用自 Helm Repo。Pull 模式 vs Push 模式：传统 CI 推送到集群，GitOps 用 Git 作为单一事实来源，ArgoCD 从仓库拉取——避免外部 CI 对集群的直接写入，安全性更高。安全性：ArgoCD 支持 SSO（OIDC/OAuth2）、RBAC、Project 隔离。","hints":["GitOps 中 Git 仓库作为单一真实来源的含义","ArgoCD 的 Self-Heal 机制和 Prune 策略有什么风险"],"tags":["GitOps","ArgoCD","K8s"],"id":1802},{"category":"devops","difficulty":"medium","type":"choice","title":"Dockerfile 层构建","content":"以下 Dockerfile 指令中，哪一项不会创建新的镜像层？","options":["A) RUN apt-get update && apt-get install -y python3","B) COPY app.py /app/","C) ENV APP_HOME=/usr/src/app","D) FROM python:3.11-slim"],"answer":"C","hints":["ENV、CMD、ENTRYPOINT、EXPOSE、LABEL 等元数据指令不增加层"],"tags":["Docker","镜像","优化"],"id":1803},{"category":"devops","difficulty":"medium","type":"short_answer","title":"持续交付与持续部署的区别","content":"请解释持续交付（Continuous Delivery）和持续部署（Continuous Deployment）的区别。","answer":"答案：两个概念的差异在于生产环境部署是否经过人工审批\n\n解析：持续交付：代码合并到主分支后自动经过构建、测试和预发布阶段，但部署到生产环境需要人工点击确认按钮。持续交付确保每次提交的代码都是可发布状态的（随时可以发布到生产），但出于业务节奏或风险控制考虑保留人工审批环节。持续部署：代码合并到主分支后全流程自动从构建、测试、部署直到上线，没有人工干预。持续部署是持续交付的进一步自动化，适用于需要快速迭代的产品（SaaS、Web 应用）。两者共同的前提：高质量自动化测试套件（单元、集成、E2E）+ 良好的部署策略（滚动更新/蓝绿部署）+ 完善的监控和回滚能力。\n\n扩展延伸：成熟的持续交付 pipeline 阶段：Commit -> 单元测试 -> 静态分析/代码扫描 -> Build -> 集成测试 -> 制件管理（Artifactory/Nexus）-> 部署到 Staging -> 验收/性能测试 -> 预生产镜像 -> 批准 -> 部署到生产 -> 监控/告警。什么时候不适合持续部署：1）传统金融/医疗受监管行业（需要 Change Approval Board 审批）2）客户端应用（App Store/Google Play 审核周期长，无法频繁发布）3）嵌入式/硬件固件。工具链实践：持续交付常用 Spinnaker（多云部署，支持金丝雀发布）；持续部署在 K8s 上用 Argo Rollouts（渐进式交付，流量渗透）。","hints":["持续交付和持续部署的最终区别在哪里","什么团队才适合做真正的持续部署"],"tags":["CI/CD","持续交付","DevOps"],"id":1804},{"category":"devops","difficulty":"hard","type":"short_answer","title":"云成本优化 FinOps","content":"请介绍 FinOps 的核心理念和云成本优化实践。","answer":"答案：FinOps 将财务管理与 DevOps 结合，通过跨团队协作实现云支出最大化价值\n\n解析：FinOps 三阶段生命周期：1）Inform（可见性）— 成本归因到团队/项目/服务，对每个资源打标签（tagging），通过云厂商的 Cost Explorer 或第三方工具（CloudHealth/Spot by NetApp）可视化。建立成本中心和预算规则。2）Optimize（优化）— 识别闲置/浪费资源（未绑定的 EBS、低利用率实例、orphaned Load Balancer），调整实例类型到合适的规格。承诺使用优惠（Reserved Instance / Savings Plans）对稳态负载降 30-60%。利用 Spot 实例运行容错/无状态工作负载。3）Operate（持续运营）— 设置预算告警（当支出超过阈值时自动通知），定期的成本评审会议优化架构。建立成本文化：工程团队享有成本可见性并对自身资源消耗负责。\n\n扩展延伸：K8s 成本优化：利用 HPA/VPA 自动调整副本和资源，利用 Karpenter/Cluster Autoscaler 自动扩缩集群，使用 node pool 分离 spot 和 on-demand 工作负载。K8s 成本分摊难点——多租户下的计算资源如何分摊到团队：基于 request 分配（和调度一致但未考虑实际使用），基于指标（Prometheus 采集实际使用量，OpenCost 推荐）。云原生 FinOps 工具：Kubecost（实时 K8s 成本可视化）、Crane（腾讯开源 FinOps 平台，推荐率和扩缩容建议）。降本案例：合理配置 HPA request 从 2:1 降到 1.2:1 利用率为 60->80% 节省 25%，小实例合并大实例（200 台 2c4g->80 台 8c16g）集群整体利用率提升。","hints":["Reserved Instance 和 Spot Instance 分别适合什么负载","FinOps 中工程团队需要什么级别的成本可见性"],"tags":["FinOps","云成本","优化"],"id":1805},{"category":"devops","difficulty":"medium","type":"short_answer","title":"GitOps 工作流详解与 ArgoCD 架构解析","content":"GitOps 的核心原则是什么？ArgoCD 作为 GitOps 工具是如何工作的？ArgoCD 如何保证集群状态与 Git 仓库中的期望状态一致？","answer":"答案：GitOps 的核心原则是使用 Git 仓库作为声明式基础设施和应用的单一事实来源（Single Source of Truth），通过自动化工具确保集群的实际状态与 Git 中定义的期望状态一致。ArgoCD 是 Kubernetes 生态中最流行的 GitOps 工具，它持续监控 Git 仓库中的资源配置（K8s Manifest/Helm/Kustomize），自动将集群状态同步到仓库中的定义状态。\n\n解析：1）GitOps 五大原则——声明式描述（整个系统的期望状态通过声明式配置定义）、版本控制（所有配置变更通过 Git 管理，可审计、可回滚）、不可变存储（Git 作为可信的唯一事实来源）、自动同步（自动将声明式配置应用到目标环境）、持续验证（持续监测和修正漂移）。\n\n2）ArgoCD 架构——Application Controller：核心组件，持续对比 Git 中定义的期望状态和集群中的实际状态，检测到差异时触发同步（自动或手动）。API Server：提供 gRPC/REST API，Web UI 和 CLI 通过 API Server 管理应用。Repo Server：缓存 Git 仓库内容，生成 Manifests（支持 Helm/Kustomize/Jsonnet）。Application CRD：定义 Git 仓库路径、目标集群、同步策略等。\n\n扩展延伸：3）同步策略——自动同步（Auto Sync）：检测到配置漂移时自动修正。手动同步：审批后才执行。同步波（Sync Waves）：控制资源创建的先后顺序（先创建 Namespace 再部署应用）。4）Prune 策略——自动清理集群中不在 Git 仓库中定义的资源。5）SSO 集成——ArgoCD 支持 OIDC/LDAP/SAML，集成 RBAC 权限控制。6）对比 Flux（另一个 CNCF GitOps 工具）：ArgoCD 提供 Web UI 更丰富，支持多集群管理更好。Flux 更轻量，依赖少（不需要 CRD）。7）生产建议——禁止直接通过 kubectl 修改集群资源（配置漂移的大敌），所有变更必须走 Git PR 流程。","hints":["ArgoCD 的 Auto Sync 和 Manual Sync 分别在什么场景下使用","配置漂移（Configuration Drift）是指什么——ArgoCD 如何检测和处理"],"tags":["GitOps","ArgoCD","Kubernetes","CD"],"id":1806},{"category":"devops","difficulty":"medium","type":"short_answer","title":"金丝雀部署（Canary Deployment）与蓝绿部署的适用场景对比","content":"金丝雀部署（Canary Deployment）和蓝绿部署（Blue-Green Deployment）是两种常用的发布策略。它们的核心区别是什么？分别在什么场景下适合使用？各自的优缺点是什么？","answer":"答案：金丝雀部署将新版本逐步引入（先给少量用户使用），观察无问题后逐步扩大到全部流量。蓝绿部署维护两套完整环境（蓝色=当前生产，绿色=新版本），通过切换流量入口一次性将全部流量切换到新环境。金丝雀适合风险控制，蓝绿适合即时切换和快速回滚。\n\n解析：1）金丝雀部署——流程：新版本部署到少量实例 -> 将小比例流量（如 5%）路由到新版本 -> 监控指标（错误率/延迟/业务指标）-> 逐步扩大比例（10% -> 50% -> 100%）-> 发现问题则回滚（将流量切回旧版本）。关键技术：服务网格（Istio 流量权重调整）、K8s 的 Service 流量比例控制、应用层灰度规则（按用户 ID 或地域路由）。优点：风险最小化，影响范围可控，可验证真实流量下的表现。缺点：部署周期长（逐步放量需要时间），需要完善的监控和自动化回滚能力。\n\n2）蓝绿部署——流程：准备好与当前生产（蓝色）完全一致的新环境（绿色）-> 在绿色环境部署新版本并做完整验证 -> 验证通过后将流量入口从蓝色切换到绿色（如更新负载均衡器或 DNS）-> 保留蓝色环境作为回滚备用。优点：切换瞬间完成（秒级），回滚极快（切回蓝色即可），新环境可做完整预验证。缺点：成本高（维护双倍资源），绿色环境长时间闲置浪费资源，数据库架构变更时难以切换（需要向前向后兼容）。\n\n扩展延伸：3）选择建议——需要充分验证新版本且资源充足 -> 蓝绿部署。需要逐步验证、降低影响面、频繁发布 -> 金丝雀部署。4）混合策略——蓝绿验证 + 金丝雀放量：蓝色环境切换到绿色后，先让少量用户流量走绿色环境，逐步放量到 100%。5）注意要点——两种策略都要求数据库变更向后兼容。金丝雀要看关键业务指标而非仅技术指标。蓝绿部署中数据库回滚是最大的挑战。","hints":["蓝绿部署中数据库结构变更不能回滚怎么办——向前向后兼容是必须的设计原则","金丝雀部署中如何设计流量路由规则才不影响用户体验"],"tags":["金丝雀部署","蓝绿部署","发布策略","DevOps"],"id":1807},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Terraform 状态管理策略与远程后端配置","content":"Terraform 的状态（State）文件是什么？为什么需要状态管理？常见的远程后端（Remote Backend）有哪些？如何避免状态文件冲突和实现团队协作？","answer":"答案：Terraform 状态文件（terraform.tfstate）记录了当前基础设施的所有资源及其属性映射，是 Terraform 判断基础设施期望状态与实际状态差异的依据。远程后端将状态文件存储在共享位置（如 S3/GCS/Azure Storage/Consul），通过状态锁（State Locking）防止多人同时执行 terraform apply 导致冲突。\n\n解析：1）状态文件的作用——资源映射：将配置中的 resource 块映射到云平台上的真实资源 ID。性能优化：terraform plan 不需要调用 API 列举所有资源，直接从状态文件读取。依赖关系：通过状态文件中的资源属性传递引用（如 ${aws_instance.web.id}）。\n\n2）远程后端配置——S3 后端：terraform { backend \"s3\" { bucket = \"my-tf-state\" key = \"prod/network/terraform.tfstate\" region = \"us-east-1\" dynamodb_table = \"tf-lock\" } }。DynamoDB 表用于状态锁。GCS 后端：类似 S3，使用 object versioning 保存状态历史。Terraform Cloud/Enterprise 后端：提供内置状态管理、锁、策略即代码（Sentinel）。\n\n扩展延伸：3）状态隔离策略——工作区（Workspace）：同一配置多环境（dev/staging/prod）。每个 Workspace 独立的状态文件。文件结构：按环境/项目分目录，每个目录独立 state。4）State Locking——远程后端通过 DynamoDB/GCS 对象租约/Consul Session 实现。状态锁失败时 terraform apply 会报错退出，不会破坏状态文件。5）敏感信息——状态文件中可能包含明文密码或密钥。使用 S3 加密（SSE）和访问控制保护。terraform state 命令用于操作状态文件（mv/rm/pull/push）。6）最佳实践——永远不要手动编辑状态文件。开启 state versioning（S3 对象版本控制）以便回溯。定期 terraform plan 检查配置漂移。","hints":["为什么 Terraform 的状态文件不能放在本地 Git 仓库中管理","DynamoDB 在 S3 后端的 State Locking 中扮演什么角色"],"tags":["Terraform","状态管理","IaC","状态锁"],"id":1808},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Docker 多阶段构建优化策略","content":"什么是 Docker 多阶段构建（Multi-Stage Build）？它解决了什么问题？有哪些最佳实践可以进一步优化 Docker 镜像大小和构建速度？","answer":"答案：多阶段构建是 Docker 17.05+ 引入的特性，允许在一个 Dockerfile 中使用多个 FROM 语句，每个 FROM 是一个独立的构建阶段。前一阶段的产物可以通过 COPY --from 复制到后一阶段。核心价值在于：编译环境和运行环境分离——编译阶段的工具链（编译器、构建工具）不进入最终镜像，大幅缩小镜像体积。\n\n解析：1）基本用法——Dockerfile 中两个 FROM：编译阶段（使用 Maven/Gradle/Go build 等编译工具）和运行阶段（使用轻量基础镜像如 alpine、distroless）。只有运行阶段的镜像被保存和推送。示例：\n第一阶段 FROM maven:3.8 AS build，编译出 JAR 文件。\n第二阶段 FROM eclipse-temurin:17-jre-alpine，仅包含 JRE 和 COPY --from=build 复制的 JAR 文件。\n\n2）进阶优化——依赖层分离：先 COPY 依赖描述文件（pom.xml/go.mod/requirements.txt）单独构建依赖层（利用 Docker 层缓存避免每次重新下载依赖），再 COPY 源代码。基础镜像选择：alpine（约 5MB）vs slim（约 40MB）vs distroless（约 20MB）。distroless 最安全（没有 shell 和包管理器）但调试困难。\n\n扩展延伸：3）构建缓存——docker build 利用缓存机制：如果某层的构建上下文没有变化，直接复用缓存层。层排列原则：变化最少的指令放在 Dockerfile 最前面（如安装系统包），变化最多的放在最后面（COPY 源代码）。4）Herd（Parallel Build）——构建多平台镜像时使用 docker buildx 并行构建（AMD64 + ARM64）。5）镜像安全——多阶段构建的第二个重要好处：运行镜像不包含构建工具和源代码，攻击面大幅减少。6）调试——为调试镜像添加 bash/curl（使用 debug 标签或单独的 debug 阶段，生产部署时用 minimal 阶段）。","hints":["Docker 层缓存机制如何与多阶段构建配合优化构建速度","为什么 distroless 镜像比 alpine 更安全但调试更困难"],"tags":["Docker","多阶段构建","镜像优化","Dockerfile"],"id":1809},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Prometheus 记录规则与告警规则的配置与调试","content":"Prometheus 的记录规则（Recording Rules）和告警规则（Alerting Rules）有什么区别？如何配置和调试？预先计算（Recording Rules）在什么场景下能显著提升查询性能？","answer":"答案：记录规则（Recording Rules）用于预先计算复杂或频繁执行的 PromQL 表达式，结果作为新的时间序列存储在 Prometheus 中，后续查询直接使用预先计算好的结果。告警规则（Alerting Rules）定义了触发告警的条件表达式，满足条件时 Prometheus 将告警发送到 Alertmanager。记录规则提升查询性能，告警规则实现监控告警。\n\n解析：1）记录规则——配置方式：在 rules.yml 中的 groups 下定义，包含 name、record（新指标名）、expr（PromQL 表达式）、labels（可选附加标签）。示例：groups:\n  - name: node_rules\n    interval: 30s\n    rules:\n      - record: job:node_memory_usage:ratio\n        expr: (1 - (node_memory_MemAvailable_bytes / node_memory_MemTotal_bytes))\n适用场景：复杂聚合（多级聚合如机房级 -> 集群级 -> 业务级）、仪表盘共用的 PromQL（团队标准化）、高并发仪表盘（减少 Prometheus 计算压力）。\n\n2）告警规则——配置方式：包含 name、alert（告警名称）、expr（条件表达式）、for（持续时间，防止抖动）、labels（附加标签）、annotations（告警内容）。示例：\n      - alert: NodeMemoryUsageHigh\n        expr: job:node_memory_usage:ratio > 0.9\n        for: 5m\n        annotations:\n          summary: \"Node {{ $labels.instance }} memory usage > 90%\"\n\n扩展延伸：3）告警生命周期——Pending（`for` 持续期内条件满足但未到阈值）-> Firing（条件持续满足超过 `for` 阈值）-> Resolved（条件不再满足）。Alertmanager 处理：分组（grouping）、抑制（inhibition）、静默（silence）。4）调试技巧——直接在 Prometheus UI 的 Graph 页面测试 PromQL 表达式。`for: 5m` 防止网络抖动误告警。5）最佳实践——记录规则命名规范：<level>:<metric_name>:<aggregation>（全局规范如 job:node_memory_usage:ratio）。告警规则配够 annotations（summary/description/runbook_url），便于运维人员响应。避免过多记录规则（每条记录规则消耗存储），只预先计算确实频繁使用的聚合查询。","hints":["记录规则和仪表盘中的 PromQL 直接计算相比有什么存储开销的权衡","告警规则的 for 参数为什么能减少告警疲劳"],"tags":["Prometheus","记录规则","告警规则","PromQL"],"id":1810},{"category":"devops","difficulty":"medium","type":"short_answer","title":"K8s ResourceQuota vs LimitRange","content":"解释 Kubernetes ResourceQuota 和 LimitRange 的区别。它们各自管控什么维度？配合使用时如何工作？Namespace 下设置了 ResourceQuota 后 Pod 会有什么约束？","answer":"ResourceQuota 和 LimitRange 的对比：\\n\\nResourceQuota（资源配额）：\\n- 作用域：Namespace 级别。\\n- 功能：限制整个 Namespace 内所有 Pod/Container 的资源总和上限。\\n- 可限制：CPU、内存总和，PVC 数量，Service/Pod/Secret 等对象计数。\\n- 副作用：一旦 Namespace 设置了 ResourceQuota，该 Namespace 下的 Pod 必须显式声明资源 requests 和 limits。\\n- 示例：`kubectl create quota my-quota --hard=cpu=4,memory=8Gi,pods=10`。\\n\\nLimitRange（限制范围）：\\n- 作用域：Namespace 级别，作用于单个 Container/Pod。\\n- 功能：\\n  1. 默认值：为未设置 requests/limits 的 Container 设置默认值。\\n  2. 约束：限制单个 Container 的资源最小/最大值。\\n  3. 比例约束：限制 requests 与 limits 的最大比例。\\n- 示例：`kubectl create limitrange my-limits --max=cpu=2,memory=1Gi --default=cpu=500m,memory=256Mi`。\\n\\n配合工作方式：\\n- ResourceQuota 设置 Namespace 资源预算上限。\\n- LimitRange 确保单个 Pod 不超限同时也有默认值。\\n- 没有 LimitRange 时，一个 Pod 可能占用整个 Quota。\\n- 没有 ResourceQuota 时，LimitRange 只能约束单个容器但不能阻止总量失控。\\n\\n超限行为：\\n- 创建 Pod 时如果超过 ResourceQuota 剩余额度，请求被拒绝（HTTP 403 Forbidden）。\\n- 更新时不检查（K8s 的设计决定）。","hints":["设置了 ResourceQuota 后，不指定 resource requests 的 Pod 能创建吗","LimitRange 的 default 字段在什么情况下会被使用"],"tags":["Kubernetes","ResourceQuota","LimitRange"],"id":1811},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Docker 镜像层缓存","content":"解释 Docker 镜像的分层缓存机制。Dockerfile 中指令顺序如何影响缓存命中率？什么会导致缓存失效？如何使用 BuildKit 和多阶段构建优化缓存？","answer":"Docker 镜像分层缓存：\\n\\n分层机制：\\n- 每个 RUN、COPY、ADD 指令产生一个新层。\\n- 构建时，Docker 对每一层计算校验和，如果层的内容未变则复用缓存。\\n- 一旦某一层的缓存失效（内容变化），该层及其后所有层必须重新构建。\\n\\n缓存失效条件：\\n- RUN：命令字符串变化或相关文件变化（取决于上下文）。\\n- COPY/ADD：源文件内容变化（基于文件校验和）。\\n- 其他指令：指令参数变化。\\n\\n最佳实践（指令顺序从最稳定到最易变）：\\n1. 系统依赖：`RUN apt-get update && apt-get install -y …`\\n2. 语言运行时：`RUN curl -sL https:// …`\\n3. 依赖声明文件：`COPY package.json package-lock.json ./` → `RUN npm install`\\n4. 应用代码：`COPY . .`（变化最频繁，放在最后）\\n\\n多阶段构建：\\n- 第一阶段（Builder）：安装编译工具，编译代码。\\n- 第二阶段（Runtime）：只复制编译产物到精简基础镜像。\\n- 减少了最终镜像大小和安全面。\\n\\nBuildKit（DOCKER_BUILDKIT=1）：\\n- 并行构建独立的构建阶段。\\n- 跳过未使用的阶段。\\n- 更好的缓存失效追踪（基于内容寻址而非指令级比较）。\\n- `--cache-from` 支持远程缓存（CI/CD 中特别有用）。\\n- 支持保密构建（Secret mount，不保留在镜像中）。\\n\\n其他优化：\\n- 合理使用 .dockerignore 避免不必要的上下文。\\n- COPY --from=… 仅复制需要的文件到最终镜像。","hints":["Dockerfile 中哪些指令应该放在最前面以减少缓存失效","BuildKit 的 --cache-from 在 CI/CD 中解决什么问题"],"tags":["Docker","镜像缓存","Dockerfile","CI/CD"],"id":1812},{"category":"devops","difficulty":"hard","type":"short_answer","title":"Argo Rollouts 渐进式交付","content":"解释 Argo Rollouts 的渐进式交付策略。Blue-Green 和 Canary 两种部署模式的工作原理是什么？如何通过指标分析（Analysis）自动决定 Promote 还是 Rollback？","answer":"Argo Rollouts 是 Kubernetes 的渐进式交付控制器：\\n\\nBlue-Green 部署：\\n1. 新版本创建 Green 副本集（ReplicaSet）与现有 Blue 共存。\\n2. 通过 Service 切换流量（Preview Service 可先测试 Green）。\\n3. 确认后更新主 Service 指向 Green。\\n4. 可配置自动 Promotio n/Rollback。\\n\\nCanary 部署：\\n1. 按步进策略逐步切换流量（如 10% → 25% → 50% → 100%）。\\n2. 每一步可设置暂停（Pause）等待自动分析或人工审批。\\n3. 在每一步执行 metric 分析。\\n\\n指标分析（Analysis）：\\n- AnalysisTemplate：定义分析规则（PromQL、Datadog 查询、Web 请求等）。\\n- AnalysisRun：模板的实例化执行。\\n- 分析结果：Success（继续灰度）、Failure（回滚）、Inconclusive（暂停等待人工）。\\n- 可设置失败阈值和取样周期。\\n\\n服务网格集成：\\n- Istio VirtualService + DestinationRule：基于权重路由。\\n- SMI（Service Mesh Interface）：标准化的流量拆分 API。\\n- NGINX Ingress：通过 annotation/配置权重。\\n\\n优势：\\n- 自动回滚防止有问题的版本影响所有用户。\\n- 平滑的流量切换速度控制。\\n- 丰富的指标集成（Prometheus、Datadog、New Relic、Web）。\\n- 可视化的 Dashboard 实时展示部署进度。\\n\\n与 K8s Deployment 的区别：\\n- K8s Deployment 只支持滚动更新（Rolling Update）。\\n- Argo Rollouts 提供 Blue-Green 和 Canary 两种高级策略。\\n- Argo Rollouts 不替换 Deployment——Rollout 是一个独立的 CRD 资源。","hints":["Argo Rollouts 如何判断是继续放量还是回滚","Canary 部署中 step weight 和分析流程如何配合"],"tags":["Kubernetes","Argo Rollouts","渐进式交付","CI/CD"],"id":1813},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Terraform 模块化","content":"解释 Terraform 模块化设计的最佳实践。如何设计模块结构（输入变量、输出值、本地变量）？如何实现模块版本控制和远程状态共享？如何组合模块构建基础设施？","answer":"Terraform 模块化实践：\\n\\n模块结构：\\n```\\nmodules/\\n  vpc/\\n    main.tf         # 核心资源定义\\n    variables.tf     # 输入变量（类型、描述、校验、敏感标记）\\n    outputs.tf       # 输出值（资源 ID、ARN、DNS 等）\\n    versions.tf      # Terraform 和 Provider 版本约束\\n    README.md        # 模块文档\\n```\\n\\n输入变量最佳实践：\\n- 定义 type、description、nullable、sensitive。\\n- validation block 做输入校验。\\n- 使用 optional() 定义可选字段。\\n\\n输出值：\\n- 暴露必要的下游依赖信息（vpc_id、subnet_ids、security_group_id 等）。\\n- 使用 description 说明输出值的含义。\\n\\n模块组合（Composition）：\\n- 根模块（Root Module）调用多个子模块。\\n- 数据传递：子模块的输出作为另一个子模块的输入。\\n- for_each/count 实现多实例。\\n- 隐式依赖优于 explicit depends_on。\\n\\n版本管理：\\n- Git Tag 版本号：source = 「git::ssh://git@github.com/org/terraform-module-vpc.git?ref=v1.2.0」\\n- Terraform Registry 私有模块。\\n- 遵循 SemVer 语义化版本。\\n\\n远程状态：\\n- 后端：S3 + DynamoDB（状态锁定）/ GCS + Bigtable / Azure Storage。\\n- Workspace 分离环境（dev/staging/prod）。\\n- 状态文件通过 backend 配置统一管理。\\n\\n最佳实践清单：\\n- 单一职责（一个模块只做一件事）。\\n- 避免硬编码——全部通过变量传入。\\n- 使用 locals 块推导重复的值。\\n- 使用 terratest 或 tfsec 做测试和安全扫描。","hints":["模块间如何传递依赖关系","如何对不同的环境（dev/staging/prod）使用同一套模块"],"tags":["Terraform","IaC","模块化","基础设施"],"id":1814},{"category":"devops","difficulty":"medium","type":"short_answer","title":"日志收集 Loki","content":"解释 Grafana Loki 的日志聚合架构。Loki 的日志索引策略与 ELK（Elasticsearch）有何本质区别？主要组件（Distributor、Ingester、Querier、Query Frontend）的职责是什么？LogQL 的定位是什么？","answer":"Grafana Loki 架构：\\n\\n设计哲学：\\n- 受 Prometheus 启发，只索引日志元数据（Labels），不索引日志内容。\\n- 日志内容压缩后存储在对象存储中（S3/GCS/MinIO）。\\n- 这是一种「便宜但足够好」的日志方案，区别于 ES 的全文索引。\\n\\n核心组件：\\n1. Distributor：接收日志流 → 校验 → 按一致性哈希分发到 Ingester。\\n2. Ingester：将日志在内存中批量压缩 → 定期 Flush 到对象存储。\\n   - 近期日志在内存中可直接查询，历史日志从对象存储读取。\\n3. Querier：接收查询 → 根据标签 + 时间范围从 Ingester 和对象存储中获取日志。\\n4. Query Frontend（可选）：查询拆分、缓存、并行执行。\\n\\n与 ELK 对比：\\n| 维度 | Loki | Elasticsearch |\\n|------|------|---------------|\\n| 索引对象 | 标签（Labels） | 日志全文 |\\n| 存储 | 对象存储（廉价） | 本地磁盘 + 副本 |\\n| 写入性能 | 高（无索引构建开销） | 低（全文索引成本） |\\n| 全文搜索 | 慢（扫描） | 快（倒排索引） |\\n| 运维成本 | 低 | 高 |\\n| K8s 集成 | 原生 | 需额外配置 |\\n\\nLogQL：\\n- 类似 PromQL 的日志查询语言。\\n- 基本：`{app=「nginx」} |= 「error」`。\\n- 聚合：`rate({app=「nginx」}[5m])`。\\n- 管道：`| json` 或 `| logfmt` 解析结构化日志。\\n\\n最佳实践：\\n- 选择合适的标签基数（太高导致索引膨胀，太低导致查询效率低）。\\n- 常用标签：namespace、pod、container、app。\\n- 使用 Promtail 或 Alloy 作为日志采集 Agent。","hints":["Loki 和 Elasticsearch 在索引策略上的根本区别是什么","Loki 为什么比 ELK 运维成本低——存储层面如何体现"],"tags":["Loki","日志收集","Grafana","可观测性"],"id":1815},{"category":"devops","difficulty":"hard","type":"short_answer","title":"Linux Namespace 与 Cgroups 容器隔离原理","content":"Docker 容器利用 Linux 内核的 Namespace 和 Cgroups 实现资源隔离与限制。请说明 Namespace 提供了哪几种隔离维度？Cgroups 可以限制哪些资源？它们各自解决了什么安全问题？","answer":"答案：Namespace 提供 8 种隔离维度——PID（进程号）、Network（网络栈）、Mount（文件系统挂载点）、UTS（主机名和域名）、IPC（进程间通信）、User（用户和 UID）、Cgroup（cgroup 根目录）、Time（系统时间，Linux 5.6+）。Cgroups 限制 CPU、内存、磁盘 I/O、网络带宽和 PID 数量。Namespace 解决「进程只能看到隔离后的视图」的问题，Cgroups 解决「进程不能使用超出限制的资源」的问题。\n\n解析：Namespace 的工作原理——每个进程关联一组 Namespace，系统调用 clone() 或 unshare() 时指定 CLONE_NEWNS/NEWPID/NEWNET 等标志创建新 Namespace。PID Namespace：进程在容器内看到的 PID 从 1 开始，但宿主机上映射为普通 PID。Mount Namespace：容器有独立的文件系统挂载点，容器内 /proc 只显示自己的进程。Network Namespace：容器有独立的网络栈（lo、veth pair），容器间通过 veth bridge 通信。Cgroups（Control Groups）的 v1/v2 版本：通过/sys/fs/cgroup/ 下的子系统控制资源。cpu.shares 控制 CPU 权重，memory.limit_in_bytes 限制内存上限，blkio.throttle 控制磁盘读写速率。\n\n扩展延伸：安全性考量：1）Namespace 隔离不是安全边界——容器内仍可通过/proc、sysfs 等内核接口逃逸（如 CVE-2022-0492 cgroup 逃逸）。2）Cgroups 无法阻止资源竞争的侧信道攻击（如 L1TF 推测执行）。3）生产环境建议：不使用 privileged 容器、使用 Seccomp 限制系统调用、使用 AppArmor/SELinux 做强制访问控制、使用 User Namespace 将容器内 root 映射为宿主机非特权用户。注意：Namespace 和 Cgroups 只提供「资源隔离」功能，不提供严格安全隔离。需要更强隔离时考虑 Kata Containers（轻量虚拟机）或 gVisor（用户态内核）。","hints":["Namespace 隔离和安全隔离的区别——为什么说 Namespace 不是安全边界","User Namespace 如何将容器内 root 映射为宿主机普通用户"],"tags":["Docker","Namespace","Cgroups","容器","安全"],"id":1816},{"category":"devops","difficulty":"medium","type":"choice","title":"CI/CD 流水线方案对比","content":"关于 Jenkins Pipeline、GitLab CI/CD 和 GitHub Actions 三种主流 CI/CD 方案的对比，以下说法正确的是？","options":["A) GitHub Actions 只能用于 GitHub 托管的仓库，不支持自托管 Runner","B) GitLab CI/CD 的 Runner 只能由 GitLab 官方托管，不支持私有化部署","C) Jenkins Pipeline 通过 Jenkinsfile 定义流水线，支持复杂的有状态流水线和人工审批节点，但需要自行维护 Jenkins 服务","D) GitLab CI/CD 使用 YAML 描述流水线，但完全不支持并行 Job 执行"],"answer":"答案：C) Jenkins Pipeline 通过 Jenkinsfile 定义流水线，支持复杂的有状态流水线和人工审批节点，但需要自行维护 Jenkins 服务\n\n解析：Jenkins Pipeline 使用 Groovy 语法定义声明式或脚本式流水线——支持条件分支、循环、异常处理、人工审批（input 指令）、跨 Job 共享工作空间等复杂场景。对复杂的部署流水线（如多环境审批发布、金丝雀+全量、数据库迁移等）支持最好。缺点是需要自行维护 Jenkins 服务（Master + Agent 集群），CI 配置用 Groovy DSL，学习曲线较陡。\n\n扩展延伸：其他选项的问题：A) GitHub Actions 既支持 GitHub 托管的 Runner（免费额度），也支持自托管 Runner（self-hosted runner）在自己的服务器上执行 Job。B) GitLab CI/CD 的 Runner 可以私有化部署（通过 gitlab-runner 注册到 GitLab 实例），也是部署最常见的方案。C) GitLab CI/CD 支持并行 Job（parallel 关键字）和 DAG（needs 关键字实现有向无环图编排）。选型建议：代码在 GitHub 上→GitHub Actions（与 GitHub 深度集成）；团队使用 GitLab Self-Managed →GitLab CI/CD（开箱即用）；有复杂的发布审批和状态管理需求→Jenkins（最成熟灵活）；简单云原生场景→直接使用 ArgoCD + K8s（GitOps 模式）。","hints":["Jenkins Pipeline 的 Groovy DSL 相比 YAML 的优劣","三种 CI/CD 方案在自托管 Runner 能力上的差异"],"tags":["CI/CD","Jenkins","GitLab CI","GitHub Actions","DevOps"],"id":1817},{"category":"devops","difficulty":"hard","type":"short_answer","title":"蓝绿部署、滚动更新与金丝雀发布的对比","content":"请对比蓝绿部署（Blue-Green Deployment）、滚动更新（Rolling Update）和金丝雀发布（Canary Release）三种发布策略的实现原理、优缺点以及各自的适用场景。","answer":"答案：蓝绿部署维护两套完全独立的环境（蓝/绿），通过切换流量入口瞬时完成版本切换。滚动更新分批替换旧版本 Pod，逐步用新版本取代旧版本，始终保持一定数量实例可用。金丝雀发布先让少量用户使用新版本，验证稳定后再逐步扩大范围到全量。\n\n解析：1）蓝绿部署——维护两套全量环境（蓝=当前版本，绿=新版本），发布时部署绿环境，验证通过后瞬间切换负载均衡指向绿环境。优点：切换速度快（秒级）、回滚简单（切回蓝环境即可）。缺点：资源需求翻倍（两套全量环境同时运行）、数据库兼容性需同时支持新旧版本。适用：对业务中断敏感、资源充足的场景。2）滚动更新（K8s Deployment 默认策略）——逐步替换 Pod：先起一个新 Pod，等就绪后停一个旧 Pod，重复直到全部替换。K8s 通过 maxSurge 和 maxUnavailable 控制更新速率。优点：资源需求不变、可设置自动回滚。缺点：新旧版本短暂共存，需处理兼容性问题。适用：大多数无状态服务。3）金丝雀发布——通常结合服务网格（Istio）或网关（Nginx/Gateway）做流量权重分配：初始 1% 流量到新版本→5%→25%→50%→100%。优点：风险最小（影响面可控）、可结合监控和告警做自动化判断。缺点：实现复杂、流量分发和监控需要基础设施支持。适用：核心业务、影响面大的关键变更。\n\n扩展延伸：结合实践——大多数公司对核心服务使用「金丝雀+滚动更新」的组合：金丝雀阶段验证功能和性能，全量切换时用滚动更新秒级过渡。数据库变更的发布策略最为棘手——建议遵循「前向兼容、后向兼容」原则，即先加后删。CRUD 操作的发布步骤：1）新版本代码兼容旧表结构。2）执行数据库变更（加列）。3）旧版本代码做好兼容。4）发布新版本代码使用新列。5）清理旧代码路径。6）删除不再需要的旧列。","hints":["蓝绿部署中数据库兼容性问题如何解决","金丝雀发布如何结合 Prometheus 指标自动判断是否继续放量"],"tags":["部署","蓝绿部署","金丝雀发布","滚动更新","发布策略"],"id":1818},{"category":"devops","difficulty":"medium","type":"short_answer","title":"CNI 容器网络模型与实现方案","content":"容器网络的 CNI（Container Network Interface）模型是什么？Flannel 和 Calico 两种常见的 CNI 实现方案在数据平面和控制平面上有什么根本区别？","answer":"答案：CNI 是容器网络的标准接口规范，定义了两个核心操作——ADD（将容器加入网络）和 DEL（将容器移出网络），由 Container Runtime（Kubelet）调用 CNI 插件实现网络配置。Flannel 使用 Overlay 网络（VXLAN 封装），Calico 使用纯三层路由（BGP+Bird，无 Overlay 封装）实现 Pod 间通信。\n\n解析：Flannel 的工作原理：1）每个节点分配一个独立的子网（如 10.1.1.0/24）。2）节点上的 flanneld 通过 etcd/K8s API 协调子网分配。3）跨节点通信时，原始数据包被 VXLAN/UDP 封装后通过宿主机网络传输（Overhead 约 20-50 字节，带来约 5-15% 性能损耗）。Flannel 的优点是简单、与 K8s 集成好、无需额外基础设施。Calico 的工作原理：1）每个节点充当纯三层路由器（通过 BGP 协议交换路由）。2）Pod 到 Pod 的通信直接通过宿主机内核路由表转发（不需要 Overlay 封装），性能接近宿主机网络。3）通过 iptables/IPVS 实现 NetworkPolicy 的网络策略控制。\n\n扩展延伸：性能对比：Calico（无 Overlay）≈ 宿主机原生网络 98% 吞吐，Flannel（VXLAN）≈ 宿主机原生网络 85-90% 吞吐。选型建议：对性能敏感的生产集群→Calico（推荐 BGP 模式或 IPIP 模式）；中小集群或网络基础设置不支持 BGP→Flannel（简单可靠）；需要 NetworkPolicy 策略控制→Calico（Flannel 需要额外集成 Canal/Kube-router）。Calico 的两种数据路径：eBPF 模式（性能最优，内核 5.3+）和标准 iptables 模式。注意：Calico 需要 BGP 基础设施支持（在公有云中可能需要配合其他网络方案，或使用 VXLAN+Calico 混合模式）。","hints":["Calico 的 BGP 模式为什么比 Flannel 的 VXLAN 性能更好","Overlay 网络（VXLAN）和纯三层路由各自的性能损耗因素"],"tags":["CNI","Flannel","Calico","容器网络","Kubernetes"],"id":1819},{"category":"devops","difficulty":"hard","type":"choice","title":"IaC 工具选型与不可变基础设施","content":"关于基础设施即代码（IaC）和不可变基础设施（Immutable Infrastructure）的实践，以下说法正确的是？","options":["A) 不可变基础设施意味着服务器上的配置永远不可更改，即使需要打安全补丁也必须重新部署整个镜像","B) Terraform 只支持声明式配置管理，不支持 Shell 脚本等过程式操作","C) 不可变基础设施与可变基础设施的核心区别在于：前者通过重新创建实例来应用变更，后者通过 SSH 登录已运行实例修改配置","D) Ansible 和 Terraform 都只能管理云资源，不能管理内部数据中心"],"answer":"答案：C) 不可变基础设施与可变基础设施的核心区别在于：前者通过重新创建实例来应用变更，后者通过 SSH 登录已运行实例修改配置\n\n解析：不可变基础设施的核心原则：任何时候都不修改已运行的服务器。需要任何变更（更新软件、修改配置、打补丁）时，从基线镜像创建新实例，验证后替换旧的。这消除了配置漂移（Configuration Drift）问题，保证了环境的一致性和可重现性。相比之下，可变基础设施中运维人员通过 SSH 登录服务器执行命令修改配置，随着时间的推移，服务器的实际状态与代码定义的状态越来越不一致（配置漂移），且难以自动化回滚。\n\n扩展延伸：其他选项的分析：A）不可变基础设施并不意味着完全不打安全补丁——补丁通过更新基础镜像版本并重新部署实例来应用，而非在运行中的实例上打补丁。这是一个「重新创建还是原地修改」的哲学差异。B）Terraform 支持 provisioner（remote-exec/local-exec）执行脚本和 Shell 命令，但官方不推荐将 provisioner 用作核心配置手段——违背了声明式原则。D）Ansible 和 Terraform 都支持管理物理机、虚拟机和私有云（OpenStack/vSphere）——不限于公有云。工具选型：Terraform——基础设施资源编排（声明式创建/管理云资源）；Ansible/Puppet——配置管理（在现有机器上安装软件/管理配置）；Packer——创建不可变镜像（从 ISO 或基础镜像自动化构建机器镜像）。","hints":["不可变基础设施如何解决配置漂移（Configuration Drift）问题","Terraform 的 Provisioner 为什么官方不推荐作为核心配置手段"],"tags":["IaC","Terraform","Ansible","不可变基础设施","DevOps"],"id":1820},{"category":"devops","difficulty":"hard","type":"short_answer","title":"Kubernetes CNI 网络模型与 Pod 通信","content":"Kubernetes 的 CNI（Container Network Interface）网络模型是如何定义的？Pod 内容器如何共享网络命名空间（pause 容器的作用）？跨节点 Pod 通信的几种主流方案（overlay、路由、eBPF）各自的实现原理和性能差异是什么？","answer":"答案：CNI 定义容器的网络配置标准接口，K8s 通过 CNI 插件管理 Pod 网络。Pod 内通过 pause 容器持有网络命名空间。跨节点通信使用 overlay（VXLAN）、路由（Calico BGP）或 eBPF（Cilium）三种方案。\n\n解析：Pod 内多容器共享网络：每个 Pod 创建时先启动 infra/pause 容器，它持有 network namespace + PID namespace。其他业务容器通过 join 共享该 netns（localhost 通信，共享 IP 和端口空间）。CNI 插件工作流程：kubelet 在 Pod 调度到节点后调用 CNI 插件的 ADD 命令，插件负责分配 IP、配置网络接口、创建路由规则。\n\n扩展延伸：三种跨节点方案对比：1）Overlay（Flannel VXLAN）——在宿主机网络之上建立 VTEP 隧道，数据包封装在内核中完成。性能损耗约 10-20%，配置简单、不依赖底层网络。2）路由方案（Calico BGP）——每个节点作为 BGP Speaker，向集群网络通告 Pod CIDR 路由。数据包直接由三层路由转发，无封装开销，但需要底层网络设备支持 BGP，有 Pod 数量限制（路由表条目数）。3）eBPF 方案（Cilium）——通过 BPF 程序在内核级别直接处理网络数据包，替代 iptables 和 kube-proxy，延迟最低（微秒级），支持 L7 策略。性能排名：eBPF > BGP 路由 > VXLAN。","hints":["Pause 容器为什么叫 pause——它的唯一作用是保持 network namespace 存活（进程永久 sleep）","VXLAN 封装的数据包外部 UPD 头和内部 MAC 头各有多少字节——50 字节开销影响 MTU"],"tags":["K8s","CNI","Pod网络","VXLAN","Calico","Cilium"],"id":1821},{"category":"devops","difficulty":"medium","type":"choice","title":"Kubernetes Pod QoS 模型","content":"K8s Pod 配置如下：containers[0].resources.requests = {cpu: 0.5, memory: 256Mi}，limits = {cpu: 1, memory: 512Mi}。该 Pod 的 QoS 类别是什么？","options":["A) Guaranteed","B) Burstable","C) BestEffort","D) Unknown"],"answer":"答案：B)。解析：K8s 三种 QoS 类别判定：1）Guaranteed——所有容器都设置了 limits，且所有资源类型的 limits == requests（CPU 和 Memory 都必须分别相等）。本 Pod CPU limits(1) != requests(0.5)，Memory limits(512Mi) != requests(256Mi)，不满足。2）Burstable——至少一个容器有 requests 或 limits 但不满足 Guaranteed。3）BestEffort——没有任何 requests 和 limits。QoS 决定了节点资源紧张（OOM 或内存压力）时哪些 Pod 优先被驱逐：BestEffort > Burstable > Guaranteed。同一 QoS 类别内部，根据 OOM Score 按实际使用超出 requests 比例排序（超得越多越优先被杀死）。注意：QoS 仅基于资源 requests/limits 配置判断，与实际资源使用无关。","hints":["Burstable Pod 内如果某个容器不设置 limits 只设置 requests，会有什么影响——CPU 可以 Burst 到节点上限","Pod 的 QoS 如何影响 OOM Killer 的优先级——通过 oom_score_adj 参数"],"tags":["K8s","QoS","资源限制","OOM","驱逐"],"id":1822},{"category":"devops","difficulty":"hard","type":"short_answer","title":"GitOps 工作流与 ArgoCD 原理","content":"GitOps 的核心原则是什么？ArgoCD 如何实现声明式环境同步和自动修复（Self-healing）？与传统 CI/CD 推模式（Push-based）相比，GitOps 拉模式（Pull-based）在安全性和一致性方面有什么架构优势？","answer":"答案：GitOps 以 Git 仓库作为唯一事实来源（Single Source of Truth），集群状态持续与 Git 同步。ArgoCD 监控 Git 仓库和集群状态的差异，自动或手动同步使集群匹配 Git 声明。\n\n解析：ArgoCD 工作流程：1）Application Controller 持续对比 Git 仓库中声明的 manifest（Helm/Kustomize/YAML）与集群中实际运行的资源。2）检测到差异时，根据 syncPolicy（manual/auto）决定是否同步。auto-sync 模式自动应用 Git 仓库中的最新配置；自愈（Self-healing）模式下，即使有人手动 kubectl edit 修改了集群资源，ArgoCD 也会将其恢复到 Git 仓库声明的状态。3）Git Webhook 触发同步——收到 Git push 事件后，ArgoCD 立即同步（而非默认 3 分钟轮询）。\n\n扩展延伸：GitOps Pull 模式的安全优势：1）CI 流水线只需推送镜像到仓库和更新 Git 仓库中的 manifest（如 kustomize edit set image），不需要 kubectl 权限或集群凭据。2）集群中的 ArgoCD Agent 从 Git 仓库拉取配置——集群凭据不出集群边界。3）回滚只需 git revert 提交，ArgoCD 自动同步回旧版本。4）审计日志天然由 Git 提供——谁在什么时间改了什么是不可篡改的。5）多集群管理：一个 ArgoCD 控制面可以管理多个集群，通过 RBAC 控制每个团队可同步的应用范围。对比传统 Push 模式（Jenkins/GitLab CI 直接 kubectl apply）：每个 CI Job 都需要 Kubeconfig（凭据散落在各处），且没有统一的变更审计和回滚能力。","hints":["ArgoCD 的 sync 策略——manual/auto & prune/self-heal 的组合含义","GitOps 中 CI 和 CD 的分界点在哪里——CI 到更新 Git manifest 为止，CD 是 ArgoCD 从 Git 到集群的同步"],"tags":["GitOps","ArgoCD","CI/CD","K8s","声明式"],"id":1823},{"category":"devops","difficulty":"medium","type":"choice","title":"Docker 镜像分层结构与构建缓存","content":"关于 Docker 镜像的分层结构（UnionFS）和构建缓存，以下描述正确的是？","options":["A) Docker 镜像的每一层都是完整的文件系统快照，层与层之间相互独立且不共享数据","B) COPY 和 RUN 指令在 Dockerfile 中都会创建新的镜像层","C) 修改 Dockerfile 中任何一条指令都会导致所有后续层的缓存失效，无论改动多小","D) CMD 和 ENTRYPOINT 指令也会创建新的镜像层，因为它们定义了容器的执行入口"],"answer":"答案：B)。解析：Docker 镜像由只读层堆叠，每层记录与上一层的差异（增量而非全量）。COPY/RUN/ADD 创建新层，因为这几条指令会改变文件系统。CMD/ENTRYPOINT/ENV/LABEL/EXPOSE 等元数据指令不创建新层——它们只修改 Image Config JSON（非 UnionFS 层）。A) 错，层记录的是增量差异（overlayfs2 的 lowerdir 层），不是完整快照。C) 错，只有底层指令修改导致该层缓存失效时，上层的缓存才失效（顶层修改不影响已缓存的下层指令）。最典型的优化：把变更频率低的放在 Dockerfile 前面（先 COPY package.json 再 RUN npm install 再 COPY 源码），让依赖安装层尽可能命中缓存。D) 错，CMD/ENTRYPOINT 不创建层。","hints":["Docker 镜像层存储在 /var/lib/docker/overlay2/ 下如何组织——lower 和 upper 目录叠加","为什么先 COPY package.json 再 RUN npm install 能提升缓存命中率——依赖文件变更频率远低于源码"],"tags":["Docker","分层","缓存","Dockerfile","UnionFS"],"id":1824},{"category":"devops","difficulty":"hard","type":"short_answer","title":"OpenTelemetry 与可观测性三支柱","content":"可观测性（Observability）的三大支柱是什么？OpenTelemetry 如何统一 Metrics、Logs 和 Traces 的采集和关联？OTLP 协议的设计原理和 Collector 的 Pipeline 架构是怎样的？","answer":"答案：三大支柱：Metrics（指标）、Logs（日志）、Traces（链路）。OpenTelemetry（OTel）提供统一 SDK 和 Collector，通过 OTLP 协议传输数据。Collector 使用 Receivers → Processors → Exporters 管道处理数据。\n\n解析：OTel 核心组件：1）API + SDK——应用代码引入 OTel SDK，通过统一的 API 生成 Traces（Span）、Metrics（Counter/Histogram）、Logs。SDK 自动采集 gRPC/HTTP 调用的链路上下文。2）Context Propagation——通过 W3C Trace Context 标准（traceparent 头：00-traceid-spanid-01）在跨服务调用中传播 Trace ID。3）OTLP 协议——基于 gRPC/HTTP Protobuf 传输，支持批量和 GZip 压缩。\n\n扩展延伸：OTel Collector 核心 Pipeline：1）Receivers——接收数据源（OTLP Receiver、Prometheus Receiver、Jaeger Receiver、K8s Receiver）。2）Processors——处理数据（batch 合并、attributes 增删、sampling 采样、memory_limiter 防止 OOM）。3）Exporters——转发到后端（Prometheus、Jaeger/ Tempo、Loki、DataDog、S3 存储）。Tail Sampling Processor：可以按 Trace 粒度采样——如果某个 Span 包含错误（error span），即使整体采样率是 1%，这个 Trace 的全体 Span 都会被保留。这是传统概率采样做不到的。关联手段——Logs 中可以嵌入 Trace ID 和 Span ID，实现 Log → Trace 的跳转查询。","hints":["W3C Trace Context 的 traceparent 头格式——00-traceid(32hex)-spanid(16hex)-01(traceflag)","Tail Sampling 相比 Head Sampling 的优点——可以基于完整 Trace 信息做采样决策（如保留含错误的 Trace）"],"tags":["可观测性","OpenTelemetry","OTLP","Traces","Collector"],"id":1825},{"category":"devops","difficulty":"medium","type":"choice","title":"Kubernetes Node 压力驱逐顺序","content":"当 Kubernetes 节点因内存不足触发节点压力驱逐（Node Pressure Eviction）时，以下哪种 Pod 会被优先驱逐？","options":["A) 设置了 Guaranteed QoS 的关键业务 Pod","B) Pod Priority 最高且设置了 Guaranteed QoS 的 Pod","C) 未设置 resources requests/limits 的 BestEffort Pod","D) 使用节点 HostNetwork 模式的 Pod"],"answer":"答案：C) 未设置 resources requests/limits 的 BestEffort Pod\n\n解析：Kubelet 在节点资源不足（内存/磁盘/PID 耗尽）时启动节点压力驱逐，驱逐顺序严格按 QoS 等级从低到高：BestEffort（未设置任何 resources）→ Burstable（至少设置了 requests 但未全部等于 limits）→ Guaranteed（requests == limits）。同一 QoS 等级内，按 Pod 使用资源相对于请求的比例从高到低驱逐。PriorityClass 只影响抢占（Preemption）——调度时高优 Pod 抢占低优 Pod，不影响驱逐顺序。HostNetwork 模式不影响驱逐顺序。\n\n扩展延伸：驱逐触发条件：eviction-hard 硬阈值触发时立即驱逐（如 memory.available<100Mi），eviction-soft 软阈值触发后有宽限期（eviction-soft-grace-period）才驱逐。驱逐过程：Kubelet 先尝试回收节点级资源（删除死掉的 Pod、删除不再使用的镜像），不够再驱逐 Pod。驱逐时终止 Pod 并通知 API Server，被驱逐的 Pod 的 status.phase 变为 Failed，reason=Evicted。API Server 重新创建 Pod（由 Deployment/StatefulSet 控制器执行），但可能仍然调度到同一节点（如果节点资源已恢复）。被驱逐的 Pod 建议用 PriorityClass 保证关键服务优先调度。避免关键服务被驱逐：设置合理的 requests/limits（Guaranteed QoS）和高优先级（PriorityClass）。","hints":["QoS 类驱逐顺序：BestEffort -> Burstable -> Guaranteed","eviction-hard 和 eviction-soft 触发时的行为差异"],"tags":["K8s","驱逐","QoS","资源管理"],"id":1826},{"category":"devops","difficulty":"hard","type":"short_answer","title":"容器镜像仓库 Harbor 架构与镜像复制策略","content":"企业级容器镜像仓库 Harbor 的核心架构是怎样的？Harbor 如何实现跨数据中心的镜像复制（Replication）？镜像清理策略如何设计？","answer":"答案：Harbor 是 CNCF 孵化的企业级镜像仓库，核心组件包括：Proxy（Nginx，TLS 终止和请求转发）、Core Service（API/Auth/UI/Token Service，核心业务）、Registry（Docker Distribution，镜像存储，支持 OCI 标准）、Database（PostgreSQL，存储元数据/用户/项目信息）、Job Service（异步任务执行，如复制、GC、扫描）、Trivy/Clair（漏洞扫描器）、Storage（S3/Azure/OSS/NFS/本地文件系统）。\n\n解析：跨数据中心镜像复制：1）Push-based 模式——在源 Harbor 配置目标 Harbor 的地址和凭证，源 Harbor 主动推送镜像到目标。2）Pull-based 模式——在目标 Harbor 配置源 Harbor 地址，目标 Harbor 主动拉取。3）Replication Rule——定义需要复制的镜像过滤条件（仓库/标签/版本），触发方式（手动/定时/事件驱动）。4）复制依赖 Job Service 执行异步任务，支持断点续传和重试。\n\n扩展延伸：镜像清理策略（Garbage Collection，GC）：1）Harbor 2.5+ 支持在线 GC（不需要停机）。2）清理对象：未被任何标签引用的 Blob（不可变镜像层）、已删除的镜像的 Blob。3）自动清理策略：按保留数量（保留最近 N 个标签）、按保留天数（保留最近 N 天内的标签）、按正则过滤（如只保留带 v 前缀的标签）。4）标签不可变（Tag Immutability）——指定仓库中的标签不可覆盖（防止生产环境镜像被误覆盖）。5）安全扫描策略：镜像推送后自动触发漏洞扫描、标记不可信镜像阻止部署（阻断 CI/CD 流水线）。配置建议：定期自动清理（每周）+ 保留最近 30 天的所有镜像标签 + 生产镜像不可变。","hints":["Harbor 跨数据中心复制的两种模式","镜像仓库的 GC 回收的是什么数据"],"tags":["Harbor","镜像仓库","复制","GC"],"id":1827},{"category":"devops","difficulty":"medium","type":"short_answer","title":"Kubernetes ServiceAccount 与权限绑定最佳实践","content":"如何在 Kubernetes 中为每个微服务创建独立的 ServiceAccount 并绑定最小权限？RBAC 的 Role/ClusterRole、RoleBinding/ClusterRoleBinding 如何正确选择？","answer":"答案：Kubernetes 安全性最佳实践要求每个微服务使用独立的 ServiceAccount，通过 RBAC 绑定最小权限，避免使用默认的 default ServiceAccount（该账号通常没有任何资源访问限制）。\n\n解析：1）创建 ServiceAccount：为每个服务创建一个 SA（如 kubectl create sa order-service）。2）选择 Role 还是 ClusterRole：如果服务只需要访问特定 Namespace 的资源（如读取本 Namespace 的 Pod），使用 Role（Namespace 级别）；如果需要跨 Namespace 访问（如查看所有 Namespace 的 Pod），使用 ClusterRole。3）RoleBinding vs ClusterRoleBinding：RoleBinding 将 Role/ClusterRole 绑定到特定 Namespace 的用户/SA/Group；ClusterRoleBinding 授予集群级别权限（不限 Namespace）。推荐组合：用 ClusterRole 定义公共权限集合（如 pod-reader），在各自 Namespace 中用 RoleBinding 引用该 ClusterRole 并绑定到本 Namespace 的 SA。4）最小权限示例：SA order-service 只需要查看本 Namespace 的 Pod 和 Endpoint（服务发现），不需要创建/删除 Pod。\n\n扩展延伸：自动化 RBAC 管理工具：1）kube-rbac-proxy——保护 Prometheus metrics 端点，要求请求带 SA 的 Token。2）OPA/Gatekeeper——强制检查 Pod 是否设置了 automountServiceAccountToken: false 限制不需要访问 API 的服务。3）rbac-manager（ReactiveOps）——按声明式配置自动管理 RBAC 资源。排查 RBAC：当 Pod 中的应用调用 K8s API 返回 403 Forbidden 时，首先检查 Pod 使用的 SA、然后确认 RoleBinding/ClusterRoleBinding 是否创建正确。kubectl auth can-i --list --as=system:serviceaccount:<ns>:<sa> 可测试 SA 的权限。","hints":["为什么不用 default ServiceAccount 比用最小权限的独立 SA 更危险","RoleBinding + ClusterRole 组合如何实现跨 Namespace 资源的最小权限访问"],"tags":["K8s","RBAC","ServiceAccount","安全"],"id":1828},{"category":"devops","difficulty":"hard","type":"short_answer","title":"Kubernetes 网络策略与 Cilium NetworkPolicy 增强","content":"Kubernetes 标准 NetworkPolicy 只能控制 L3/L4 层（IP+Port），如何实现 L7 层（HTTP 方法/路径/gRPC 服务）的网络策略？Cilium 的 NetworkPolicy 做了哪些增强？","answer":"答案：标准 K8s NetworkPolicy 只支持 L3/L4 过滤（基于 IP、Port、协议）。要实现 L7 网络策略（如只允许 GET /api/orders 路径的流量），需要借助支持 L7 策略的 CNI 插件（如 Cilium）或 Service Mesh（如 Istio AuthorizationPolicy）。Cilium 基于 eBPF 提供了标准 NetworkPolicy 的增强，支持 HTTP/gRPC/Kafka/DNS 等协议级别的规则。\n\n解析：Cilium 的 NetworkPolicy 增强：1）HTTP 规则——允许匹配特定 HTTP 路径、方法、Host 头的流量。示例规则允许 GET /api/orders HTTP/1.1 请求进入 Service A，拒绝其他路径或 POST 方法。2）gRPC 规则——按 service/method 匹配，如拒绝 mTLS 未认证的 gRPC 调用访问特定服务。3）Kafka 规则——按 Topic 和 ClientID 过滤 Kafka 请求，实现 topic 级别的 Kafka 访问控制。4）DNS 规则——基于 DNS 域名（FQDN）的总出站流量控制，而非使用 IP CIDR（IP 可能变化）。\n\n扩展延伸：Istio AuthorizationPolicy 也做 L7 策略但架构不同：Istio 通过 Envoy Sidecar 执行策略（需要注入 Sidecar），Cilium 通过 eBPF 在内核层面执行策略（无需 Sidecar，性能更高）。CiliumNetworkPolicy（CRD）是 Cilium 扩展的自定义资源，用法与标准 NetworkPolicy 类似但支持更多字段。生产实践：大部分场景下标准 NetworkPolicy 已足够（限制 namespace 间互相访问、限制特定端口）。只有需要 HTTP 路径级别或 gRPC 方法级别控制时才用 CiliumNetworkPolicy。CiliumNetworkPolicy 可以单独使用也可以与标准 NetworkPolicy 叠加——两者取交集（都允许才算允许）。","hints":["Cilium 如何通过 eBPF 实现 L7 网络策略","CiliumNetworkPolicy 和标准 NetworkPolicy 的叠加规则"],"tags":["K8s","Cilium","NetworkPolicy","L7"],"id":1829},{"category":"devops","difficulty":"medium","type":"choice","title":"Docker 镜像构建缓存层命中规则","content":"Docker 构建镜像时缓存命中规则是什么？以下哪个操作会使得后续层的缓存全部失效？","options":["A) 在 Dockerfile 中改变了 COPY 指令复制的文件内容","B) 在 Dockerfile 中使用 ADD 指令添加一个永不改变的 tar.gz 压缩包","C) 在 Dockerfile 中插入了 ENV 指令设置环境变量 KEY=VALUE","D) 在 RUN apt-get update 之前添加了一条注释"],"answer":"答案：A) 在 Dockerfile 中改变了 COPY 指令复制的文件内容\n\n解析：Docker 构建缓存命中规则基于指令和上下文的完整性检查。对于 COPY/ADD 指令，Docker 计算被复制文件的 checksum（校验和）并比较——如果文件内容发生变化，则该层和所有后续层缓存失效。对于 RUN 指令，缓存命中取决于上一条指令是否命中缓存，以及 RUN 命令的字符串是否改变。ENV 指令如果内容（KEY=VALUE）发生变化，该层缓存失效。注释不影响（注释在构建时被忽略，不会产生层）。\n\n扩展延伸：Dockerfile 的位置影响：经常变化的内容（源码）放 Dockerfile 后面，不常变化的内容（apt 安装、pip 安装依赖）放前面，最大化利用缓存。示例顺序：1）FROM base。2）RUN apt-get update && apt-get install（缓存稳定，除非改 apt 命令）。3）COPY package.json /app/（依赖配置文件，相对稳定）。4）RUN npm install（利用上一层的 package.json 变化缓存）。5）COPY . /app/（源码经常变化，放最后）。如果 COPY . 放前面，每次源码变化后 apt-get install 也重新执行。额外的缓存失效因素：ARG 或 ENV 值变化也会使引用它们的后续层缓存失效。docker build --no-cache 强制跳过所有缓存。docker build --cache-from 指定外部镜像作为缓存源（CI/CD 中加速构建）。","hints":["COPY 指令缓存失效的判定依据（checksum 变化）","Dockerfile 中元素排列顺序对缓存命中率的影响"],"tags":["Docker","构建缓存","Dockerfile"],"id":1830},{"category":"devops","difficulty":"medium","type":"choice","title":"Docker BuildKit 与 buildx 多平台构建","content":"关于 Docker BuildKit 和 buildx 多平台构建，以下说法正确的是？","answer":"答案：A) BuildKit 是下一代 Docker 构建引擎，通过并发构建、LLB 中间表示和缓存导入导出加速镜像构建过程\n\n解析：BuildKit 是 Docker Engine 从 18.09 开始集成的下一代构建引擎（DOCKER_BUILDKIT=1 启用），核心改进：1）并发构建——解析依赖 DAG 后并行执行无依赖的构建步骤。2）LLB（Low-Level Build）中间表示——将 Dockerfile 转换成 LLB 后优化执行计划。3）导入/导出缓存（inline/registry/local 等多种缓存模式）。4）前端支持多种前端（gateway）——不仅限 Dockerfile。buildx 是 BuildKit 的 CLI 封装，核心功能：跨平台构建（--platform linux/amd64,linux/arm64）通过 QEMU 模拟或远程 builder 实例实现。\n\n扩展延伸：buildx bake 支持 HCL/JSON/YAML 格式定义多服务构建配置。构建缓存共享：--cache-from type=registry,ref=image:cache --cache-to type=registry,ref=image:cache,mode=max。多平台镜像不是真正的 multi-arch manifest（manifest list）而是通过 manifest list 引用多个平台的镜像。BuildKit 的 --secret 和 --ssh 参数解决了构建中安全传递证书和 SSH key 的问题。","options":["A) BuildKit 是下一代 Docker 构建引擎，通过并发构建、LLB 中间表示和缓存导入导出加速镜像构建过程","B) buildx 是独立的构建引擎，不依赖 Docker 守护进程","C) BuildKit 不支持多阶段构建","D) buildx 多平台构建必须在同一台机器上使用 QEMU 模拟"],"hints":["BuildKit 的 LLB 是什么","buildx 如何实现跨架构构建"],"tags":["Docker","BuildKit","buildx","镜像构建","CI/CD"],"id":1831},{"category":"devops","difficulty":"hard","type":"short_answer","title":"Crossplane 基础设施控制平面","content":"Crossplane 是一种基础设施控制平面的开源框架。请说明 Crossplane 的核心架构（包括 Provider、Composition、Claim 和 XRD 的关系），以及它如何实现「基础设拖即代码」和「平台工程」理念。与 Terraform 相比有哪些本质区别？","answer":"答案：Crossplane 是基于 Kubernetes 的 CNCF 项目，通过 K8s CRD 和 Operator 模式将云资源（AWS RDS、GCP CloudSQL 等）以 K8s API 对象的形式暴露，实现「声明式基础设施管理」。\n\n解析：核心抽象：1）Provider——封装云厂商 API 的 Controller，watch CR 并调谐实际云资源。2）Managed Resource（MR）——Provider 管理的单个云资源（如一个 RDS 实例）。3）Composite Resource（XR）——由 Composition 定义的多个资源组合。4）Composition——定义 XR 的模板，用 patches 和 transforms 将 Claim 参数注入子资源。5）Claim（XRC）——最终用户通过 namespace 隔离的轻量级 API。6）XRD（CompositeResourceDefinition）——定义 XR 的 schema。Terraform 对比：Terraform 用 HCL + statefile，是执行驱动工具；Crossplane 用 K8s API + controller reconcile，是持续调谐的控制平面。Crossplane 不需要 CI/CD 触发 apply/plan，controller 自动保持期望状态。\n\n扩展延伸：Crossplane 与 ArgoCD/GitOps 天然集成（因为资源都是 K8s 对象）。功能包（Package）机制通过 provider-xxx 镜像分发 Provider。Composition Functions（Crossplane 1.14+）支持用 Python/Go 编写自定义资源转换逻辑。作为平台工程工具，Crossplane 让平台团队定义 Composition + XRD，应用开发者只创建 Claim（简单的 YAML），无需关心底层云资源细节。","hints":["Crossplane 的 XRD、Composition、Claim 三层抽象关系","Crossplane 与 Terraform 的设计哲学区别"],"tags":["Crossplane","IaC","平台工程","Kubernetes","基础设施"],"id":1832},{"category":"devops","difficulty":"medium","type":"short_answer","title":"DevContainer 开发容器规范","content":"DevContainer（Development Container）正在成为标准化的开发环境规范。请说明 DevContainer 的核心概念（devcontainer.json 的关键配置项），以及它如何解决「在我机器上能跑」的问题。与传统 Docker Compose 开发方案相比有什么优势？","answer":"答案：DevContainer 是 Microsoft 主导的开放规范（现归 CNCF），通过 devcontainer.json 描述开发容器的配置，支持 VS Code、JetBrains、GitHub Codespaces、Gitpod 等环境。\n\n解析：devcontainer.json 关键配置：image/build（基础镜像或 Dockerfile 构建）、extensions（IDE 插件预装）、settings（编辑器配置）、postCreateCommand（容器创建后运行的脚本）、forwardPorts（端口转发）、mounts（额外挂载卷）、features（开箱即用的功能包——Java、Python、Docker-in-Docker 等）。Features 机制是 DevContainer 的核心创新：一个声明即可安装完整工具链，无需手写 Dockerfile RUN 命令。\n\n扩展延伸：DevContainer 规范支持三种模式——本地（Docker）、远程（SSH/远程机器）、云（Codespaces/Gitpod）。相比传统 Docker Compose 方案：DevContainer 提供 IDE 感知（自动安装插件，自动配置调试器）、postCreate 钩子（环境初始化自动完成）、Feature 生态（社区共享的工具安装配方）。缺点：对 Docker 依赖较强，资源占用较高，对于轻量开发环境可能过于臃肿。spec 目前由 devcontainer-spec 维护。","hints":["DevContainer 的 Features 机制解决了什么问题","DevContainer 的三种运行模式是什么"],"tags":["DevContainer","开发环境","容器化","IDE"],"id":1833},{"category":"devops","difficulty":"hard","type":"short_answer","title":"Falco 容器运行时安全","content":"Falco 是 CNCF 的容器运行时安全项目。请说明 Falco 的工作原理（包括驱动层、规则引擎和输出管道），它如何利用 eBPF 或内核模块进行系统调用监控，以及规则（Rule）的编写方法。","answer":"答案：Falco 通过监控 Linux 系统调用实现容器运行时威胁检测，核心原理是：捕获所有系统调用 → 解析系统调用上下文（进程、容器、命名空间信息） → 通过规则引擎匹配异常行为 → 输出告警。\n\n解析：驱动层三种模式：1）kernel module——falco-probe 内核模块，性能最佳但需要加载内核模块。2）eBPF probe（推荐）——通过 BPF 程序挂载到 tracepoint/sys_enter 和 sys_exit，无需内核模块。3）modern eBPF——利用 CO-RE (Compile Once Run Everywhere) 和 BPF iterator，支持 5.10+ 内核。规则引擎使用 Falco Rules（YAML 格式），每个规则包含 condition（用 Sysdig 过滤语法编写）、output（告警输出格式化字符串）、priority（emergency/alert/critical/error/warning/notice/info/debug）。规则示例：condition: evt.type=execve and proc.name!=bash and container.id!=host。\n\n扩展延伸：Falco 输出支持多种方式——stdout、Syslog、gRPC、Webhook、Falcosidekick（对接 Slack/PagerDuty/AWS SQS/Elasticsearch 等）。Falco 规则集分为默认规则（异常 shell、特权容器、敏感路径访问）和自定义规则。Falco 的优先级：macro（可复用的条件片段）> list（可复用的元素列表）> rule（完整的检测规则）。Falco 0.36+ 支持 Plugins，可扩展到非系统调用事件源（如 Kubernetes audit log、AWS CloudTrail）。","hints":["Falco 的三种驱动模式及各自的优缺点","Falco 规则的 condition 语法基础"],"tags":["Falco","运行时安全","eBPF","容器安全","CNCF"],"id":1834},{"category":"devops","difficulty":"hard","type":"short_answer","title":"Kubernetes Descheduler 与节点负载均衡","content":"Kubernetes Descheduler 的作用是什么？请说明 Descheduler 的策略类型（RemoveDuplicates、LowNodeUtilization、RemovePodsViolatingInterPodAntiAffinity 等）以及每个策略的触发机制。如何将 Descheduler 与 Cluster Autoscaler 配合使用？","answer":"答案：Kubernetes Descheduler 是一个可选的调度优化组件（目前为 sig-scheduling 子项目），通过周期性扫描当前 Pod 分布，根据配置策略找到不合理的调度决策并驱逐 Pod，由 Scheduler 重新调度到更适合的节点。\n\n解析：主要策略（v1alpha2 API）：1）RemoveDuplicates——将同属于一个 ReplicaSet/Deployment 的多个 Pod 分散到不同节点。2）LowNodeUtilization——找出资源利用率低的节点，从高利用率节点驱逐 Pod 并调度到低利用率节点实现负载均衡。3）RemovePodsViolatingInterPodAntiAffinity——移除违反 Pod 反亲和性策略的 Pod。4）RemovePodsViolatingNodeAffinity——移除因节点标签变更而不再满足 Node Affinity 的 Pod。5）RemovePodsViolatingTopologySpreadConstraint——移除违反拓扑分布约束的 Pod（v1alpha2+）。6）PodLifeTime——驱逐运行时间超过阈值的 Pod。每个策略可配置包括 evictionTimeGroup（策略执行间隔）、thresholds（资源利用率阈值）等参数。\n\n扩展延伸：Descheduler + Cluster Autoscaler 配合：Descheduler 通过 Pod 驱逐创建可调度空间，Cluster Autoscaler 检测到节点利用率低后缩容节点，实现全局弹性。注意：Descheduler 本身用 Eviction API（遵循 PDB），不会触发 PDB 不允许的驱逐。Descheduler 的 v1alpha2（1.24+）支持策略配置文件（Profile）模式，可定义多个策略集。生产注意事项：Graduated to beta in 1.21，但仍建议先通过 dry-run 模式观察影响。","hints":["Descheduler 和 Scheduler 的关系是什么","Descheduler 如何与 Cluster Autoscaler 联动"],"tags":["Kubernetes","Descheduler","调度","负载均衡","Cluster Autoscaler"],"id":1835},{"category":"devops","difficulty":"hard","type":"short_answer","title":"K8s 准入控制器（Admission Controller）","content":"什么是 Kubernetes 的准入控制器（Admission Controller）？MutatingAdmissionWebhook 和 ValidatingAdmissionWebhook 的区别？常见的内置准入控制器有哪些？","answer":"答案：准入控制器在 API Server 处理请求的认证和授权之后、对象持久化到 etcd 之前拦截请求。分为 Mutating（可以修改请求对象）和 Validating（只能验证不能修改）两种。Webhook 准入控制器允许用户通过外部 Webhook 服务自定义准入逻辑。\n\n解析：工作流程——1）请求经过认证（Authentication）→ 授权（Authorization）→ 准入控制（Admission Control）→ 持久化到 etcd。2）MutatingAdmissionWebhook 在 ValidatingAdmissionWebhook 之前执行。Mutating 先修改对象（如注入 Sidecar），Validating 再验证修改后的对象（如检查镜像来源是否白名单）。3）Webhook 配置：MutatingWebhookConfiguration 和 ValidatingWebhookConfiguration 资源。配置 webhook 的 URL、触发规则（operations/apiGroups/resources）、超时时间、失败策略（Fail/Ignore）。\n\n扩展延伸：重要内置准入控制器——1）NamespaceLifecycle：拒绝在删除中的 Namespace 创建新资源。2）LimitRanger：检查 Pod 资源请求和限制是否符合 LimitRange。3）ResourceQuota：检查 Namespace 的资源配额是否超限。4）PodSecurity：替代 PodSecurityPolicy (PSP)，基于标签的 Pod 安全标准。5）NodeRestriction：限制 kubelet 只能修改本节点相关的资源。6）DefaultStorageClass：为 PVC 自动设置默认 StorageClass。Webhook 开发注意——1）必须处理 TLS（使用 CA 签发的证书）。2）超时时间 30s（设置更短的超时避免阻塞 API Server）。3）failurePolicy=Fail 时 webhook 不可用导致整个集群不可用——用 Ignore 做灰度。4）避免 webhook 之间的循环调用（webhook 修改的资源又触发了同样的 webhook）。","hints":["准入控制器拦截顺序——认证 → 授权 → MutatingWebhook → ValidatingWebhook → etcd","failurePolicy 的选择——Fail 保证安全但 webhook 故障会影响集群，Ignore 反之"],"tags":["DevOps","K8s","准入控制","安全"],"id":3072},{"category":"devops","difficulty":"medium","type":"short_answer","title":"K8s 节点资源管理","content":"Kubernetes 节点如何管理资源？Node Capacity、Allocatable、Requests/Limits 的关系？节点压力驱逐（Node Pressure Eviction）的触发条件？kubelet 如何保证节点不因过载而崩溃？","answer":"答案：节点资源层次——Node Capacity（节点的总资源，如 32C/128G）→ kube-reserved（kubelet/kube-proxy 等系统组件保留）→ system-reserved（OS/sshd 等系统进程保留）→ Eviction Threshold（驱逐阈值）→ Allocatable（可调度给 Pod 的资源总量）。公式：Allocatable = Capacity - kube-reserved - system-reserved - eviction-hard-threshold。\n\n解析：节点压力驱逐——1）kubelet 监控节点资源（memory/disk/pid/压力）。当资源使用超过软阈值（eviction-soft）时启动驱逐流程，超过硬阈值（eviction-hard）时立即驱逐 Pod。2）驱逐顺序：先 BestEffort（无 requests/limits）→ Burstable 中超限使用最多的 → Guaranteed（最晚被驱逐）。3）资源回收：kubelet 优先回收本地资源（如 GC 镜像/终止 Pod），如果不够再驱逐 Pod。\n\n扩展延伸：配置——1）--kube-reserved 和 --system-reserved 参数配置。2）--eviction-hard=memory.available<500Mi,nodefs.available<10% 等。3）--eviction-soft-grace-period（软阈值的等待时间，给 Pod 时间主动释放）。4）--eviction-minimum-reclaim（每次驱逐至少回收多少资源，防止频繁驱逐）。Pod 层面——设置 Pod 的 requests 和 limits（特别是 Guaranteed QoS 的 Pod 几乎不会被驱逐）。PriorityClass——高优先级的 Pod 在驱逐时排在最后，且可能抢占低优先级 Pod 的资源（Priority Preemption）。","hints":["Allocatable = Capacity - kube-reserved - system-reserved - eviction-threshold","驱逐顺序：BestEffort → 超限 Burstable → Guaranteed——设置 Guaranteed QoS 提高稳定性"],"tags":["DevOps","K8s","节点管理","驱逐"],"id":3073},{"category":"devops","difficulty":"medium","type":"short_answer","title":"K8s 存储卷与 PV/PVC 生命周期","content":"Kubernetes 存储卷有哪些类型？PersistentVolume（PV）和 PersistentVolumeClaim（PVC）的生命周期？StorageClass 和动态供给（Dynamic Provisioning）的原理？PV 的访问模式（Access Modes）？","answer":"答案：PV 是集群级别的存储资源（由管理员预先创建或通过 StorageClass 动态供给），PVC 是 Pod 对存储资源的请求。PVC 绑定到满足条件的 PV（容量/访问模式/StorageClass 匹配）。PVC 被 Pod 使用后，PVC 删除时 PV 根据回收策略（Retain/Delete/Recycle）处理。\n\n解析：生命周期——1）静态供给：管理员创建 PV（指定存储类型/容量/访问模式/回收策略）。用户创建 PVC（指定容量/访问模式/StorageClass）。K8s 将 PVC 绑定到匹配的 PV（一对一绑定）。2）动态供给：StorageClass 定义 provisioner（如 ebs.csi.aws.com/managed-nfs.storageclass）和参数。PVC 指定 StorageClass → 系统自动创建 PV 并绑定。3）回收策略：Retain（保留 PV 和数据，管理员手动清理）、Delete（自动删除 PV 和后端存储）、Recycle（已废弃，清空数据后重新可用）。\n\n扩展延伸：访问模式——1）ReadWriteOnce（RWO）：单节点读写（最常见的模式）。2）ReadOnlyMany（ROX）：多节点只读。3）ReadWriteMany（RWX）：多节点读写（需要 NFS/CephFS 等共享存储）。4）ReadWriteOncePod（RWOP，K8s 1.22+）：单 Pod 读写。CSI 存储接口——Container Storage Interface 是 K8s 与存储系统交互的标准接口。driver 实现 CSI 接口（CreateVolume/DeleteVolume/ControllerPublishVolume/NodePublishVolume）。常见的 CSI Driver：AWS EBS/EFS、GCE PD、Azure Disk/File、Ceph RBD/CephFS、NFS CSI。","hints":["PVC 绑定 PV 是一对一的——PVC 删除后 PV 根据回收策略（Retain/Delete）决定是否保留数据","RWX（多节点读写）需要共享存储（NFS/CephFS），RWO（单节点读写）是最常用的模式"],"tags":["DevOps","K8s","存储","PV/PVC"],"id":3074},{"category":"devops","difficulty":"medium","type":"short_answer","title":"K8s 资源配额与 LimitRange","content":"Kubernetes 的 ResourceQuota 和 LimitRange 的区别？如何为不同 Namespace 设置资源配额？ResourceQuota 可以限制哪些资源类型？","answer":"答案：ResourceQuota 是 Namespace 维度的资源总量限制（整个 Namespace 的 CPU/内存总和上限、PVC 数量上限等）。LimitRange 是 Pod/Container 维度的默认值和范围限制（最小请求/最大限制/默认值）。两者配合使用——ResourceQuota 防止 Namespace 超支，LimitRange 防止单个 Pod 占用过多。\n\n解析：ResourceQuota——1）计算资源：limits.cpu/limits.memory/requests.cpu/requests.memory。2）存储资源：requests.storage（PVC 总容量）、persistentvolumeclaims（PVC 数量上限）。3）对象数量：count/deployments、count/services、count/secrets、count/configmaps 等。4）配额作用范围：选择器作用（scopes）——Terminating（删除中的 Pod）、NotTerminating、BestEffort、NotBestEffort。\n\n扩展延伸：LimitRange——1）Pod 级别：max/min（Pod 中所有 Container 的最大/最小资源）、maxLimitRequestRatio（limits/requests 的最大比例）。2）Container 级别：default（默认 limits）、defaultRequest（默认 requests）、max/min。3）LimitRange 在 Namespace 级别生效——在该 Namespace 中创建 Pod 时如果没有设置 resources，LimitRange 的默认值会被应用。注意——ResourceQuota 没有设置 `limits` 时，Pod 必须有 limits（否则拒绝创建）。因此 ResourceQuota 和 LimitRange 通常一起使用——LimitRange 设置默认 limits，ResourceQuota 限制总量。","hints":["ResourceQuota 限制 Namespace 总量——LimitRange 设置 Pod/Container 的资源默认值和边界——两者互补","ResourceQuota 如果限制了 limits.cpu——Namespace 中所有 Pod 必须设置 CPU limits（否则拒绝创建）"],"tags":["DevOps","K8s","ResourceQuota","LimitRange"],"id":3075},{"category":"devops","difficulty":"hard","type":"short_answer","title":"etcd 原理与运维","content":"etcd 在 Kubernetes 中的角色？Raft 协议如何保证 etcd 一致性？etcd 的性能瓶颈和运维最佳实践？etcd 快照和恢复？","answer":"答案：etcd 是 K8s 的分布式键值存储——存储所有集群状态（Pod/Service/ConfigMap/Secret 等资源的数据）。etcd 使用 Raft 一致性协议保证数据的一致性和高可用。K8s API Server 是无状态的——所有状态通过 etcd 持久化。\n\n解析：Raft 在 etcd 中——1）Leader 选举：etcd 集群节点通过随机超时机制选举 Leader。Leader 处理所有写请求（Follower 将写请求转发给 Leader）。2）日志复制：Leader 将写操作作为日志条目复制到多数 Follower（quorum）。quorum = N/2 + 1（如 3 节点集群需要 2 个节点确认）。3）持久化：日志写入 WAL（Write-Ahead Log）后才能确认。快照（Snapshot）压缩旧的 WAL，减少启动恢复时间。\n\n扩展延伸：运维——1）集群规模：推荐 3 或 5 节点（奇数）。3 节点容忍 1 个节点故障，5 节点容忍 2 个。2）性能：etcd 对磁盘 IO 敏感——推荐 SSD（固态硬盘）和独立的 etcd 节点（不混部）。监控 fsync 耗时和 db size。3）磁盘：etcd 对磁盘延迟敏感——fsync 延迟应 < 10ms。慢磁盘是 etcd 不稳定的最常见原因。4）压缩：定期 defrag（碎片整理）和 compact（历史压缩）。默认自动每 5 分钟 compact。db size 通常应 < 2GB 且增长到 < 8GB。5）备份：定期快照备份——`ETCDCTL_API=3 etcdctl snapshot save`。恢复：`etcdctl snapshot restore`。灾难恢复——当 etcd 集群丢失 quorum 时，用最新快照恢复单个 etcd 节点。","hints":["etcd 对磁盘 IO 极度敏感——SSD 是必须的，fsync 延迟 < 10ms 是健康标准","etcd 集群推荐奇数节点（3 或 5）——3 节点容忍 1 个故障，5 节点容忍 2 个"],"tags":["DevOps","etcd","K8s","一致性"],"id":3076}];
